-- Poems batch 47
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8a18ce54-699e-42c8-adb8-a7716113f39c','書小齋壁','李中','唐','唐诗','tang','','[]','其誰肯見尋，冷淡少知音。',48,'全唐诗/poet.tang.41000.json','["其誰肯見尋，冷淡少知音。", "塵土侵閑榻，煙波隔故林。", "竹風醒晚醉，窗月伴秋吟。", "道在唯求己，明時豈陸沈。"]'),
('12f06949-6535-4ea0-8e09-71e7a9f1eb64','懷王道者','李中','唐','唐诗','tang','','[]','閑思王道者，逸格世難羣。',48,'全唐诗/poet.tang.41000.json','["閑思王道者，逸格世難羣。", "何處眠青嶂，從來愛白雲。", "酒沽應獨醉，藥熟許誰分。", "正作趨名計，如何得見君。"]'),
('bba3b8ff-fc8f-4510-b3da-0b1325c008b2','桃花','李中','唐','唐诗','tang','','[]','祗應紅杏是知音，灼灼偏宜間竹陰。',64,'全唐诗/poet.tang.41000.json','["祗應紅杏是知音，灼灼偏宜間竹陰。", "幾樹半開金谷曉，一溪齊綻武陵深。", "豔舒百葉時皆重，子熟千年事莫尋。", "誰步宋牆明月下，好香和影上衣襟。"]'),
('087e93b6-7045-45b1-a710-46fadf31b395','思舊遊有感','李中','唐','唐诗','tang','','[]','長憶銜杯處，酕醄尚未闌。',48,'全唐诗/poet.tang.41000.json','["長憶銜杯處，酕醄尚未闌。", "江南正煙雨，樓上恰春寒。", "好樹藏鶯密，平蕪徹野寬。", "如今無處覓，音信隔波瀾。"]'),
('ccadb49b-2e8f-4209-8148-7c6feb7cfeaf','依韻和智謙上人送李相公赴昭武軍','李中','唐','唐诗','tang','','[]','暫別廟堂上，雄藩去豁情。',48,'全唐诗/poet.tang.41000.json','["暫別廟堂上，雄藩去豁情。", "秋風生鴈渚，晚霧濕龍旌。", "吟裏過侯服，夢中歸帝城。", "下車軍庶樂，千里月華清。"]'),
('c3850ecb-48d0-4a9a-bef8-fd3721fdcb4f','姑蘇懷古 一','李中','唐','唐诗','tang','','[]','闔閭興霸日，繁盛復風流。',50,'全唐诗/poet.tang.41000.json','["闔閭興霸日，繁盛復風流。", "歌舞一場夢，煙波千古愁。", "樵人歸野徑，漁笛起[扁]舟。", "觸目牽傷感，將行又駐留。"]'),
('564bf05d-6b31-42c9-961a-c1bd4603dab1','姑蘇懷古 二','李中','唐','唐诗','tang','','[]','蘇臺蹤跡在，曠望向江濱。',48,'全唐诗/poet.tang.41000.json','["蘇臺蹤跡在，曠望向江濱。", "往事誰堪問，連空草自春。", "花疑西子臉，濤想伍胥神。", "吟盡情難盡，斜陽照路塵。"]'),
('385d667b-d46d-4342-ae30-01a8c2103899','贈史虛白','李中','唐','唐诗','tang','','[]','致主嘉謀尚未伸，慨然深志與誰論。',64,'全唐诗/poet.tang.41000.json','["致主嘉謀尚未伸，慨然深志與誰論。", "喚迴古意琴開匣，陶出真情酒滿樽。", "明月過溪吟釣艇，落花堆席睡僧軒。", "九重夢卜時終在，莫向深雲獨閉門。"]'),
('58130c76-fb35-4e5a-9b02-3c2e8e013969','贈蒯亮處士','李中','唐','唐诗','tang','','[]','著得新書義更幽，負琴何處不遨遊。',64,'全唐诗/poet.tang.41000.json','["著得新書義更幽，負琴何處不遨遊。", "玄宮寄宿月華冷，羽客伴吟松韻秋。", "滿戶煙霞思紫閣，一帆風雨憶滄洲。", "吾君側席求賢切，未可懸瓢枕碧流。"]'),
('d378f562-482b-4345-87e9-d9b8fceaf79d','春夕偶作','李中','唐','唐诗','tang','','[]','早是春愁觸目生，那堪春夕酒初醒。',32,'全唐诗/poet.tang.41000.json','["早是春愁觸目生，那堪春夕酒初醒。", "貫珠聲罷人歸去，半落桃花月在庭。"]'),
('3ba1f32d-23ba-4602-ada9-faf6322613b5','子規','李中','唐','唐诗','tang','','[]','暮春滴血一聲聲，花落年年不忍聽。',32,'全唐诗/poet.tang.41000.json','["暮春滴血一聲聲，花落年年不忍聽。", "帶月莫啼江畔樹，酒醒遊子在離亭。"]'),
('7e9ff0b2-cde3-4499-b61b-b0acae7e05ca','書王秀才壁','李中','唐','唐诗','tang','','[]','茅舍何寥落，門庭長綠蕪。',48,'全唐诗/poet.tang.41000.json','["茅舍何寥落，門庭長綠蕪。", "貧來賣書劒，病起憶江湖。", "對枕暮山碧，伴吟涼月孤。", "前賢多晚達，莫歎有霜鬚。"]'),
('2364b919-1af6-4e89-acd6-65b3268bca16','春日途中作','李中','唐','唐诗','tang','','[]','干祿趨名者，迢迢別故林。',36,'全唐诗/poet.tang.41000.json','["干祿趨名者，迢迢別故林。", "春風短亭路，芳草異鄉心。", "雨過江山出，鶯啼村落深。"]'),
('ed0c988c-7aee-4259-98ae-18b61d1bbccd','依韻和蠡澤王去微秀才見寄','李中','唐','唐诗','tang','','[]','咫尺風騷客，難諧面繼酬。',48,'全唐诗/poet.tang.41000.json','["咫尺風騷客，難諧面繼酬。", "相思對煙雨，一鴈下汀洲。", "花影誰家塢，笛聲何處樓？", "搘筇朗吟罷，搔首獨遲留。"]'),
('057a7a01-89bd-4cc5-b568-dbcaac3b7872','送孫孔二秀才遊廬山','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','廬山多勝景，偏稱二君遊。',48,'全唐诗/poet.tang.41000.json','["廬山多勝景，偏稱二君遊。", "松徑蒼苔合，花陰碧澗流。", "傾壺同坐石，搜句共登樓。", "莫學天台客，逢山即駐留。"]'),
('fb2baacc-573d-4a84-8213-5938f70ce2c9','春日野望懷故人','李中','唐','唐诗','tang','','[]','野外登臨望，蒼蒼煙景昏。',48,'全唐诗/poet.tang.41000.json','["野外登臨望，蒼蒼煙景昏。", "暖風醫病草，甘雨洗荒村。", "雲散天邊野，潮迴島上痕。", "故人不可見，倚杖役吟魂。"]'),
('c40b291d-149d-422b-a966-799b191e039e','遊玄真觀','李中','唐','唐诗','tang','','[]','閑吟遊古觀，靜慮想神仙。',48,'全唐诗/poet.tang.41000.json','["閑吟遊古觀，靜慮想神仙。", "上景非難度，陰功不易全。", "醮壇松作蓋，丹井蘚成錢。", "浩浩紅塵裏，誰來叩自然。"]'),
('ece79d50-b2fe-4092-bff5-a788bdbb90da','劒客','李中','唐','唐诗','tang','','[]','恩酬期必報，豈是輙輕生。',24,'全唐诗/poet.tang.41000.json','["恩酬期必報，豈是輙輕生。", "神劒沖霄去，誰爲平不平。"]'),
('46ae552f-e210-4e0a-91e0-b46e8333fd92','鶴','李中','唐','唐诗','tang','','[]','警露精神異，沖天羽翼新。',24,'全唐诗/poet.tang.41000.json','["警露精神異，沖天羽翼新。", "千年一歸日，誰識令威身。"]'),
('9e0b3ff4-6f11-492a-96f1-414198993fa2','送致仕沈彬郎中遊茅山','李中','唐','唐诗','tang','','[]','掛却朝冠披鶴氅，羽人相伴恣遨遊。',64,'全唐诗/poet.tang.41000.json','["掛却朝冠披鶴氅，羽人相伴恣遨遊。", "忽因風月思茅嶺，便挈琴樽上葉舟。", "野寺宿時魂夢冷，海門吟處水雲秋。", "華陽洞府年光永，莫向仙鄉擬駐留。"]'),
('3c544431-6f42-415c-aaa2-e4b454c421f5','題廬山東寺遠大師影堂','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','遠公遺跡在東林，往事名存動苦吟。',64,'全唐诗/poet.tang.41000.json','["遠公遺跡在東林，往事名存動苦吟。", "杉檜已依靈塔老，煙霞空鎖影堂深。", "入簾輕吹催香印，落石幽泉雜磬音。", "十八賢人消息斷，蓮池千載月沈沈。"]'),
('654a7a8f-f73c-4ecb-865c-56695d216920','庭葦','李中','唐','唐诗','tang','','[]','品格清於竹，詩家景最幽。',72,'全唐诗/poet.tang.41000.json','["品格清於竹，詩家景最幽。", "從栽向池沼，長似在汀洲。", "玩好招溪叟，棲堪待野鷗。", "影疎當夕照，花亂正深秋。", "韻細堪清耳，根牢好繫舟。", "故溪高岸上，冷淡有誰遊。"]'),
('e26ff256-4b77-4163-abb9-7437b9015850','寄左偃','李中','唐','唐诗','tang','','[]','每病風騷路，荒涼人莫遊。',48,'全唐诗/poet.tang.41000.json','["每病風騷路，荒涼人莫遊。", "惟君還似我，成癖未能休。", "捨寐緣孤月，忘形爲九秋。", "垂名如不朽，那恨雪生頭。"]'),
('28e95d92-c9c6-49aa-af9e-15b363fe9b00','宿山店書懷寄東林令圖上人','李中','唐','唐诗','tang','','[]','一宿山前店，旅情安可窮。',48,'全唐诗/poet.tang.41000.json','["一宿山前店，旅情安可窮。", "猨聲鄉夢後，月影竹窗中。", "南楚征途闊，東吳舊業空。", "虎溪蓮社客，應笑此飄蓬。"]'),
('81966d11-a11b-450a-81e1-8ca64ac084e5','途中聞子規','李中','唐','唐诗','tang','','[]','春殘杜宇愁，越客思悠悠。',48,'全唐诗/poet.tang.41000.json','["春殘杜宇愁，越客思悠悠。", "雨歇孤村裏，花飛遠水頭。", "微風聲漸咽，高樹血應流。", "因此頻迴首，家山隔幾州。"]'),
('07605b9b-e844-4dbd-be7f-0ca67982cee1','春日書懷','李中','唐','唐诗','tang','','[]','千峰雪盡鳥聲春，日永孤吟野水濱。',32,'全唐诗/poet.tang.41000.json','["千峰雪盡鳥聲春，日永孤吟野水濱。", "霄漢路岐昇未得，花時空拂滿衣塵。"]'),
('a5d27526-c32c-48e5-8860-3c1e908c83ee','所思代人','李中','唐','唐诗','tang','','[]','巫峽雲深湘水遙，更無消息夢空勞。',32,'全唐诗/poet.tang.41000.json','["巫峽雲深湘水遙，更無消息夢空勞。", "夢迴深夜不成寐，起立閑庭花月高。"]'),
('b87a0fd7-5456-4809-9a1b-3efea7aa99ca','春晚過明氏閑居','李中','唐','唐诗','tang','','[]','寥寥陋巷獨扃門，自樂清虛不厭貧。',64,'全唐诗/poet.tang.41000.json','["寥寥陋巷獨扃門，自樂清虛不厭貧。", "數局棊中消永日，一罇酒裏送殘春。", "雨催綠蘚鋪三徑，風送飛花入四鄰。", "羨爾朗吟無外事，滄洲何必去垂綸。"]'),
('bdf97d8c-0a1e-46d4-981d-0587c828aaad','贈重安寂道者','李中','唐','唐诗','tang','','[]','寒松肌骨鶴心情，混俗陶陶隱姓名。',64,'全唐诗/poet.tang.41000.json','["寒松肌骨鶴心情，混俗陶陶隱姓名。", "白髮只聞悲短景，紅塵誰解信長生。", "壺中日月存心近，島外煙霞入夢清。", "每許相親應計分，琴餘常見話蓬瀛。"]'),
('c98b7045-9c3e-453a-ad36-1cafab573603','江邊吟','李中','唐','唐诗','tang','','[]','風暖汀洲吟興生，遠山如畫雨新晴。',64,'全唐诗/poet.tang.41000.json','["風暖汀洲吟興生，遠山如畫雨新晴。", "殘陽影裏水東注，芳草煙中人獨行。", "閃閃酒帘招醉客，深深綠樹隱啼鶯。", "盤桓漁舍忘歸去，雲靜高空月又明。"]'),
('d683232d-58d8-4fd6-a299-472c97e7327c','獻張義方常侍','李中','唐','唐诗','tang','','[]','雄飛看是逼嵓廊，逸思常聞不暫忘。',64,'全唐诗/poet.tang.41000.json','["雄飛看是逼嵓廊，逸思常聞不暫忘。", "公署靜眠思水石，古屏閑展看瀟湘。", "老來酒病雖然減，秋杪詩魔更是狂。", "乘興有時招羽客，橫琴移月啓茅堂。"]'),
('180e250e-042f-4674-afa0-cccde92ee6a2','贈永真杜作翺少府','李中','唐','唐诗','tang','','[]','藍袍竹簡佐琴堂，縣僻人稀覺日長。',64,'全唐诗/poet.tang.41000.json','["藍袍竹簡佐琴堂，縣僻人稀覺日長。", "愛靜不嫌官況冷，苦吟從聽鬢毛蒼。", "閑尋野寺聽秋水，寄睡僧窗到夕陽。", "騫翥會應霄漢去，漁竿休更戀滄浪。"]'),
('a0d318a3-6083-4ec9-adf5-9cbe7363ad79','獻中書韓舍人','李中','唐','唐诗','tang','','[]','丹墀朝退後，靜院即冥搜。',48,'全唐诗/poet.tang.41000.json','["丹墀朝退後，靜院即冥搜。", "盡日捲簾坐，前峰當檻秋。", "烹茶留野客，展畫看滄洲。", "見說東林夜，尋常秉燭遊。"]'),
('7191dd38-8aec-47c1-b27e-598dcaa2c5a5','獻徐舍人','李中','唐','唐诗','tang','','[]','清名喧四海，何止並南金。',144,'全唐诗/poet.tang.41000.json','["清名喧四海，何止並南金。", "奧學羣英伏，多才萬乘欽。", "秩參金殿峻，步歷紫微深。", "顧聞承中旨，絲綸演帝心。", "褒雄饒義路，賈馬避詞林。", "下直無他事，開門對遠岑。", "軒窗來晚吹，池沼歇秋霖。", "蘚點生棊石，茶煙過竹陰。", "希夷元已達，躁競豈能侵。", "羽客閑陪飲，詩人伴靜吟。", "自漸爲滯物，多幸辱虛襟。", "此日重遭遇，心期出陸沈。"]'),
('e899591d-bb7a-4209-bf1a-7c5c55749926','新秋有感','李中','唐','唐诗','tang','','[]','門巷涼秋至，高梧一葉驚。',96,'全唐诗/poet.tang.41000.json','["門巷涼秋至，高梧一葉驚。", "漸添衾簟爽，頓覺夢魂清。", "暗促蓮開豔，乍催蟬發聲。", "雨降炎氣減，竹引冷煙生。", "戍客添歸思，行人怯遠程。", "未逢征鴈下，漸聽夜砧鳴。", "張翰思鱸興，班姬詠扇情。", "音塵兩難問，蛩砌月空明。"]'),
('a2d26194-7393-4297-a650-78bfcedc8a58','秋雨','李中','唐','唐诗','tang','','[]','竟日散如絲，吟看半掩扉。',96,'全唐诗/poet.tang.41000.json','["竟日散如絲，吟看半掩扉。", "秋聲在梧葉，潤氣逼書幃。", "曲澗泉承去，危簷燕帶歸。", "寒蛩悲旅壁，亂蘚滑漁磯。", "爽欲除幽簟，涼須換熟衣。", "疎篷誰夢斷，荒徑獨遊稀。", "偏稱江湖景，不妨鷗鷺飛。", "最憐爲瑞處，南畝稻苗肥。"]'),
('40b03fb1-6e91-4985-9c15-755aff294298','寄廬山白大師','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','長憶尋師處，東林寓泊時。',72,'全唐诗/poet.tang.41000.json','["長憶尋師處，東林寓泊時。", "一秋同看月，無夜不論詩。", "泉美茶香異，堂深磬韻遲。", "鹿馴眠蘚徑，猨苦叫霜枝。", "別後音塵隔，年來鬢髮衰。", "趨名方汲汲，未果再遊期。"]'),
('075bf3b1-2edf-4ed9-9960-4e9fba1ef812','訪龍光智謙上人','李中','唐','唐诗','tang','','[]','忽起尋師興，穿雲不覺勞。',48,'全唐诗/poet.tang.41000.json','["忽起尋師興，穿雲不覺勞。", "相留看山雪，盡日論風騷。", "竹影搖禪榻，茶煙上毳袍。", "夢魂曾去否，舊國阻波濤。"]'),
('ac8f18a0-1079-4027-9ebb-46f8a1bb081e','送仙客','李中','唐','唐诗','tang','','[]','危言危行是男兒，倚伏相牽豈足悲。',32,'全唐诗/poet.tang.41000.json','["危言危行是男兒，倚伏相牽豈足悲。", "莫向汀洲時獨立，悠悠斜日照江蘺。"]'),
('51f0cb3f-2d07-4e95-9159-f29296cf300a','祀風師迎神曲','李中','唐','唐诗','tang','','[]','太皥御氣，勾芒肇功。',40,'全唐诗/poet.tang.41000.json','["太皥御氣，勾芒肇功。", "蒼龍青旗，爰候祥風。", "律以和應，□以感通。", "鼎徂修蠁，時惟禮崇。"]'),
('cdde833e-af18-453a-9aa5-7a3c31ba5441','柳二首 一','李中','唐','唐诗','tang','','[]','春來無樹不青青，似共東風別有情。',32,'全唐诗/poet.tang.41000.json','["春來無樹不青青，似共東風別有情。", "閑憶舊居湓水畔，數枝煙雨屬啼鶯。"]'),
('6e5592b5-c16d-4fa7-aab3-69205bfe86b8','柳二首 二','李中','唐','唐诗','tang','','[]','最愛青青水國中，莫愁門外間花紅。',32,'全唐诗/poet.tang.41000.json','["最愛青青水國中，莫愁門外間花紅。", "纖纖無力勝春色，撼起啼鶯恨晚風。"]'),
('1b150d27-5ccf-4408-833e-5301874e4651','送廬阜僧歸山陽','李中','唐','唐诗','tang','','[]','山陽舊社終經夢，容易言歸不可留。',64,'全唐诗/poet.tang.41000.json','["山陽舊社終經夢，容易言歸不可留。", "瓶貯瀑泉離五老，錫搖江雨上孤舟。", "魚行細浪分沙觜，鴈逆高風下葦洲。", "遙想枚臯宅邊寺，不知涼月共誰遊。"]'),
('e37f28fb-f90e-4c51-a43b-5bd15968d645','投所知','李中','唐','唐诗','tang','','[]','孤琴塵翳劒慵磨，自顧泥蟠欲奈何。',64,'全唐诗/poet.tang.41000.json','["孤琴塵翳劒慵磨，自顧泥蟠欲奈何。", "千里交親消息斷，一庭風雨夢魂多。", "題橋未展相如志，叩角誰憐寧戚歌。", "唯賴明公憐道在，敢攜蓑笠釣煙波。"]'),
('ada3a445-dc80-4cd4-8177-62975a5a6c1b','寄左偃','李中','唐','唐诗','tang','','[]','蕭條陋巷綠苔侵，何事君心似我心。',64,'全唐诗/poet.tang.41000.json','["蕭條陋巷綠苔侵，何事君心似我心。", "貧戶懶開元愛靜，病身纔起便思吟。", "閑留好鳥庭柯密，暗養鳴蛩砌草深。", "況是清朝重文物，無愁當路少知音。"]'),
('1710d52b-de53-45be-8f3b-807537428373','遊北山洞神宮','李中','唐','唐诗','tang','','[]','悶見塵中光景促，仙鄉來禮紫陽君。',64,'全唐诗/poet.tang.41000.json','["悶見塵中光景促，仙鄉來禮紫陽君。", "人居淡寂應難老，道在虛無不可聞。", "松檜穩棲三島鶴，樓臺閑鎖九霄雲。", "羨師向此朝星斗，一炷清香午夜焚。"]'),
('e60c82c2-a8e4-4811-ac95-f716a9eeb9ad','思簡寂觀舊遊寄重道者','李中','唐','唐诗','tang','','[]','閑憶當年遊物外，羽人曾許駐仙鄉。',64,'全唐诗/poet.tang.41000.json','["閑憶當年遊物外，羽人曾許駐仙鄉。", "溪頭烘藥煙霞暖，花下圍棊日月長。", "偷摘蟠桃思曼倩，化成蝴蝶學蒙莊。", "俗緣未斷歸浮世，空望林泉意欲狂。"]'),
('c3ac136e-fe16-40e0-8667-3bb99135c6d8','雲','李中','唐','唐诗','tang','','[]','悠悠離洞壑，冉冉上天津。',120,'全唐诗/poet.tang.41000.json','["悠悠離洞壑，冉冉上天津。", "捧日終爲異，從龍自有因。", "高行四海雨，暖拂萬山春。", "靜與霞相近，閑將鶴最親。", "帝鄉歸莫問，楚殿夢曾頻。", "白向封中起，碧從詩裏新。", "冷容橫釣浦，輕縷絆蟾輪。", "不滯濃還淡，無心卷復伸。", "非煙聊擬議，干呂在逡巡。", "會作五般色，爲祥覆紫宸。"]'),
('69420666-078b-4180-bd7f-bfadeed5afe8','徐司徒池亭','李中','唐','唐诗','tang','','[]','亭榭跨池塘，泓澄入座涼。',96,'全唐诗/poet.tang.41000.json','["亭榭跨池塘，泓澄入座涼。", "扶疎皆竹柏，冷淡似瀟湘。", "萍嫩鋪波面，苔深鎖岸傍。", "朝迴遊不厭，僧到賞難忘。", "最稱收殘雨，偏宜帶夕陽。", "吟堪期謝朓，醉好命嵇康。", "奢侈心難及，清虛趣最長。", "月明垂釣興，何必憶滄浪。"]'),
('a82d7d19-a280-43f2-8238-f2d11b46c83f','賦得江邊草','李中','唐','唐诗','tang','','[]','岸春芳草合，幾處思纏綿。',48,'全唐诗/poet.tang.41000.json','["岸春芳草合，幾處思纏綿。", "向暮江蘺雨，初晴杜若煙。", "靜宜幽鷺立，遠稱碧波連。", "送別王孫處，萋萋南浦邊。"]'),
('bee82159-14a8-4071-a264-5f61e2f18a02','江行夜泊','李中','唐','唐诗','tang','','[]','扁舟倦行役，寂寂宿江干。',48,'全唐诗/poet.tang.41000.json','["扁舟倦行役，寂寂宿江干。", "半夜風雷過，一天星斗寒。", "潮平沙觜沒，霜苦鴈聲殘。", "漁父何疎逸，扣舷歌未闌。"]'),
('63c53976-e13f-4116-97e0-bd5acfa57f33','訪山叟留題','李中','唐','唐诗','tang','','[]','策杖尋幽客，相攜入竹扃。',48,'全唐诗/poet.tang.41000.json','["策杖尋幽客，相攜入竹扃。", "野雲生晚砌，病鶴立秋庭。", "茶美睡心爽，琴清塵慮醒。", "輪蹄應少到，門巷草青青。"]'),
('d90955f1-bc2f-48b7-900d-11699e3ea91a','江行晚泊寄湓城知友','李中','唐','唐诗','tang','','[]','孤舟相憶久，何處倍關情。',48,'全唐诗/poet.tang.41000.json','["孤舟相憶久，何處倍關情。", "野渡帆初落，秋風蟬一聲。", "江浮殘照闊，雲散亂山橫。", "漸去湓城遠，那堪新月生。"]'),
('37c212a3-6152-4539-b4a9-9d777fe41448','秋夕書懷','李中','唐','唐诗','tang','','[]','功名未立誠非晚，骨肉分飛又入秋。',32,'全唐诗/poet.tang.41000.json','["功名未立誠非晚，骨肉分飛又入秋。", "枕上不堪殘夢斷，壁蛩窗月夜悠悠。"]'),
('f462fed5-9e09-4044-aed1-4f7736e8de32','感興','李中','唐','唐诗','tang','','[]','漁休渭水興周日，龍起南陽相蜀時。',32,'全唐诗/poet.tang.41000.json','["漁休渭水興周日，龍起南陽相蜀時。", "不遇文王與先主，經天才業擬何爲。"]'),
('3e5c9279-e6a7-488c-ae85-7baaac8b1a53','舟中望九華山','李中','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','排空蒼翠異，輟櫂看崔嵬。',72,'全唐诗/poet.tang.41000.json','["排空蒼翠異，輟櫂看崔嵬。", "一面雨初歇，九峰雲正開。", "當時思水石，便欲上樓臺。", "隱去心難遂，吟餘首懶迴。", "僧休傳紫閣，屏歇寫天臺。", "中有忘機者，逍遙不可陪。"]'),
('9f1438e5-ce57-40d6-9901-7c41e3332198','漁父','李中','唐','唐诗','tang','','[]','煙冷暮江濱，高歌散誕身。',48,'全唐诗/poet.tang.41000.json','["煙冷暮江濱，高歌散誕身。", "移舟過蓼岸，待月正絲綸。", "亦與樵翁約，同遊酒市春。", "白頭雲水上，不識獨醒人。"]'),
('dc161291-baef-4440-babb-e4dd7fe9e928','贈上都紫極宮劉日新先生','李中','唐','唐诗','tang','','[]','道德吾君重，含貞本去華。',48,'全唐诗/poet.tang.41000.json','["道德吾君重，含貞本去華。", "因知鍊神骨，何必在煙霞。", "棊散庭花落，詩成海月斜。", "瀛洲舊仙侶，應許寄丹砂。"]'),
('4181e4e9-d92e-4448-b0fd-990a1f2715fd','勉同志','李中','唐','唐诗','tang','','[]','讀書與磨劒，旦夕但忘疲。',48,'全唐诗/poet.tang.41000.json','["讀書與磨劒，旦夕但忘疲。", "儻若功名立，那愁變化遲。", "塵從侵硯席，苔任滿庭墀。", "明代搜揚切，升沈莫問龜。"]'),
('c5ecfa07-7344-4187-bd06-6b791ae38faa','寄劉鈞秀才','李中','唐','唐诗','tang','','[]','掩戶當春晝，知君志在詩。',48,'全唐诗/poet.tang.41000.json','["掩戶當春晝，知君志在詩。", "閑花半落處，幽客未來時。", "野鳥穿莎徑，江雪過竹籬。", "會須明月夜，與子水邊期。"]'),
('eb5eb66a-aeb7-408b-8fc0-3c9568090eb3','離亭前思有寄','李中','唐','唐诗','tang','','[]','酒醒江亭客，纏綿恨別離。',48,'全唐诗/poet.tang.41000.json','["酒醒江亭客，纏綿恨別離。", "笙歌筵散後，風月夜長時。", "耿耿看燈暗，悠悠結夢遲。", "若無騷雅分，何計達相思。"]'),
('ee10d325-2277-43e7-a65e-6d7f344f673f','贈上都先業大師','李中','唐','唐诗','tang','','[]','懶向人前著紫衣，虛堂閑倚一條藜。',64,'全唐诗/poet.tang.41000.json','["懶向人前著紫衣，虛堂閑倚一條藜。", "雖承雨露居龍闕，終憶煙霞夢虎溪。", "睡起曉窗風淅淅，病來深院草萋萋。", "有時乘興尋師去，煮茗同吟到日西。"]'),
('aa85d525-22b2-4b56-9e83-fa05b5b87dfa','思九江舊居三首 一','李中','唐','唐诗','tang','','[]','結茅曾在碧江隈，多病貧身養拙來。',64,'全唐诗/poet.tang.41000.json','["結茅曾在碧江隈，多病貧身養拙來。", "雨歇汀洲垂釣去，月當門巷訪僧迴。", "靜臨窗下開琴匣，悶向牀頭潑酒醅。", "遊宦等閑千里隔，空餘魂夢到漁臺。"]'),
('c55b5a29-376b-4431-a79b-039e74f56aee','思九江舊居三首 二','李中','唐','唐诗','tang','','[]','門前煙水似瀟湘，放曠優游興味長。',64,'全唐诗/poet.tang.41000.json','["門前煙水似瀟湘，放曠優游興味長。", "虛閣靜眠聽遠浪，扁舟閑上泛殘陽。", "鶴翹碧蘚庭除冷，竹引清風枕簟涼。", "犬吠疎籬明月上，隣翁攜酒到茅堂。"]'),
('3c23d117-3e00-438f-8a8b-2e74e53ddb08','思九江舊居三首 三','李中','唐','唐诗','tang','','[]','無機終日狎沙鷗，得意高吟景且幽。',64,'全唐诗/poet.tang.41000.json','["無機終日狎沙鷗，得意高吟景且幽。", "檻底江流偏稱月，簷前山朵最宜秋。", "遙村處處吹橫笛，曲岸家家繫小舟。", "別後再遊心未遂，設屏惟畫白蘋洲。"]'),
('7e540ebb-b2b4-4904-bb80-1e3f7330dfb8','贈東林白大師','李中','唐','唐诗','tang','','[]','虎溪久駐靈蹤，禪外詩魔尚濃。',56,'全唐诗/poet.tang.41000.json','["虎溪久駐靈蹤，禪外詩魔尚濃。", "卷宿吟銷永日，移牀坐對千峰。", "蒼苔冷鏁幽徑，微風閑坐古松。", "自說年來老病，出門漸覺疎慵。"]'),
('f1860069-039a-458e-bc8f-a0145550a09d','春曉','李中','唐','唐诗','tang','','[]','殘燭猶存月尚明，幾家幃幌夢魂驚。',32,'全唐诗/poet.tang.41000.json','["殘燭猶存月尚明，幾家幃幌夢魂驚。", "星河漸沒行人動，歷歷林梢百舌聲。"]'),
('68403fac-9c8e-4fbb-97db-47a14797a0a5','聽鄭羽人彈琴','李中','唐','唐诗','tang','','[]','仙鄉景已清，仙子啓琴聲。',48,'全唐诗/poet.tang.41000.json','["仙鄉景已清，仙子啓琴聲。", "秋月空山寂，淳風一夜生。", "莎間蟲罷響，松頂鶴初驚。", "因感浮華世，誰憐太古情。"]'),
('91c1082e-26de-48d2-b57b-2694d1d855a1','秋夕書事寄友人','李中','唐','唐诗','tang','','[]','信斷關河遠，相思秋夜深。',48,'全唐诗/poet.tang.41000.json','["信斷關河遠，相思秋夜深。", "砌蛩聲咽咽，簷月影沈沈。", "未遂青雲志，那堪素髮侵。", "吟餘成不寐，徹曙四鄰砧。"]'),
('5c42bd45-384b-4d9c-8b5a-0134b1e1025f','秋日途中','李中','唐','唐诗','tang','','[]','竹林已蕭索，客思正如讎。',48,'全唐诗/poet.tang.41000.json','["竹林已蕭索，客思正如讎。", "舊業吳江外，新蟬楚驛頭。", "遙天疎雨過，列岫亂雲收。", "今夕誰家宿，孤吟月色秋。"]'),
('dd5e46cf-fc24-470d-8ad5-60beb540c03a','秋夜吟寄左偃','李中','唐','唐诗','tang','','[]','與君詩興素來狂，況入清秋夜景長。',64,'全唐诗/poet.tang.41000.json','["與君詩興素來狂，況入清秋夜景長。", "溪閣共誰看好月，莎堦應獨聽寒螿。", "卷中新句誠堪喜，身外浮名不足忙。", "會約垂名繼前哲，任他玄髮盡如霜。"]'),
('382ddc78-be7b-4a41-be97-57a47ffc799f','竹','李中','唐','唐诗','tang','','[]','森森移得自山莊，植向空庭野興長。',64,'全唐诗/poet.tang.41000.json','["森森移得自山莊，植向空庭野興長。", "便有好風來枕簟，更無閑夢到瀟湘。", "蔭來砌蘚經疎雨，引下溪禽帶夕陽。", "閑約羽人同賞處，安排棊局就清涼。"]'),
('385fe1e5-c9e6-4dbc-8e1e-98aa55d9da29','懷廬岳舊遊寄劉鈞因感鑒上人','李中','唐','唐诗','tang','','[]','昔年廬岳閑遊日，乘興因尋物外僧。',64,'全唐诗/poet.tang.41000.json','["昔年廬岳閑遊日，乘興因尋物外僧。", "寄宿愛聽松葉雨，論詩惟對竹窗燈。", "各拘片祿尋分別，高謝浮名竟未能。", "一念支公安可見，影堂何處暮雲凝。"]'),
('6b7339dc-2851-4406-b5be-4a56d8f3ea3a','依韻酬智謙上人見寄','李中','唐','唐诗','tang','','[]','性拙才非逸，同心友亦稀。',48,'全唐诗/poet.tang.41000.json','["性拙才非逸，同心友亦稀。", "風昏秋病眼，霜濕夜吟衣。", "鶯谷期猶負，蘭陔養不違。", "吾師惠佳句，勝得楚金歸。"]'),
('e5dbfc4f-340d-4d0f-8c9d-050d9e7a1fdb','落花','李中','唐','唐诗','tang','','[]','年年三月暮，無計惜殘紅。',48,'全唐诗/poet.tang.41000.json','["年年三月暮，無計惜殘紅。", "酷恨西園雨，生憎南陌風。", "片隨流水遠，色逐斷霞空。", "悵望叢林下，悠悠飲興窮。"]'),
('acdc5dd4-8c1e-461b-af08-9c770b204310','題柳','李中','唐','唐诗','tang','','[]','折向離亭畔，春光滿手生。',48,'全唐诗/poet.tang.41000.json','["折向離亭畔，春光滿手生。", "群花豈無豔，柔質自多情。", "夾岸籠溪月，兼風撼野鶯。", "隋堤三月暮，飛絮想縱橫。"]'),
('859d6868-9564-4647-86eb-4e1d01c6a2e6','贈謙明上人','李中','唐','唐诗','tang','','[]','雖寄上都眠竹寺，逸情終憶白雲端。',64,'全唐诗/poet.tang.41000.json','["雖寄上都眠竹寺，逸情終憶白雲端。", "閑登鍾阜林泉晚，夢去沃洲風雨寒。", "新試茶經煎有興，舊嬰詩病捨終難。", "常聞秋夕多無寐，月在高臺獨憑欄。"]'),
('23354138-d189-4592-bf08-de8da5be0079','書蔡隱士壁','李中','唐','唐诗','tang','','[]','病後霜髭出，衡門寂寞中。',48,'全唐诗/poet.tang.41000.json','["病後霜髭出，衡門寂寞中。", "蠹侵書帙損，塵覆酒罇空。", "池暗菰蒲雨，徑香蘭蕙風。", "幽閑已得趣，不見卜窮通。"]'),
('3efb6a51-c126-4b8a-ae99-4f767be6b742','贈鍾尊師遊茅山','李中','唐','唐诗','tang','','[]','笻杖擔琴背俗塵，路尋茅嶺有誰群。',64,'全唐诗/poet.tang.41000.json','["笻杖擔琴背俗塵，路尋茅嶺有誰群。", "仙翁物外應相遇，靈藥壺中必許分。", "香入肌膚花洞酒，冷侵魂夢石牀雲。", "伊予亦有朝修志，異日遨遊願見君。"]'),
('05cbc260-5e6c-4292-88fd-86ade243a9cf','訪徐長史留題水閣','李中','唐','唐诗','tang','','[]','君家池閣靜，一到且淹留。',48,'全唐诗/poet.tang.41000.json','["君家池閣靜，一到且淹留。", "坐聽蒹葭雨，如看島嶼秋。", "杯盤深有興，吟笑迥忘憂。", "更愛幽奇處，雙雙下野鷗。"]'),
('e3f7e39f-e7be-40e2-a5a9-ef9ec1f3853f','夕陽','李中','唐','唐诗','tang','','[]','影未沈山水面紅，遙天雨過促征鴻。',32,'全唐诗/poet.tang.41000.json','["影未沈山水面紅，遙天雨過促征鴻。", "魂銷舉子不回首，閑照槐花驛路中。"]'),
('8cc67c87-2f60-4e50-be11-a5224ef2a467','鸂鶒','李中','唐','唐诗','tang','','[]','流品是鴛鴦，翻飛雲水鄉。',48,'全唐诗/poet.tang.41000.json','["流品是鴛鴦，翻飛雲水鄉。", "風高離極浦，煙暝下方塘。", "比鷺行藏別，穿荷羽翼香。", "雙雙浴輕浪，誰見在瀟湘。"]'),
('19b93af1-390e-4fd0-97eb-59ea42f24836','所思','李中','唐','唐诗','tang','','[]','離思春來切，誰能慰寂寥。',48,'全唐诗/poet.tang.41000.json','["離思春來切，誰能慰寂寥。", "花飛寒食過，雲重楚山遙。", "耿耿夢徒往，悠悠鬢易凋。", "那堪對明月，獨立水邊橋。"]'),
('ee682ad0-691f-4e26-8f4c-3fd869dfbec1','春閨辭二首 一','李中','唐','唐诗','tang','','[]','卷簾遲日暖，睡起思沈沈。',48,'全唐诗/poet.tang.41000.json','["卷簾遲日暖，睡起思沈沈。", "遼海音塵遠，春風旅館深。", "疎篁留鳥語，曲砌轉花陰。", "寄語長征客，流年不易禁。"]'),
('9de537bc-72a1-4f7d-8379-48a4c4545359','春閨辭二首 二','李中','唐','唐诗','tang','','[]','不得遼陽信，春心何以安。',48,'全唐诗/poet.tang.41000.json','["不得遼陽信，春心何以安。", "鳥啼窗樹曉，夢斷碧煙殘。", "綠鑑開還懶，紅顏駐且難。", "相思誰可訴，時取舊書看。"]'),
('b546e502-2411-4b18-9780-5c186a025ece','臘中作','李中','唐','唐诗','tang','','[]','冬至雖云遠，渾疑朔漠中。',48,'全唐诗/poet.tang.41000.json','["冬至雖云遠，渾疑朔漠中。", "勁風吹大野，密雪翳高空。", "泉凍如頑石，人藏類蟄蟲。", "豪家應不覺，獸炭滿爐紅。"]'),
('dbe85b38-7481-4336-9388-a36be9491978','海城秋日書懷寄朐山孫明府','李中','唐','唐诗','tang','','[]','槐柳蟬聲起渡頭，海城孤客思悠悠。',64,'全唐诗/poet.tang.41000.json','["槐柳蟬聲起渡頭，海城孤客思悠悠。", "青雲展志知何日，皓月牽吟又入秋。", "鑑裏漸生潘岳鬢，風前猶著卜商裘。", "鳴琴良宰揮毫士，應笑蹉跎身未酬。"]'),
('fb27edc6-ae5c-450c-9424-3a5d743c6d14','題柴司徒亭假山','李中','唐','唐诗','tang','','[]','疊石峨峨象翠微，遠山魂夢便應稀。',64,'全唐诗/poet.tang.41000.json','["疊石峨峨象翠微，遠山魂夢便應稀。", "從教蘚長添峰色，好引泉來作瀑飛。", "螢影夜攢疑燒起，茶煙朝出認雲歸。", "知君創得茲幽致，公退吟看到落暉。"]'),
('b7e142fa-a1c5-407e-a6b7-73220b5f4de1','都下寒食夜作','李中','唐','唐诗','tang','','[]','香塵未歇暝煙收，城滿笙歌事勝遊。',32,'全唐诗/poet.tang.41000.json','["香塵未歇暝煙收，城滿笙歌事勝遊。", "自是離人睡長早，千家簾卷月當樓。"]'),
('afd6e4a6-9e5c-408b-a8a0-a6cf16d7473b','客中春思','李中','唐','唐诗','tang','','[]','又聽黃鳥綿蠻，目斷家鄉未還。',28,'全唐诗/poet.tang.41000.json','["又聽黃鳥綿蠻，目斷家鄉未還。", "春水引將客夢，悠悠遶遍關山。"]'),
('e156b68c-3a29-4bee-843d-3fe1c67e79a4','所思','李中','唐','唐诗','tang','','[]','門掩殘花寂寂，簾垂斜月悠悠。',28,'全唐诗/poet.tang.41000.json','["門掩殘花寂寂，簾垂斜月悠悠。", "縱有一庭萱草，何曾與我忘憂。"]'),
('074149c1-4f6e-4686-996f-afacb1f76200','江館秋思因成自勉','李中','唐','唐诗','tang','','[]','江邊候館幽，汀鳥暝煙收。',48,'全唐诗/poet.tang.41000.json','["江邊候館幽，汀鳥暝煙收。", "客思雖悲月，詩魔又愛秋。", "聲名都是幻，窮達未能憂。", "散逸憐漁父，波中漾小舟。"]'),
('082661da-b8c9-4c39-898f-952aad6bf4ad','贈朐山楊宰','李中','唐','唐诗','tang','','[]','訟閑徴賦畢，吏散卷簾時。',48,'全唐诗/poet.tang.41000.json','["訟閑徴賦畢，吏散卷簾時。", "聽雨入秋竹，留僧覆舊棋。", "得詩書落葉，煮茗汲寒池。", "化俗功成後，煙霄會有期。"]'),
('360a269e-67a7-446e-9790-2ec78c01e437','廬山','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','控厭潯陽景，崔嵬古及今。',168,'全唐诗/poet.tang.41000.json','["控厭潯陽景，崔嵬古及今。", "勢雄超地表，翠盛接天心。", "湓浦春煙列，星灣晚景沈。", "圖經宜細覽，題詠卒難任。", "靖節門遙對，庾公樓俯臨。", "參差含積雪，隱映見歸禽。", "峭拔推雙劒，清虛數二林。", "白蓮池宛在，翠輦事難尋。", "天近星河冷，龍歸洞穴深。", "谷春攢錦繡，石潤疊瓊琳。", "玄鶴傳仙拜，青猨伴客吟。", "泉通九江遠，雲出幾州陰。", "冬有靈湯溢，夏無炎暑侵。", "他年如遂隱，五老是知音。"]'),
('ecf8f63c-9794-4e44-b907-e464a191e5ee','送孫霽書記赴壽陽[辟]命','李中','唐','唐诗','tang','','[]','辟命羨君赴，其如愴別情。',96,'全唐诗/poet.tang.41000.json','["辟命羨君赴，其如愴別情。", "酒闌汀樹晚，帆展野風生。", "淮靜寒煙歛，村遙夜火明。", "醉沈朐嶺夢，吟達壽春城。", "舊友搖鞭接，元戎掃榻迎。", "雪晴蓮幕啓，雲散桂山橫。", "王粲從軍畫，陳琳草檄名。", "知君提健筆，重振此嘉聲。"]'),
('e9da3de6-98aa-4268-9468-749c5424e519','聽蟬寄朐山孫明府','李中','唐','唐诗','tang','','[]','忽聽新蟬發，客情其奈何。',48,'全唐诗/poet.tang.41000.json','["忽聽新蟬發，客情其奈何。", "西風起槐柳，故國阻煙波。", "壠笛悲猶少，巴猨恨未多。", "不知陶靖節，還動此心麽。"]'),
('f9d3435f-70b0-440e-8d00-4063b73e3bad','秋江夜泊寄劉鈞正字','李中','唐','唐诗','tang','','[]','閑憶詩人思倍勞，維舟清夜泥風騷。',64,'全唐诗/poet.tang.41000.json','["閑憶詩人思倍勞，維舟清夜泥風騷。", "魚龍不動澄江遠，雲霧皆收皎月高。", "潮滿釣舟迷浦嶼，霜繁野樹叫猨猱。", "此時吟苦君知否，雙鬢從他有二毛。"]'),
('bab54698-2d93-4e9c-bb69-faf2613ce866','贈朐山孫明府','李中','唐','唐诗','tang','','[]','縣庭無事似山齋，滿砌青青旋長苔。',64,'全唐诗/poet.tang.41000.json','["縣庭無事似山齋，滿砌青青旋長苔。", "閑撫素琴曹吏散，自烹新茗海僧來。", "買將病鶴勞心養，移得閑花用意栽。", "幾度訪君留我醉，甕香皆值酒新開。"]'),
('fa466916-e6d5-450d-b1b6-c74121f808a7','贈海上書記張濟員外','李中','唐','唐诗','tang','','[]','鵬霄休歎志難伸，貧病雖縈道且存。',64,'全唐诗/poet.tang.41000.json','["鵬霄休歎志難伸，貧病雖縈道且存。", "阮瑀不能專筆硯，嵇康唯要樂琴尊。", "春風滿院空欹枕，芳草侵堦獨閉門。", "劒有塵埃書有蠹，昔年心事共誰論。"]'),
('bf9e6eef-e993-40a2-95b8-57120e743649','對竹','李中','唐','唐诗','tang','','[]','懶穿幽徑衝鳴鳥，忍踏清陰損翠苔。',32,'全唐诗/poet.tang.41000.json','["懶穿幽徑衝鳴鳥，忍踏清陰損翠苔。", "不似閉門欹枕聽，秋聲如雨入軒來。"]'),
('0fe2febb-e787-46db-87a8-b5bb7106cd82','送朐山孫明府赴壽陽幕府辟命','李中','唐','唐诗','tang','','[]','堪羨元戎虛右席，便承綸綍起金臺。',64,'全唐诗/poet.tang.41000.json','["堪羨元戎虛右席，便承綸綍起金臺。", "菊叢憔悴陶潛去，蓮幕光輝阮瑀來。", "好向尊罍陳妙畫，定應書檄播雄才。", "預愁別後相思處，月入閑窗遠夢迴。"]'),
('b3c51847-2082-4b1d-8a8c-4599a72e2066','經廢宅','李中','唐','唐诗','tang','','[]','一夢奢華去不還，斷牆花發豈堪看。',32,'全唐诗/poet.tang.41000.json','["一夢奢華去不還，斷牆花發豈堪看。", "玉纖素綆知何處，金井梧枯碧甃寒。"]'),
('f0e0cb06-986e-45b8-b08e-9084b7b2ede7','溪邊吟','李中','唐','唐诗','tang','','[]','鸂鶒雙飛下碧流，蓼花蘋穗正含秋。',32,'全唐诗/poet.tang.41000.json','["鸂鶒雙飛下碧流，蓼花蘋穗正含秋。", "茜裙二八採蓮去，笑衝微雨上蘭舟。"]'),
('78ebb91b-2ab3-494c-8e47-525cf34e00c7','得故人消息','李中','唐','唐诗','tang','','[]','多難分離久，相思每淚垂。',48,'全唐诗/poet.tang.41000.json','["多難分離久，相思每淚垂。", "夢歸殘月曉，信到落花時。", "未必乖良會，何當有後期。", "那堪樓上望，煙水接天涯。"]'),
('a23b5687-ede7-40df-800c-6752b97e92a5','芳草','李中','唐','唐诗','tang','','[]','二月正綿綿，離情被爾牽。',48,'全唐诗/poet.tang.41000.json','["二月正綿綿，離情被爾牽。", "四鄰初過雨，萬里正鋪煙。", "眷戀殘花惹，留連醉客眠。", "飄香是杜若，最憶楚江邊。"]'),
('813878c5-ac35-43d2-ab52-f78f151f787f','江南春','李中','唐','唐诗','tang','','[]','千家事勝遊，景物可忘憂。',48,'全唐诗/poet.tang.41000.json','["千家事勝遊，景物可忘憂。", "水國樓臺晚，春郊煙雨收。", "鷓鴣啼竹樹，杜若媚汀洲。", "永巷歌聲遠，王孫會莫愁。"]'),
('ceacacbe-09d1-4dca-879f-68dff66da9ca','悼亡','李中','唐','唐诗','tang','','[]','巷深芳草細，門靜綠楊低。',48,'全唐诗/poet.tang.41000.json','["巷深芳草細，門靜綠楊低。", "室邇人何處，花殘月又西。", "武陵期已負，巫峽夢終迷。", "獨立銷魂久，雙雙好鳥啼。"]'),
('3726937b-39c5-4332-9ddc-6e06beabaf26','春晏寄從弟德潤','李中','唐','唐诗','tang','','[]','相思禁煙近，樓上動吟魂。',48,'全唐诗/poet.tang.41000.json','["相思禁煙近，樓上動吟魂。", "水國春寒在，人家暮雨昏。", "朱橋通竹樹，香徑匝蘭蓀。", "安得吾宗會，高歌醉一尊。"]'),
('50b00256-df12-4aed-9f3c-0b524453791e','贈致仕沈彬郎中','李中','唐','唐诗','tang','','[]','自言婚嫁畢，塵事不關心。',48,'全唐诗/poet.tang.41000.json','["自言婚嫁畢，塵事不關心。", "老去詩魔在，春來酒病深。", "山翁期採藥，海月伴鳴琴。", "多謝維舟處，相留接靜吟。"]'),
('a35a41ef-9353-496c-ba82-3f1ca96cfee5','憶溪居','李中','唐','唐诗','tang','','[]','竹軒臨水靜無塵，別後鳧鷖入夢頻。',32,'全唐诗/poet.tang.41000.json','["竹軒臨水靜無塵，別後鳧鷖入夢頻。", "杜若菰蒲煙雨歇，一溪春色屬何人。"]'),
('b672cad4-f5a9-42dc-b900-66f61ccd1459','登下蔡縣樓','李中','唐','唐诗','tang','','[]','長涯煙水又含秋，吏散時時獨上樓。',32,'全唐诗/poet.tang.41000.json','["長涯煙水又含秋，吏散時時獨上樓。", "信斷蘭臺鄉國遠，依稀王粲在荆州。"]'),
('14910201-84b1-45db-97bd-7f18e69211c1','下蔡春偶作','李中','唐','唐诗','tang','','[]','旅館飄飄類斷蓬，悠悠心緒有誰同。',64,'全唐诗/poet.tang.41000.json','["旅館飄飄類斷蓬，悠悠心緒有誰同。", "一宵風雨花飛後，萬里鄉關夢自通。", "多難不堪容鬢改，沃愁惟怕酒杯空。", "採蘭扇沈何時遂，洗慮焚香叩上穹。"]'),
('946a5389-3292-45b1-908a-ce05b8faeddc','再遊洞神宮懷邵羽人有感','李中','唐','唐诗','tang','','[]','重向煙蘿省舊遊，因尋遺跡想浮丘。',64,'全唐诗/poet.tang.41000.json','["重向煙蘿省舊遊，因尋遺跡想浮丘。", "峰頭鶴去三清遠，壇畔月明千古秋。", "泉落小池清復咽，雲從高嶠起還收。", "自慙未得沖虛術，白髮無情漸滿頭。"]'),
('b32e9626-d13d-4b2a-b68f-51bedad2cc22','秋雨二首 一','李中','唐','唐诗','tang','','[]','飄灑當窮巷，苔深落葉鋪。',48,'全唐诗/poet.tang.41000.json','["飄灑當窮巷，苔深落葉鋪。", "送寒來客館，滴夢在庭梧。", "逼砌蛩聲斷，侵窗竹影孤。", "遙思漁叟興，蓑笠在江湖。"]'),
('49c874de-e656-477e-b161-b038703f299d','秋雨二首 二','李中','唐','唐诗','tang','','[]','竟日聲蕭颯，兼風不暫闌。',48,'全唐诗/poet.tang.41000.json','["竟日聲蕭颯，兼風不暫闌。", "竹窗秋睡美，荻浦夜漁寒。", "地僻苔生易，林疎鳥宿難。", "誰知苦吟者，坐聽一燈殘。"]'),
('acd98737-85a0-414f-902f-d32bfc6f7781','經古觀有感','李中','唐','唐诗','tang','','[]','古觀寥寥枕碧溪，偶思前事立殘暉。',64,'全唐诗/poet.tang.41000.json','["古觀寥寥枕碧溪，偶思前事立殘暉。", "漆園化蝶名空在，柱史猶龍去不歸。", "丹井泉枯苔鎖合，醮壇松折鶴來稀。", "回頭因歎浮生事，夢裏光陰疾若飛。"]'),
('0c7aa01c-455b-4df7-be88-0960436d40cb','吉水春暮訪蔡文慶處士留題','李中','唐','唐诗','tang','','[]','無事無憂鬢任蒼，濁醪閑酌送韶光。',64,'全唐诗/poet.tang.41000.json','["無事無憂鬢任蒼，濁醪閑酌送韶光。", "溟濛雨過池塘暖，狼藉花飛硯席香。", "好古未嘗疎典冊，懸圖時要看瀟湘。", "戀君清話難留處，歸路迢迢又夕陽。"]'),
('e2b75c92-9143-473e-8e9e-4c1b9971feb9','烈祖孝高挽歌二首 一','李中','唐','唐诗','tang','','[]','誰解叩乾關，音容去不還。',48,'全唐诗/poet.tang.41000.json','["誰解叩乾關，音容去不還。", "位方尊北極，壽忽殞南山。", "鳳輦應難問，龍髯不可攀。", "千秋遺恨處，雲物鎖橋山。"]'),
('e1d6a327-561a-42c5-96eb-7704f8cb42e8','烈祖孝高挽歌二首 二','李中','唐','唐诗','tang','','[]','仙馭歸何處，蒼蒼問且難。',48,'全唐诗/poet.tang.41000.json','["仙馭歸何處，蒼蒼問且難。", "華夷喧道德，陵壠葬衣冠。", "御水穿城咽，宮花泣露寒。", "九疑消息斷，空望白雲端。"]'),
('273da384-9ce2-4801-a771-70ce779e831c','贈海上觀音院文依上人','李中','唐','唐诗','tang','','[]','煙霞海邊寺，高臥出門慵。',48,'全唐诗/poet.tang.41000.json','["煙霞海邊寺，高臥出門慵。", "白日少來客，清風生古松。", "虛窗從燕入，壞屐任苔封。", "幾度陪師話，相留到暮鍾。"]'),
('86a6df57-392c-49d0-b14f-6ae0373189cc','秋夕病中作','李中','唐','唐诗','tang','','[]','臥病當秋夕，悠悠枕上情。',48,'全唐诗/poet.tang.41000.json','["臥病當秋夕，悠悠枕上情。", "不堪拋月色，無計避蟲聲。", "煎藥惟憂澁，停燈又怕明。", "曉臨清鑑裏，應有白髭生。"]'),
('e4174f43-2ab1-449c-8fcc-1dc4deb27124','寄黃鶚秀才','李中','唐','唐诗','tang','','[]','長憶狂遊日，惜春心恰同。',48,'全唐诗/poet.tang.41000.json','["長憶狂遊日，惜春心恰同。", "預愁花片落，不遣酒壺空。", "草軟眠難捨，鶯嬌聽莫窮。", "如今千里隔，騷首對秋風。"]'),
('c5bc934a-64fa-40cb-8978-9d94f2dfacdb','春日書懷寄朐山孫明府','李中','唐','唐诗','tang','','[]','一作邊城客，閑門兩度春。',48,'全唐诗/poet.tang.41000.json','["一作邊城客，閑門兩度春。", "鶯花深院雨，書劒滿牀塵。", "紫閣期終負，青雲道未伸。", "猶憐陶靖節，詩酒每相親。"]'),
('f36ab51b-0cd7-433f-b68e-067042aaa53f','柴司徒宅牡丹','李中','唐','唐诗','tang','','[]','暮春欄檻有佳期，公子開顏乍拆時。',64,'全唐诗/poet.tang.41000.json','["暮春欄檻有佳期，公子開顏乍拆時。", "翠幄密籠鶯未識，好香難掩蝶先知。", "願陪妓女爭調樂，欲賞賓朋預課詩。", "只恐却隨雲雨去，隔年還是動相思。"]'),
('fc8a87a7-611e-4773-bbbe-f7ac89e318bc','贈王道者','李中','唐','唐诗','tang','','[]','混俗從教鬢似銀，世人無分得相親。',64,'全唐诗/poet.tang.41000.json','["混俗從教鬢似銀，世人無分得相親。", "槎流海上波濤闊，酒滿壺中天地春。", "功就不看丹竈火，性閑時拂玉琴塵。", "仙家變化誰能測，只恐洪崖是此身。"]'),
('5728ceb6-d26a-43fe-a354-4c228c91a386','春閨辭二首 一','李中','唐','唐诗','tang','','[]','塵昏菱鑑懶修容，雙臉桃花落盡紅。',32,'全唐诗/poet.tang.41000.json','["塵昏菱鑑懶修容，雙臉桃花落盡紅。", "玉塞夢歸殘燭在，曉鶯窗外囀梧桐。"]'),
('4243b281-f54f-423a-b018-608dd9a77efa','春閨辭二首 二','李中','唐','唐诗','tang','','[]','邊無音信暗消魂，茜袖香裙積淚痕。',32,'全唐诗/poet.tang.41000.json','["邊無音信暗消魂，茜袖香裙積淚痕。", "海燕歸來門未掩，悠悠花落又黃昏。"]'),
('6b3fdf19-ad86-4eba-83b9-131995950134','暮春懷故人','李中','唐','唐诗','tang','','[]','池館寂寥三月盡，落花重疊蓋莓苔。',64,'全唐诗/poet.tang.41000.json','["池館寂寥三月盡，落花重疊蓋莓苔。", "惜春眷戀不忍掃，感物心情無計開。", "夢斷美人沈信息，目穿長路倚樓臺。", "琅玕繡段安可得，流水浮雲共不迴。"]'),
('0ecfb57b-64d9-47d1-8bd4-a2f074c4a410','秋日登潤州城樓','李中','唐','唐诗','tang','','[]','虛樓一望極封疆，積雨晴來野景長。',64,'全唐诗/poet.tang.41000.json','["虛樓一望極封疆，積雨晴來野景長。", "水接海門鋪遠色，稻連京口發秋香。", "鳴蟬歷歷空相續，歸鳥翩翩自著行。", "吟罷倚欄深有思，清風留我到斜陽。"]'),
('6acae7e6-08f9-4d3d-8583-c2176a1e7d91','晚春客次偶吟','李中','唐','唐诗','tang','','[]','暫駐征輪野店間，悠悠時節又春殘。',64,'全唐诗/poet.tang.41000.json','["暫駐征輪野店間，悠悠時節又春殘。", "落花風急宿酲解，芳草雨昏春夢寒。", "慙逐利名頭易白，欲眠雲水志猶難。", "却憐村寺僧相引，閑上虛樓共倚欄。"]'),
('c440c023-a648-4596-a2ad-7b5b101709ed','對雨寄朐山林番明府','李中','唐','唐诗','tang','','[]','竟日如絲不暫停，莎堦閑聽滴秋聲。',64,'全唐诗/poet.tang.41000.json','["竟日如絲不暫停，莎堦閑聽滴秋聲。", "斜飄虛閣琴書潤，冷逼幽窗夢寐清。", "開戶只添搜句味，看山還阻上樓情。", "遙知公退琴堂靜，坐對蕭騷飲興生。"]'),
('19f00378-fea5-4f11-a9f7-221b106d422f','落花','李中','唐','唐诗','tang','','[]','殘紅引動詩魔，懷古牽情奈何。',56,'全唐诗/poet.tang.41000.json','["殘紅引動詩魔，懷古牽情奈何。", "半落銅臺月曉，亂飄金谷風多。", "悠悠旋逐流水，片片輕黏短莎。", "誰見長門深鎖，黃昏細雨相和。"]'),
('91643007-11c7-46ff-b178-27abc7fc0c8f','燕','李中','唐','唐诗','tang','','[]','豪家五色泥香，銜得營巢太忙。',28,'全唐诗/poet.tang.41000.json','["豪家五色泥香，銜得營巢太忙。", "喧覺佳人晝夢，雙雙猶在雕梁。"]'),
('523ca0c5-fd46-4ab7-bd37-38dbe0b42c33','鶯','李中','唐','唐诗','tang','','[]','羽毛特異諸禽，出谷堪聽好音。',28,'全唐诗/poet.tang.41000.json','["羽毛特異諸禽，出谷堪聽好音。", "薄暮欲棲何處，雨昏楊柳深深。"]'),
('130c6ef8-0816-4235-b7df-844c78d59c1c','宿山中寺','李中','唐','唐诗','tang','','[]','寄宿深山寺，惟逢老病僧。',48,'全唐诗/poet.tang.41000.json','["寄宿深山寺，惟逢老病僧。", "風吹幾世樹，雲暗暮秋燈。", "瞑目忘塵慮，談空入上乘。", "明晨返名路，何計戀南能。"]'),
('020110e9-fdd2-49a4-9c49-9c0b6e76efa6','海上載筆依韻酬左偃見寄','李中','唐','唐诗','tang','','[]','都城分別後，海嶠夢魂迷。',48,'全唐诗/poet.tang.41000.json','["都城分別後，海嶠夢魂迷。", "吟興疎煙月，邊情起鼓鼙。", "戍旗風颭小，營柳霧籠低。", "草檄無餘刃，難將阮瑀齊。"]'),
('31c99e62-f25d-41f5-802d-b292c930f9ef','春晚招魯從事','李中','唐','唐诗','tang','','[]','衮衮利名役，常嗟聚會稀。',48,'全唐诗/poet.tang.41000.json','["衮衮利名役，常嗟聚會稀。", "有心遊好景，無術駐殘暉。", "南陌草爭茂，西園花亂飛。", "期君舉杯酒，不醉莫言歸。"]'),
('4b7dfb70-c85d-4543-8461-cf258bae0e81','和易秀才春日見寄','李中','唐','唐诗','tang','','[]','每恨多流落，吾徒不易親。',48,'全唐诗/poet.tang.41000.json','["每恨多流落，吾徒不易親。", "相逢千里客，共醉百花春。", "小檻山當面，閑堦柳拂塵。", "何時卜西上，明月桂枝新。"]'),
('317b790e-780e-44e5-a131-990b36c16088','送黃秀才','李中','唐','唐诗','tang','','[]','雨餘飛絮亂，相別思難任。',48,'全唐诗/poet.tang.41000.json','["雨餘飛絮亂，相別思難任。", "酒罷河橋晚，帆開煙水深。", "蟾宮須展志，漁艇莫牽心。", "岐路從茲遠，雙魚信勿沈。"]'),
('0860da79-2b6f-485e-ba23-775d5bf9dbb5','庭竹','李中','唐','唐诗','tang','','[]','偶自山僧院，移歸傍砌栽。',48,'全唐诗/poet.tang.41000.json','["偶自山僧院，移歸傍砌栽。", "好風終日起，幽鳥有時來。", "篩月牽詩興，籠煙伴酒杯。", "南窗睡輕起，蕭颯雨聲迴。"]'),
('4601f286-cad7-4f76-86d9-79fd39578aec','送戴秀才','李中','唐','唐诗','tang','','[]','已是殊鄉客，送君重慘然。',48,'全唐诗/poet.tang.41000.json','["已是殊鄉客，送君重慘然。", "河橋乍分首，槐柳正鳴蟬。", "短櫂離幽浦，孤帆觸遠煙。", "清朝重文物，變化莫遷延。"]'),
('c41d63e5-7f9b-45df-a6cf-e5e8e9b38b38','病中作','李中','唐','唐诗','tang','','[]','閑齋病初起，心緒復悠悠。',48,'全唐诗/poet.tang.41000.json','["閑齋病初起，心緒復悠悠。", "開篋羣書蠹，聽蟬滿樹秋。", "詩魔還漸動，藥債未能酬。", "爲憶前山色，扶持上小樓。"]'),
('6a965aa6-241d-41d3-8a27-0904efde8e04','離家','李中','唐','唐诗','tang','','[]','送別人歸春日斜，獨鞭羸馬指天涯。',32,'全唐诗/poet.tang.41000.json','["送別人歸春日斜，獨鞭羸馬指天涯。", "月生江上鄉心動，投宿怱忙近酒家。"]'),
('1c5cbbb6-8494-4c89-ae8c-73e141ba540e','村行','李中','唐','唐诗','tang','','[]','極目青青壠麥齊，野塘波闊下鳧鷖。',32,'全唐诗/poet.tang.41000.json','["極目青青壠麥齊，野塘波闊下鳧鷖。", "陽烏景暖林桑密，獨立閑聽戴勝啼。"]'),
('75feca6f-3ff9-4b84-bcff-6994bfe04285','獻喬侍郎','李中','唐','唐诗','tang','','[]','位望誰能並，當年志已伸。',240,'全唐诗/poet.tang.41000.json','["位望誰能並，當年志已伸。", "人間傳鳳藻，天上演龍綸。", "賈馬才無敵，褒雄譽益臻。", "除奸深繫念，致主迥忘身。", "諫疏縱橫上，危言果敢陳。", "忠貞雖貫世，消長豈由人。", "慷慨辭朝闕，迢遙涉路塵。", "千山明夕照，孤櫂渡長津。", "杜宇聲方切，江蘺色正新。", "卷舒唯合道，喜慍不勞神。", "蟬客陪清論，漁翁作近鄰。", "靜吟窮野景，狂醉養天真。", "格論思名士，輿情渴直臣。", "九霄恩復降，比戶意皆忻。", "却入鴛鸞序，終身顧問頻。", "漏殘丹禁曉，日暖玉墀春。", "鑒物心如水，憂時鬢若銀。", "惟期康庶事，永要敘彝倫。", "貴賤知無間，孤寒必許親。", "幾多沈滯者，拭目望陶鈞。"]'),
('9712bc02-6680-4144-957d-5fe368cca038','獻中書張舍人','李中','唐','唐诗','tang','','[]','仙桂從攀後，人間播大名。',144,'全唐诗/poet.tang.41000.json','["仙桂從攀後，人間播大名。", "飛騰諧素志，霄漢是前程。", "持憲威聲振，司言品秩清。", "簾開春酒醒，月上草麻成。", "丹陛凌晨對，青雲逐步生。", "照人裴玉瑩，鑒物憲陂明。", "下直無他事，閑遊恣逸情。", "林僧開戶接，溪叟掃苔迎。", "煮茗山房冷，垂綸野艇輕。", "神清宜放曠，詩苦益縱橫。", "餘刃時皆仰，嘉謀衆佇行。", "四方觀啓沃，畢竟念孤平。"]'),
('e9c2b5bb-ac00-4332-8fa8-f2860fc22b82','海上和郎戩員外赴倅職','李中','唐','唐诗','tang','','[]','宋玉逢秋何起悲，新恩委寄好開眉。',64,'全唐诗/poet.tang.41000.json','["宋玉逢秋何起悲，新恩委寄好開眉。", "班升鴛鷺頻經歲，任佐龔黃必暫時。", "乍對煙霞吟海嶠，應思蘋蓼夢江湄。", "一朝鳳詔仲徵入，鵬化那教尺鷃知。"]'),
('5323719b-d795-402b-886c-1c005dd2ab09','又送赴關','李中','唐','唐诗','tang','','[]','心似白雲歸帝鄉，暫停良畫別龔黃。',64,'全唐诗/poet.tang.41000.json','["心似白雲歸帝鄉，暫停良畫別龔黃。", "煙波乍曉浮蘭櫂，魂夢先飛近御香。", "一路伴吟汀草綠，幾程清思水風涼。", "想應敷對忠言後，不放鄉雲離太陽。"]'),
('d9b0a2c4-06da-491c-a216-76a249fd7b45','書郭判官幽齋壁','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','不妨公退尚清虛，剏得幽齋興有餘。',64,'全唐诗/poet.tang.41000.json','["不妨公退尚清虛，剏得幽齋興有餘。", "要引好風清戶牖，旋栽新竹滿庭除。", "傾壺待客花開後，煮茗留僧月上初。", "更有野情堪愛處，石牀苔蘚似匡廬。"]'),
('84ae3e0a-e3c1-4224-b386-6f7e8d5dc075','石棊局獻時宰','李中','唐','唐诗','tang','','[]','得從岳叟誠堪重，却獻臯夔事更宜。',64,'全唐诗/poet.tang.41000.json','["得從岳叟誠堪重，却獻臯夔事更宜。", "公退啓枰書院靜，日斜收子竹陰移。", "適情豈待樵柯爛，罷局還應屐齒隳。", "預想幽窗風雨夜，一燈閑照覆圖時。"]'),
('394b6d18-0f4e-46af-ae57-6570d6ee8004','海城秋夕寄懷舍弟','李中','唐','唐诗','tang','','[]','鳥棲庭樹夜悠悠，枕上誰知淚暗流。',64,'全唐诗/poet.tang.41000.json','["鳥棲庭樹夜悠悠，枕上誰知淚暗流。", "千里夢魂迷舊業，一城砧杵搗殘秋。", "窗閑寂寂燈猶在，簾外蕭蕭雨未休。", "早晚萊衣同著去，免悲流落在邊州。"]'),
('2ca9b822-94d4-4adb-b733-a8fd96a022c5','和夏侯秀才春日見寄','李中','唐','唐诗','tang','','[]','綿蠻黃鳥不堪聽，觸目離愁怕酒醒。',64,'全唐诗/poet.tang.41000.json','["綿蠻黃鳥不堪聽，觸目離愁怕酒醒。", "雲散碧山當晚檻，雨催青蘚匝春庭。", "尋芳懶向桃花塢，垂釣空思杜若汀。", "晝夢不成吟有興，揮毫書在枕邊屏。"]'),
('7d4eaa4e-97ac-4cb6-aa6b-1444a0fa2096','送夏侯秀才','李中','唐','唐诗','tang','','[]','江村搖落暮蟬鳴，執手臨岐動別情。',64,'全唐诗/poet.tang.41000.json','["江村搖落暮蟬鳴，執手臨岐動別情。", "古岸相看殘照在，片帆難駐好風生。", "牽吟一路逢山色，醒睡長汀對月明。", "況是清朝至公在，預知喬木定遷鶯。"]'),
('032bf400-f1fc-4d70-88d4-1387e993700f','江南重會友人感舊二首 一','李中','唐','唐诗','tang','','[]','江南重會面，聊話十年心。',48,'全唐诗/poet.tang.41000.json','["江南重會面，聊話十年心。", "共立黃花畔，空驚素髮侵。", "斜陽浮遠水，歸鳥下疎林。", "牽動詩魔處，涼風村落砧。"]'),
('a34e3a94-f1c5-478d-b135-f5d276a6492d','江南重會友人感舊二首 二','李中','唐','唐诗','tang','','["\u957f\u6c5f"]','長江落照天，物景似當年。',48,'全唐诗/poet.tang.41000.json','["長江落照天，物景似當年。", "憶昔攜村酒，相將上釣船。", "狂歌紅蓼岸，驚起白鷗眠。", "今日趨名急，臨風一黯然。"]'),
('62a9991a-6ddc-4c0b-aa5f-5e53adcda83a','己未歲冬捧宣頭離下蔡','李中','唐','唐诗','tang','','[]','詔下如春煦，巢南志不違。',48,'全唐诗/poet.tang.41000.json','["詔下如春煦，巢南志不違。", "空將感恩淚，滴盡冒寒衣。", "覆載元容善，形骸果得歸。", "無心漸季路，負米覲親闈。"]'),
('11c183c0-58c9-4f83-9cd6-7323965eed5c','哭舍弟二首 一','李中','唐','唐诗','tang','','[]','鴻鴈離群後，成行憶日存。',48,'全唐诗/poet.tang.41000.json','["鴻鴈離群後，成行憶日存。", "誰知歸故里，只得奠吟魂。", "蟲蠹書盈篋，人稀草擁門。", "從茲長慟後，獨自奉晨昏。"]'),
('a32e2219-4ebd-46fc-a6a4-5507b53af8f5','哭舍弟二首 二','李中','唐','唐诗','tang','','[]','浮生多夭枉，惟爾最堪悲。',48,'全唐诗/poet.tang.41000.json','["浮生多夭枉，惟爾最堪悲。", "同氣未歸日，慈親臨老時。", "舊詩傳海嶠，新塚枕江湄。", "遺稚嗚嗚處，黃昏繞穗帷。"]'),
('8e756a61-a7c4-41ff-8ba8-9d4d3a4ba130','書情寄詩友','李中','唐','唐诗','tang','','[]','默默誰知我，裴回野水邊。',48,'全唐诗/poet.tang.41000.json','["默默誰知我，裴回野水邊。", "詩情長若舊，吾事更無先。", "芳草人稀地，殘陽鴈過天。", "靜思吟友外，此意復誰憐。"]'),
('7cb39184-b01c-4577-bbcb-f1471ee8de3a','讀蜀志','李中','唐','唐诗','tang','','[]','鼎分天地日，先主力元微。',48,'全唐诗/poet.tang.41000.json','["鼎分天地日，先主力元微。", "魚水從相得，山河遂有歸。", "任賢無間忌，報國盡神機。", "草昧爭雄者，君臣似此稀。"]'),
('c924da38-8916-427b-8a4c-287f0918585b','獻張拾遺','李中','唐','唐诗','tang','','[]','官資清貴近丹墀，性格孤高世所稀。',64,'全唐诗/poet.tang.41000.json','["官資清貴近丹墀，性格孤高世所稀。", "金殿日開親鳳扆，古幈時展看漁磯。", "酒醒虛閣秋簾捲，吟對疎篁夕鳥歸。", "獻替頻陳忠譽播，鵬霄萬里展雄飛。"]'),
('c8c60dde-c7ce-4fd7-9ae3-d2f79371d650','獻中書湯舍人','李中','唐','唐诗','tang','','[]','慶雲呈瑞爲明時，演暢絲綸在紫微。',64,'全唐诗/poet.tang.41000.json','["慶雲呈瑞爲明時，演暢絲綸在紫微。", "鑾殿對時親舜日，鯉庭過處著萊衣。", "閑尋竹寺聽啼鳥，吟倚江樓戀落暉。", "隔座銀屏看是設，一門清貴古今稀。"]'),
('62192e5b-f928-4529-9a04-7e630463914d','海上太守新剏東亭','李中','唐','唐诗','tang','','[]','使君心智杳難同，選勝開亭景莫窮。',96,'全唐诗/poet.tang.41000.json','["使君心智杳難同，選勝開亭景莫窮。", "高敞軒窗迎海月，預栽花木待春風。", "靜披典籍堪師古，醉擁笙歌不礙公。", "滿徑苔紋疎雨後，入簷山色夕陽中。", "偏宜下榻延徐孺，最稱登門禮孔融。", "事簡豈妨頻賞翫，況當爲政有餘功。"]'),
('7818bc9f-74d9-44cb-a591-cc6416d08820','宮詞二首 一','李中','唐','唐诗','tang','','[]','門鏁簾垂月影斜，翠華咫尺隔天涯。',32,'全唐诗/poet.tang.41000.json','["門鏁簾垂月影斜，翠華咫尺隔天涯。", "香鋪羅幌不成夢，背壁銀缸落盡花。"]'),
('71f6c4bc-776d-4674-8785-e72e5578526b','宮詞二首 二','李中','唐','唐诗','tang','','[]','金波寒透水精簾，燒盡沈檀手自添。',32,'全唐诗/poet.tang.41000.json','["金波寒透水精簾，燒盡沈檀手自添。", "風遞笙歌門已掩，翠華何處夜厭厭。"]'),
('731a03c8-516e-40cf-b1b4-4cfabf372004','採蓮女','李中','唐','唐诗','tang','','[]','晚涼含笑上蘭舟，波底紅妝影欲浮。',32,'全唐诗/poet.tang.41000.json','["晚涼含笑上蘭舟，波底紅妝影欲浮。", "陌上少年休植足，荷香深處不迴頭。"]'),
('70bc1882-b13a-4a6e-8777-6cdad5b7de1e','鍾陵春思','李中','唐','唐诗','tang','','[]','沈沈樓影月當午，冉冉風香花正開。',32,'全唐诗/poet.tang.41000.json','["沈沈樓影月當午，冉冉風香花正開。", "芳草迢迢滿南陌，王孫何處不歸來。"]'),
('b4f57884-539d-485f-86e6-8ac3170b4f04','贈夏秀才','李中','唐','唐诗','tang','','[]','軒車紫陌競尋春，獨掩衡門病起身。',64,'全唐诗/poet.tang.41000.json','["軒車紫陌競尋春，獨掩衡門病起身。", "步月怕傷三徑蘚，取琴因拂一牀塵。", "明時儻有丹枝分，青鑑從他素髮新。", "況是青雲知己在，原思生計莫憂貧。"]'),
('acabd0b0-1481-4e50-ac71-1ecc45781175','夏日書依上人壁','李中','唐','唐诗','tang','','[]','門外塵飛暑氣濃，院中蕭索似山中。',32,'全唐诗/poet.tang.41000.json','["門外塵飛暑氣濃，院中蕭索似山中。", "最憐煮茗相留處，疎竹當軒一榻風。"]'),
('d3a1115b-822a-4c0d-9f10-8ef55ce1cb5e','下蔡春暮旅懷','李中','唐','唐诗','tang','','[]','柳過春霖絮亂飛，旅中懷抱獨[悽悽]。',66,'全唐诗/poet.tang.41000.json','["柳過春霖絮亂飛，旅中懷抱獨[悽悽]。", "月生淮上雲初散，家在江南夢去迷。", "髮白每慙清鑑啓，心孤長怯子規啼。", "拜恩爲養慈親急，願向明朝捧紫泥。"]'),
('9ed35690-e5c7-461f-a861-21e837ec4aca','捧宣頭許歸侍養','李中','唐','唐诗','tang','','[]','泥書捧處聖恩新，許覲庭闈養二親。',32,'全唐诗/poet.tang.41000.json','["泥書捧處聖恩新，許覲庭闈養二親。", "螻蟻至微寧足數，未知何處答穹旻。"]'),
('72e10585-0f8e-4b1f-ab52-babf9dbfdf44','途中作','李中','唐','唐诗','tang','','[]','煙波涉歷指家林，欲到家林懼却深。',32,'全唐诗/poet.tang.41000.json','["煙波涉歷指家林，欲到家林懼却深。", "得信慈親痾瘵減，當時寬勉採蘭心。"]'),
('ecbf9aaf-f31d-4314-94dc-d4adf4bb6ffc','都下再會友人','李中','唐','唐诗','tang','','[]','誰言多難後，重會喜淹留。',48,'全唐诗/poet.tang.41000.json','["誰言多難後，重會喜淹留。", "欲話關河夢，先驚鬢髮秋。", "浮雲空冉冉，遠水自悠悠。", "多謝開青眼，攜壺共上樓。"]'),
('4bc30e9f-8e01-442d-b633-e35b71f97027','登毘陵青山樓','李中','唐','唐诗','tang','','[]','高樓閑上對晴空，豁目開襟半日中。',64,'全唐诗/poet.tang.41000.json','["高樓閑上對晴空，豁目開襟半日中。", "千里吳山清不斷，一邊遼海浸無窮。", "人生歌笑開花霧，世界興亡落葉風。", "吟罷倚欄何限意，回頭城郭暮煙籠。"]'),
('9d0c6032-a0dd-4ac0-b63b-45ea9edf60e5','晉陵罷任寓居依韻和陳銳秀才見寄','李中','唐','唐诗','tang','','[]','掩門三徑莓苔綠，車馬誰來陋巷間。',64,'全唐诗/poet.tang.41000.json','["掩門三徑莓苔綠，車馬誰來陋巷間。", "臥棄琴書公幹病，笑迎風月步兵閑。", "當秋每謝蛬清耳，漸老多慙酒借顏。", "濟物未能伸一術，敢於明代愛青山。"]'),
('f8448017-073f-4d7a-a1c4-8b5f7e046acd','春苔','李中','唐','唐诗','tang','','[]','春霖催得鎖煙濃，竹院莎齋徑小通。',32,'全唐诗/poet.tang.41000.json','["春霖催得鎖煙濃，竹院莎齋徑小通。", "誰愛落花風味處，莫愁門巷襯殘紅。"]'),
('169c0859-84c4-4f68-a5cf-2523bef6bd36','夏雲','李中','唐','唐诗','tang','','[]','如峰形狀在西郊，未見從龍上泬寥。',32,'全唐诗/poet.tang.41000.json','["如峰形狀在西郊，未見從龍上泬寥。", "多謝好風吹起後，化爲甘雨濟田苗。"]'),
('a5ad7fb3-9f7f-4e7f-b6a5-de2a5974be09','書夏秀才幽居壁','李中','唐','唐诗','tang','','[]','永巷苔深戶半開，牀頭書劒積塵埃。',32,'全唐诗/poet.tang.41000.json','["永巷苔深戶半開，牀頭書劒積塵埃。", "最憐小檻疎篁晩，幽鳥雙雙何處來。"]'),
('9e299667-0a16-48f2-8942-68ca2ecf5f33','紅花','李中','唐','唐诗','tang','','[]','紅花顏色掩千花，任是猩猩血未加。',32,'全唐诗/poet.tang.41000.json','["紅花顏色掩千花，任是猩猩血未加。", "染出輕羅莫相貴，古人崇儉誡奢華。"]'),
('b68f17e0-18b1-4d75-9f39-7035508d55a1','安福縣秋吟寄陳銳秘書','李中','唐','唐诗','tang','','[]','縣庭事簡得餘功，詩興秋來不可窮。',64,'全唐诗/poet.tang.41000.json','["縣庭事簡得餘功，詩興秋來不可窮。", "臥聽寒蛬莎砌月，行衝落葉水村風。", "愁髭漸去人前白，醉面猶憐鑑裏紅。", "苦恨交親多契闊，未知良會幾時同。"]'),
('2096f5c4-9908-4eef-b561-44bfe143e8de','新喻縣酬王仲華少府見貽','李中','唐','唐诗','tang','','[]','事簡開樽有逸情，共忻官舍月華清。',64,'全唐诗/poet.tang.41000.json','["事簡開樽有逸情，共忻官舍月華清。", "每慙花欠河陽景，長愧琴無單父聲。", "未泰黎元慚曠職，縱行謙直是虛名。", "與君盡力行公道，敢向昌朝俟陟明。"]'),
('1dfa1512-5774-4d8e-a07a-896fee7f4e6f','暮春有感寄宋維員外','李中','唐','唐诗','tang','','[]','杜宇聲中老病心，此心無計駐光陰。',64,'全唐诗/poet.tang.41000.json','["杜宇聲中老病心，此心無計駐光陰。", "西園雨過好花盡，南陌人稀芳草深。", "喧夢却嫌鶯語老，伴吟惟怕月輪沈。", "明年才候東風至，結駟期君預去尋。"]'),
('550020be-f537-4cac-aaa8-b9357a80e8bb','題吉水縣廳前新栽小松','李中','唐','唐诗','tang','','[]','斸開幽澗蘚苔斑，移得孤根植砌前。',64,'全唐诗/poet.tang.41000.json','["斸開幽澗蘚苔斑，移得孤根植砌前。", "影小未遮官舍月，翠濃猶帶舊山煙。", "群花解笑香寧久，衆木雖高節不堅。", "輸我婆娑欄檻內，晚風蕭颯學幽泉。"]'),
('32f480ba-1979-4391-afaa-6d0b6b9de62f','贈念法華經綬上人','李中','唐','唐诗','tang','','[]','五更初起掃松堂，瞑目先焚一炷香。',32,'全唐诗/poet.tang.41000.json','["五更初起掃松堂，瞑目先焚一炷香。", "念徹蓮經誰得見，千峰巖外曉蒼蒼。"]'),
('3444baf4-08c8-41b8-b38e-c619e9218c35','秋日途中','李中','唐','唐诗','tang','','[]','信步騰騰野岸邊，離家都爲利名牽。',32,'全唐诗/poet.tang.41000.json','["信步騰騰野岸邊，離家都爲利名牽。", "疎林一路斜陽裏，颯颯西風滿耳蟬。"]'),
('ee35c3a8-1979-433a-906e-86fee58de352','宿韋校書幽居','李中','唐','唐诗','tang','','[]','溪上高眠與鶴閑，開樽留我待柴關。',32,'全唐诗/poet.tang.41000.json','["溪上高眠與鶴閑，開樽留我待柴關。", "園林月白秋霖歇，一夜泉聲似故山。"]'),
('66c1e838-7329-46bf-8e03-d63e765a6d9e','依韻和友人秋夕見寄','李中','唐','唐诗','tang','','[]','夕風庭葉落，誰見此時情。',48,'全唐诗/poet.tang.41000.json','["夕風庭葉落，誰見此時情。", "不作關河夢，空聞砧杵聲。", "會須求至理，何必歎無成。", "好約高僧宿，同看海月生。"]'),
('2e3bd71c-9be5-48f1-a8b4-c03c93c2da03','吉水作尉酬高援秀才見贈','李中','唐','唐诗','tang','','[]','佐邑慙無術，敢言貧與清。',48,'全唐诗/poet.tang.41000.json','["佐邑慙無術，敢言貧與清。", "風騷誰是主，煙月自關情。", "卷箔當山色，開窗就竹聲。", "憐君惠嘉句，資我欲垂名。"]'),
('2bd4868f-9db9-4f92-945b-373cc4175315','送智雄上人','李中','唐','唐诗','tang','','[]','忽起游方念，飄然不可留。',48,'全唐诗/poet.tang.41000.json','["忽起游方念，飄然不可留。", "未知攜一錫，乘興向何州。", "古岸春雲散，遙天晚雨收。", "想應重會面，風月又清秋。"]'),
('8e2eb537-652c-4360-a279-ae724c397e4b','覽友人卷','李中','唐','唐诗','tang','','[]','新詩開卷處，造化竭精英。',48,'全唐诗/poet.tang.41000.json','["新詩開卷處，造化竭精英。", "雪霽楚山碧，月高湘水清。", "初吟塵慮息，再味古風生。", "自此寰區內，喧騰二雅名。"]'),
('4084fee4-f461-4dad-a480-9244f0881c1e','送人南遊','李中','唐','唐诗','tang','','[]','浪跡天涯去，南荒必動情。',48,'全唐诗/poet.tang.41000.json','["浪跡天涯去，南荒必動情。", "草青虞帝廟，雲暗夜郎城。", "越鳥驚鄉夢，蠻風解宿酲。", "早思歸故里，華髮等閑生。"]'),
('074ad70b-18df-4e5b-be68-b157f190fd68','晉陵縣夏日作','李中','唐','唐诗','tang','','[]','事簡公庭靜，開簾暑氣中。',48,'全唐诗/poet.tang.41000.json','["事簡公庭靜，開簾暑氣中。", "依經煎綠茗，入竹就清風。", "至論招禪客，忘機憶釣翁。", "晚涼安枕簟，海月出牆東。"]'),
('e5d81037-1689-4f3a-bbc9-5e8c7b36a9bd','郵亭早起','李中','唐','唐诗','tang','','[]','郵舍殘燈在，村林雞唱頻。',48,'全唐诗/poet.tang.41000.json','["郵舍殘燈在，村林雞唱頻。", "星河吟裏曉，川陸望中春。", "舊友青雲貴，殊鄉素髮新。", "悠悠念行計，難更駐征輪。"]'),
('dd98b72c-7c12-4ae1-8251-29833c96c97c','客中寒食','李中','唐','唐诗','tang','','[]','旅次經寒食，思鄉淚濕巾。',48,'全唐诗/poet.tang.41000.json','["旅次經寒食，思鄉淚濕巾。", "音書天外斷，桃李雨中春。", "欲飲都無緒，唯吟似有因。", "輸他郊郭外，多少踏青人。"]'),
('cfd5f366-8b04-4e93-a058-99ccaee4293b','旅館秋夕','李中','唐','唐诗','tang','','[]','寥寥山館裏，獨坐酒初醒。',48,'全唐诗/poet.tang.41000.json','["寥寥山館裏，獨坐酒初醒。", "舊業多年別，秋霖一夜聽。", "砌蛬聲漸息，窗燭影猶停。", "早晚無他事，休如泛水萍。"]'),
('c7f6c0ef-c65e-4dbc-a743-9dcbf65daafb','宿青溪米處士幽居','李中','唐','唐诗','tang','','[]','寄宿溪光裏，夜涼高士家。',48,'全唐诗/poet.tang.41000.json','["寄宿溪光裏，夜涼高士家。", "養風窗外竹，叫月水中蛙。", "靜慮同搜句，清神旋煮茶。", "唯憂曉雞唱，塵裏事如麻。"]'),
('9f576c02-c16d-4761-92fc-0603c815939c','維舟秋浦逢故人張矩同泊','李中','唐','唐诗','tang','','[]','卸帆清夜碧江濱，冉冉涼風動白蘋。',64,'全唐诗/poet.tang.41000.json','["卸帆清夜碧江濱，冉冉涼風動白蘋。", "波上正吟新霽月，岸頭恰見故鄉人。", "共驚別後霜侵鬢，互說年來疾逼身。", "且飲一壺銷百恨，會須遭遇識通津。"]'),
('4006c711-2ee0-4a58-bc7d-55c85188c9cd','代別','李中','唐','唐诗','tang','','[]','明日鳴鞭天一涯，悠悠此夕怯分離。',64,'全唐诗/poet.tang.41000.json','["明日鳴鞭天一涯，悠悠此夕怯分離。", "紅樓有恨金波轉，翠黛無言玉筯垂。", "浮蟻不能迷遠意，迴紋從此寄相思。", "花時定是慵開鑑，獨向春風忍掃眉。"]'),
('c6bd0627-682a-4f53-957a-35930625c1df','悼懷王喪妃','李中','唐','唐诗','tang','','[]','花綻花開事可驚，暫來浮世返蓬瀛。',64,'全唐诗/poet.tang.41000.json','["花綻花開事可驚，暫來浮世返蓬瀛。", "楚宮夢斷雲空在，洛浦神歸月自明。", "香解返魂成浪語，膠能續斷是虛名。", "音容寂寞春牢落，誰會樓中獨立情。"]'),
('c431cfd9-679d-4ab7-b8e2-716e4b50dbf7','酒醒','李中','唐','唐诗','tang','','[]','睡覺花陰芳草軟，不知明月出牆東。',32,'全唐诗/poet.tang.41000.json','["睡覺花陰芳草軟，不知明月出牆東。", "杯盤狼藉人何處，聚散空驚似夢中。"]'),
('4e02db1c-907d-4fc9-b9e7-89c49e71373b','送虞道士','李中','唐','唐诗','tang','','[]','煙霞聚散通三島，星斗分明在一壺。',32,'全唐诗/poet.tang.41000.json','["煙霞聚散通三島，星斗分明在一壺。", "笑說餘杭沽酒去，蔡家重要會麻姑。"]'),
('462425f0-cf8d-44fc-a925-bf83135ffefd','懷舊夜吟寄趙杞','李中','唐','唐诗','tang','','[]','長笛聲中海月飛，桃花零落滿庭墀。',64,'全唐诗/poet.tang.41000.json','["長笛聲中海月飛，桃花零落滿庭墀。", "魂銷事去無尋處，酒醒孤吟不寐時。", "萱草豈能忘積恨，尺書誰與達相思。", "悠悠方寸何因解，明日江樓望渺瀰。"]'),
('f1a79355-e122-455e-a869-208928acc02a','宿臨江驛','李中','唐','唐诗','tang','','[]','候館寥寥輟櫂過，酒醒無奈旅愁何。',64,'全唐诗/poet.tang.41000.json','["候館寥寥輟櫂過，酒醒無奈旅愁何。", "雨昏郊郭行人少，葦暗汀洲宿鴈多。", "干祿已悲凋髮鬢，結茅終愧負煙蘿。", "篇章早晚逢知己，苦志忘形自有魔。"]'),
('5c46b37b-50fe-4238-a789-25ac7dbb0291','途中柳','李中','唐','唐诗','tang','','[]','翠色晴來近，長亭路去遙。',24,'全唐诗/poet.tang.41000.json','["翠色晴來近，長亭路去遙。", "無人折煙縷，落日拂溪橋。"]'),
('7a748592-3985-4bd9-a645-e440a0985abb','隔牆花','李中','唐','唐诗','tang','','[]','顏色尤難近，馨香不易通。',24,'全唐诗/poet.tang.41000.json','["顏色尤難近，馨香不易通。", "朱門金鎖隔，空使怨春風。"]'),
('d31a7e7c-1104-4d54-b12b-5125642634ee','廣陵寒食夜','李中','唐','唐诗','tang','','[]','廣陵寒食夜，豪貴足佳期。',48,'全唐诗/poet.tang.41000.json','["廣陵寒食夜，豪貴足佳期。", "紫陌人歸後，紅樓月上時。", "綺羅香未歇，絲竹韻猶遲。", "明日踏青興，輸他輕薄兒。"]'),
('27c442ed-0942-4412-8d46-561a2eee36ac','寄廬山莊隱土','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','煙蘿擁竹關，物外自求安。',48,'全唐诗/poet.tang.41000.json','["煙蘿擁竹關，物外自求安。", "逼枕溪聲近，當簷岳色寒。", "藥苗應自採，琴調對誰彈。", "待了浮名後，依君共挂冠。"]'),
('e4396bae-7fca-4982-beae-2af77afa7438','吉水寄閻侍御','李中','唐','唐诗','tang','','[]','何處懷君切，令人欲白頭。',48,'全唐诗/poet.tang.41000.json','["何處懷君切，令人欲白頭。", "偶尋花外寺，獨立水邊樓。", "不得論休戚，何因校獻酬。", "吟餘興難盡，風笛起漁舟。"]'),
('ab8452c8-aa98-43a0-b09c-00ecaacf731c','送張惟貞少府之江陰','李中','唐','唐诗','tang','','[]','相送煙汀畔，酒闌登小舟。',48,'全唐诗/poet.tang.41000.json','["相送煙汀畔，酒闌登小舟。", "離京梅雨歇，到邑早蟬秋。", "俗必期康濟，詩誰互唱酬。", "晚涼諸吏散，海月入虛樓。"]'),
('0712c64a-119f-4cf0-98e8-a04c876d25fc','鍾陵禁煙寄從弟','李中','唐','唐诗','tang','','["\u601d\u4e61"]','落絮飛花日又西，踏青無侶草萋萋。',32,'全唐诗/poet.tang.41000.json','["落絮飛花日又西，踏青無侶草萋萋。", "交親書斷竟不到，忍聽黃昏杜宇啼。"]'),
('4be82751-04ae-47a6-ad2e-681527e95698','夜泊江渚','李中','唐','唐诗','tang','','[]','水鄉明月上晴空，汀島香生杜若風。',32,'全唐诗/poet.tang.41000.json','["水鄉明月上晴空，汀島香生杜若風。", "不是當年獨醒客，且沽村酒待漁翁。"]'),
('408d49a7-8fe3-4e47-a699-668cee967bfb','吉水縣依韻酬華松秀才見寄','李中','唐','唐诗','tang','','[]','官況蕭條在水村，吏歸無事好論文。',64,'全唐诗/poet.tang.41000.json','["官況蕭條在水村，吏歸無事好論文。", "枕欹獨聽殘春雨，夢去空尋五老雲。", "竹徑每憐和蘚步，禽聲偏愛隔花聞。", "詩情冷淡知音少，獨喜江臯得見君。"]'),
('716410db-748c-4c72-9447-fe43643c4e8b','貽廬山清溪觀王尊師','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','霞帔星冠復杖藜，積年修鍊住靈溪。',64,'全唐诗/poet.tang.41000.json','["霞帔星冠復杖藜，積年修鍊住靈溪。", "松軒睡覺冷雲起，石磴坐來春日西。", "採藥每尋巖徑遠，彈琴常到月輪低。", "鼎中龍虎功成後，海上三山去不迷。"]'),
('01e6936a-2e87-42c8-b1a6-6a0b23043aca','王昭君','李中','唐','唐诗','tang','','[]','蛾眉翻自累，萬里陷窮邊。',48,'全唐诗/poet.tang.41000.json','["蛾眉翻自累，萬里陷窮邊。", "滴淚胡風起，寬心漢月圓。", "飛塵長翳日，白草自連天。", "誰貢和親策，千秋汚簡編。"]'),
('e99c3e40-3337-402c-9095-e650d4dd6b18','送姚端先輩歸寧','李中','唐','唐诗','tang','','[]','知君歸覲省，稱意涉通津。',48,'全唐诗/poet.tang.41000.json','["知君歸覲省，稱意涉通津。", "解纜汀洲曉，張帆煙水春。", "牽吟芳草遠，貰酒亂花新。", "拜慶庭闈處，蟾枝香滿身。"]'),
('40e5ad70-4a40-4ceb-9f9c-9c996ed35f8b','江村晚秋作','李中','唐','唐诗','tang','','[]','高秋水村路，隔岸見人家。',48,'全唐诗/poet.tang.41000.json','["高秋水村路，隔岸見人家。", "好是經霜葉，紅於帶露花。", "臨罾魚易得，就店酒難賒。", "吟興胡能盡，風清日又斜。"]'),
('673ef2d4-f502-40b9-a97d-1676d8211504','蛩','李中','唐','唐诗','tang','','[]','月冷莎庭夜已深，百蟲聲外有清音。',32,'全唐诗/poet.tang.41000.json','["月冷莎庭夜已深，百蟲聲外有清音。", "詩情正苦無眠處，愧爾堦前相伴吟。"]'),
('4bd5130a-0f47-49ea-8efa-2f78aa9e5d05','感秋書事','李中','唐','唐诗','tang','','[]','宦途憔悴雪生頭，家計相牽未得休。',32,'全唐诗/poet.tang.42000.json','["宦途憔悴雪生頭，家計相牽未得休。", "紅寥白蘋消息斷，舊溪煙月負漁舟。"]'),
('1abf9344-171b-465c-b44c-aff4b97f8f5c','訪廬山歸章禪伯','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','沈沈石室疎鐘後，寂寂莎池片月明。',32,'全唐诗/poet.tang.42000.json','["沈沈石室疎鐘後，寂寂莎池片月明。", "多少學徒求妙法，要於言下悟無生。"]'),
('60b298cc-aae8-4b30-8db7-ede9af387035','廬山棲隱洞譚先生院留題','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','壇畔歸雲冷濕襟，拂苔移石坐花陰。',32,'全唐诗/poet.tang.42000.json','["壇畔歸雲冷濕襟，拂苔移石坐花陰。", "偶然醒得莊周夢，始覺玄門興味深。"]'),
('0e7f30a2-5ff5-4faa-b7fe-fe218e9bdd12','江行值暴風雨','李中','唐','唐诗','tang','','[]','風狂雨暗舟人懼，自委神明志不邪。',32,'全唐诗/poet.tang.42000.json','["風狂雨暗舟人懼，自委神明志不邪。", "投得葦灣波浪息，岸頭煙火近人家。"]'),
('4d793181-0d9a-4e40-8d5e-90e8e889988a','杪秋夕吟懷寄宋維先輩','李中','唐','唐诗','tang','','[]','江島窮秋木葉稀，月高何處搗寒衣。',32,'全唐诗/poet.tang.42000.json','["江島窮秋木葉稀，月高何處搗寒衣。", "苦嗟不見登龍客，此夜悠悠一夢飛。"]'),
('ca87a1e1-7656-4ebf-84f5-aa614ce60efc','七夕','李中','唐','唐诗','tang','','[]','星河耿耿正新秋，絲竹千家列綵樓。',32,'全唐诗/poet.tang.42000.json','["星河耿耿正新秋，絲竹千家列綵樓。", "可惜穿針方有興，纖纖初月苦難留。"]'),
('45debebc-c4da-41b2-80c5-21de62edfda9','吉水作尉時酬閻侍御見寄','李中','唐','唐诗','tang','','[]','謬佐驅雞任，常思賦鵩人。',48,'全唐诗/poet.tang.42000.json','["謬佐驅雞任，常思賦鵩人。", "未諧林下約，空感病來身。", "鏁徑青苔老，鋪階紅葉新。", "相思不可見，猶喜得書頻。"]'),
('88111b0a-ef31-44e1-8a63-45806c105500','清溪逢張惟貞秀才','李中','唐','唐诗','tang','','[]','洞隱紅霞外，房開碧嶂根。',48,'全唐诗/poet.tang.42000.json','["洞隱紅霞外，房開碧嶂根。", "昔年同鍊句，幾夜共聽猨。", "考古書千卷，忘憂酒一樽。", "如今歸建業，雅道喜重論。"]'),
('3d13660f-e06a-4084-98ab-45415c9269b4','送閻侍御歸闕','李中','唐','唐诗','tang','','[]','羨君乘紫詔，歸路指通津。',48,'全唐诗/poet.tang.42000.json','["羨君乘紫詔，歸路指通津。", "鼓櫂煙波暖，還京雨露新。", "趨朝丹禁曉，聳轡九衢春。", "自愧湮沈者，隨軒未有因。"]'),
('9314f4a8-71db-49fe-9a84-20ae8287fbd5','甲子歲罷吉水縣過鍾陵時暮春維舟江渚謁柴太尉席上作','李中','唐','唐诗','tang','','[]','公侯延駐暫踟躕，況值風光三月初。',64,'全唐诗/poet.tang.42000.json','["公侯延駐暫踟躕，況值風光三月初。", "亂落杯盤花片小，靜籠池閣柳陰疎。", "舟維南浦程雖阻，飲預西園興有餘。", "却笑田家門下客，當時容易歎車魚。"]'),
('727b1536-893f-440f-ab98-f809fb1a177e','海上春夕旅懷寄左偃','李中','唐','唐诗','tang','','[]','柳過清明絮亂飛，感時懷舊思悽悽。',64,'全唐诗/poet.tang.42000.json','["柳過清明絮亂飛，感時懷舊思悽悽。", "月生樓閣雲初散，家在汀洲夢去迷。", "髮白每慙清鑑啓，酒醒長怯子規啼。", "北山高臥風騷客，安得同吟復杖藜。"]'),
('5db77384-9b45-4120-82da-ac1179d31444','江次維舟登古寺','李中','唐','唐诗','tang','','[]','輟櫂因過古梵宮，荒涼門徑鏁苔茸。',64,'全唐诗/poet.tang.42000.json','["輟櫂因過古梵宮，荒涼門徑鏁苔茸。", "綠陰滿地前朝樹，清韻含風後殿鐘。", "童子縱慵眠壞榻，老僧耽話指諸峰。", "吟餘却返來時路，迴首盤桓尚駐筇。"]'),
('853a3691-e5b2-4307-aa40-5047768a68c0','春日招宋維先輩','李中','唐','唐诗','tang','','[]','甕中竹葉今朝熟，鑑裏桃花昨日開。',32,'全唐诗/poet.tang.42000.json','["甕中竹葉今朝熟，鑑裏桃花昨日開。", "爲報廣寒攀桂客，莫辭相訪共銜杯。"]'),
('2c6068d4-682e-466c-9204-63b3e8347af7','吹笛兒','李中','唐','唐诗','tang','','[]','隴頭休聽月明中，妙竹嘉音際會逢。',32,'全唐诗/poet.tang.42000.json','["隴頭休聽月明中，妙竹嘉音際會逢。", "見爾樽前吹一首，令人重憶許雲封。"]'),
('2b2b74d8-6197-4b41-954c-fc158f20b7da','所思','李中','唐','唐诗','tang','','[]','解珮當時在洛濱，悠悠疑是夢中身。',32,'全唐诗/poet.tang.42000.json','["解珮當時在洛濱，悠悠疑是夢中身。", "自從物外無消息，花謝鶯啼近十春。"]'),
('db8c0b69-51a6-490a-a192-71ff8e5f1fe1','吉水縣酬夏侯秀才見寄','李中','唐','唐诗','tang','','[]','啓鑑悠悠兩鬢蒼，病來心緒易淒涼。',32,'全唐诗/poet.tang.42000.json','["啓鑑悠悠兩鬢蒼，病來心緒易淒涼。", "知音不到吟還懶，鏁印開簾又夕陽。"]'),
('33d9e05f-2807-44d0-b346-c2a87e50f2e9','和友人喜雪','李中','唐','唐诗','tang','','[]','臘雪頻頻降，成堆不可除。',72,'全唐诗/poet.tang.42000.json','["臘雪頻頻降，成堆不可除。", "伴吟花莫並，銷瘴藥何如。", "謝女詩成處，袁安睡起初。", "深迷樵子徑，冷逼旅人居。", "惹砌催罇俎，飄窗入簿書。", "最宜樓上望，散亂滿空虛。"]'),
('f46b503d-d2b0-4e14-aa02-32ca0932294e','感事呈所知','李中','唐','唐诗','tang','','[]','競愛松筠翠，皆憐桃李芳。',24,'全唐诗/poet.tang.42000.json','["競愛松筠翠，皆憐桃李芳。", "如求濟世廣，桑柘願商量。"]'),
('31596998-4055-45fa-ab31-b5f4af167be1','送汪濤','李中','唐','唐诗','tang','','[]','知君別家後，不免淚霑襟。',48,'全唐诗/poet.tang.42000.json','["知君別家後，不免淚霑襟。", "芳草千里路，夕陽孤客心。", "花飛當野渡，猨叫在煙岑。", "霄漢知音在，何須恨陸沈。"]'),
('df99118c-649d-4a44-b9a6-2b1176f017c4','言志寄劉鈞秀才','李中','唐','唐诗','tang','','[]','童稚親儒墨，時平喜道存。',48,'全唐诗/poet.tang.42000.json','["童稚親儒墨，時平喜道存。", "酬身指書劒，賦命委乾坤。", "秋爽鼓琴興，月清搜句魂。", "與君同此志，終待至公論。"]'),
('54620419-d9b8-4b6f-86bc-52cf647dbfa5','訪澄上人','李中','唐','唐诗','tang','','[]','尋師來靜境，神骨覺清涼。',48,'全唐诗/poet.tang.42000.json','["尋師來靜境，神骨覺清涼。", "一餉逢秋雨，相留坐竹堂。", "石渠堆敗葉，莎砌咽寒螿。", "話到南能旨，怡然萬慮忘。"]'),
('7a476cc7-abe5-44aa-9ce0-c476bd16ea9e','經古寺','李中','唐','唐诗','tang','','[]','殿宇半隳摧，門臨野水開。',48,'全唐诗/poet.tang.42000.json','["殿宇半隳摧，門臨野水開。", "雲凝何代樹，草蔽此時臺。", "遶塔堆黃葉，沿階積綠苔。", "踟躕日將暮，棲鳥入巢來。"]'),
('2f28508b-402c-4d34-9a60-afa88d1d0448','送王道士遊東海','李中','唐','唐诗','tang','','[]','巨浸常牽夢，雲遊豈覺勞。',48,'全唐诗/poet.tang.42000.json','["巨浸常牽夢，雲遊豈覺勞。", "遙空收晚雨，虛閣看秋濤。", "必若思三島，應須釣六鼇。", "如通十洲去，誰信碧天高。"]'),
('18849016-0cea-4634-95e2-b1f193bed42b','貽青陽宰','李中','唐','唐诗','tang','','[]','徵賦常登限，名山管最多。',24,'全唐诗/poet.tang.42000.json','["徵賦常登限，名山管最多。", "吏閑民訟少，時得訪煙蘿。"]'),
('6fda2cb8-360e-47cd-ba79-3ed0ed55596f','哭故主人陳太師','李中','唐','唐诗','tang','','[]','十年孤跡寄侯門，入室升堂忝厚恩。',64,'全唐诗/poet.tang.42000.json','["十年孤跡寄侯門，入室升堂忝厚恩。", "遊遍春郊隨茜斾，飲殘秋月待金尊。", "車魚鄭重知難報，吐握周旋不可論。", "長慟裴回逝川上，白楊蕭颯又黃昏。"]'),
('78ee78bf-2f15-41d6-8bf2-730f090339c8','秋江夜泊寄劉鈞','李中','唐','唐诗','tang','','[]','萬里江山歛暮煙，旅情當此獨悠然。',64,'全唐诗/poet.tang.42000.json','["萬里江山歛暮煙，旅情當此獨悠然。", "沙汀月冷帆初卸，葦岸風多人未眠。", "已聽漁翁歌別浦，更堪邊鴈過遙天。", "與君共俟酬身了，結侶波中寄釣船。"]'),
('7d490812-fde6-4481-9faf-e128f7a89ac1','和潯陽宰感舊絕句五首 一','李中','唐','唐诗','tang','','[]','追感古今情不已，竹軒閑取史書看。',32,'全唐诗/poet.tang.42000.json','["追感古今情不已，竹軒閑取史書看。", "欲親往哲無因見，空樹臨風襟袖寒。"]'),
('fe3e8add-4dd6-45c6-bd61-cc32d28ba1ce','和潯陽宰感舊絕句五首 二','李中','唐','唐诗','tang','','[]','潯陽物景真難及，練瀉澄江最好看。',32,'全唐诗/poet.tang.42000.json','["潯陽物景真難及，練瀉澄江最好看。", "曾上虛樓吟倚檻，五峰擎雪照人寒。"]'),
('1b3755eb-acb6-4328-b154-29bff7623a82','和潯陽宰感舊絕句五首 三','李中','唐','唐诗','tang','','[]','園林春媚千花發，爛熳如將畫障看。',32,'全唐诗/poet.tang.42000.json','["園林春媚千花發，爛熳如將畫障看。", "惟愛松筠多冷淡，青青偏稱雪霜寒。"]'),
('fd0ad010-904e-4050-b908-f5c6a499c513','和潯陽宰感舊絕句五首 四','李中','唐','唐诗','tang','','[]','知君百里鳴琴處，公退千山盡日看。',32,'全唐诗/poet.tang.42000.json','["知君百里鳴琴處，公退千山盡日看。", "政化有同風偃草，更將餘力拯孤寒。"]'),
('95ea4bb9-b646-4bbf-b157-2ce6262ec7ac','和潯陽宰感舊絕句五首 五','李中','唐','唐诗','tang','','[]','昔歲尋芳忻得侶，江堤物景盡情看。',32,'全唐诗/poet.tang.42000.json','["昔歲尋芳忻得侶，江堤物景盡情看。", "就中吟戀垂楊下，撼起啼鶯晚吹寒。"]'),
('4469108d-a7d4-4ae7-8ccb-aba3eebc99d8','哭柴郎中','李中','唐','唐诗','tang','','[]','昔歲遭逢在海城，曾容孤跡奉雙旌。',64,'全唐诗/poet.tang.42000.json','["昔歲遭逢在海城，曾容孤跡奉雙旌。", "酒邊不厭笙歌盛，花下只愁風雨生。", "棊接山亭松影晚，吟陪月檻露華清。", "音塵自此無因問，淚灑川波夕照明。"]'),
('d710214a-7722-4f6e-9fd2-b235e39165ab','訪章禪老','李中','唐','唐诗','tang','','[]','比尋禪客叩禪機，澄却心如月在池。',32,'全唐诗/poet.tang.42000.json','["比尋禪客叩禪機，澄却心如月在池。", "松下偶然醒一夢，却成無語問吾師。"]'),
('722ab4ce-3e4d-4f7e-bb43-2503529b8b71','泊秋浦','李中','唐','唐诗','tang','','[]','葦岸風高宿鴈驚，維舟特地起鄉情。',32,'全唐诗/poet.tang.42000.json','["葦岸風高宿鴈驚，維舟特地起鄉情。", "漁兒隔水吹橫笛，半夜空江月正明。"]'),
('2d3747b5-519a-4469-9a3a-40c28a9a8a78','閑居言懷','李中','唐','唐诗','tang','','[]','未達難隨衆，從他俗所憎。',48,'全唐诗/poet.tang.42000.json','["未達難隨衆，從他俗所憎。", "閑聽九秋雨，遠憶四明僧。", "病後倦吟嘯，貧來疎友朋。", "寂寥元合道，未必是無能。"]'),
('c8d47cae-9fb0-4f62-ab5e-28cb8247bd9c','舟次彭澤','李中','唐','唐诗','tang','','[]','飄泛經彭澤，扁舟思莫窮。',48,'全唐诗/poet.tang.42000.json','["飄泛經彭澤，扁舟思莫窮。", "無人秋浪晚，一岸蓼花風。", "鄉里夢漸遠，交親書未通。", "今宵見圓月，難坐冷光中。"]'),
('7928bb90-3612-46fc-aca9-b13dd08c1fb7','宿鍾山知覺院','李中','唐','唐诗','tang','','[]','宿投林下寺，中夜覺神清。',48,'全唐诗/poet.tang.42000.json','["宿投林下寺，中夜覺神清。", "磬罷僧初定，山空月又生。", "籠燈吐冷豔，嵒樹起寒聲。", "待曉紅塵裏，依前冒遠程。"]'),
('03e2546a-7b4c-4198-89aa-5918711a4670','遊茅山二首 一','李中','唐','唐诗','tang','','[]','綠蘚深迎步，紅霞爛滿衣。',24,'全唐诗/poet.tang.42000.json','["綠蘚深迎步，紅霞爛滿衣。", "洞天應不遠，鸞鶴向人飛。"]'),
('aa4b18fe-a8c4-4ccc-860f-46be39e45051','遊茅山二首 二','李中','唐','唐诗','tang','','[]','茅許仙蹤在，煙霞一境清。',24,'全唐诗/poet.tang.42000.json','["茅許仙蹤在，煙霞一境清。", "夷希何許叩，松徑月空明。"]'),
('4b5dfb4c-405b-4d50-992b-5f1d39a0875b','鶴','李中','唐','唐诗','tang','','[]','九臯羽翼下晴空，萬里心難駐玉籠。',64,'全唐诗/poet.tang.42000.json','["九臯羽翼下晴空，萬里心難駐玉籠。", "清露滴時翹蘚徑，白雲開處唳松風。", "歸當華表千年後，怨在瑤琴別操中。", "好共靈龜作儔侶，十洲三島逐仙翁。"]'),
('57f4c031-f473-443b-8045-f2072337fa5a','暮春吟懷寄姚端先輩','李中','唐','唐诗','tang','','[]','無奈詩魔旦夕生，更堪芳草滿長汀。',64,'全唐诗/poet.tang.42000.json','["無奈詩魔旦夕生，更堪芳草滿長汀。", "故人還爽花前約，新月又生江上亭。", "莊夢斷時燈欲燼，蜀魂啼處酒初醒。", "何時得見登龍客，隔却千山萬仞青。"]'),
('e2311b5d-9693-4efd-a83e-3f65bd33f57c','送圓上人歸廬山','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','蓮宮舊隱塵埃外，策杖臨風拂袖還。',64,'全唐诗/poet.tang.42000.json','["蓮宮舊隱塵埃外，策杖臨風拂袖還。", "踏雪獨尋青嶂下，聽猨重入白雲間。", "蕭騷紅樹當門老，斑駮蒼苔鏁徑閑。", "預想松軒夜禪處，虎溪圓月照空山。"]'),
('3ac75fe4-a9c1-4597-84f1-d8213ace27c6','送相里秀才之匡山國子監','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','氣秀情閑杳莫羣，廬山遊去志求文。',64,'全唐诗/poet.tang.42000.json','["氣秀情閑杳莫羣，廬山遊去志求文。", "已能探虎窮騷雅，又欲囊螢就典墳。", "目豁乍窺千里浪，夢寒初宿五峰雲。", "業成早赴春闈約，要使嘉名海內聞。"]'),
('f8f2f950-17f5-47e3-8606-25731ff5ad44','漁父二首 一','李中','唐','唐诗','tang','','[]','偶向蘆花深處行，溪光山色晚來晴。',32,'全唐诗/poet.tang.42000.json','["偶向蘆花深處行，溪光山色晚來晴。", "漁家開戶相迎接，稚子爭窺犬吠聲。"]'),
('4d4adc40-5075-4ca3-99ec-a9652c1ce9a9','漁父二首 二','李中','唐','唐诗','tang','','[]','雪鬢衰髯白布袍，笑攜頳鯉換村醪。',32,'全唐诗/poet.tang.42000.json','["雪鬢衰髯白布袍，笑攜頳鯉換村醪。", "慇懃留我宿溪上，釣艇歸來明月高。"]'),
('ac0cdaa2-80ba-4d84-8e20-4bb152c02d45','旅次聞砧','李中','唐','唐诗','tang','','[]','砧杵誰家夜搗衣，金風淅淅露微微。',32,'全唐诗/poet.tang.42000.json','["砧杵誰家夜搗衣，金風淅淅露微微。", "月中獨坐不成寐，舊業經年未得歸。"]'),
('4c76d09f-9a06-4a16-b8bb-47bdc4fc24a9','寄楊先生','李中','唐','唐诗','tang','','[]','仙翁別後無信，應共煙霞卜隣。',56,'全唐诗/poet.tang.42000.json','["仙翁別後無信，應共煙霞卜隣。", "莫把壺中祕訣，輕傳塵裏遊人。", "浮生日月自急，上境鶯花正春。", "安得一招琴酒，與君共泛天津。"]'),
('e170b995-4daa-4a6b-bbfa-7591ec542d5e','對酒招陳昭用','李中','唐','唐诗','tang','','[]','花開葉落堪悲，似水年光暗移。',56,'全唐诗/poet.tang.42000.json','["花開葉落堪悲，似水年光暗移。", "身世都如夢役，是非空使神疲。", "良圖有分終在，所欲無勞妄思。", "幸有一壺清酒，且來閑語希夷。"]'),
('d79bfaa4-ee69-4048-b49d-87678256b335','旅夜聞笛','李中','唐','唐诗','tang','','[]','長笛起誰家，秋涼夜漏賒。',48,'全唐诗/poet.tang.42000.json','["長笛起誰家，秋涼夜漏賒。", "一聲來枕上，孤客在天涯。", "木末風微動，窗前月漸斜。", "暗牽詩思苦，不獨落梅花。"]'),
('c8b96cec-a734-461a-8892-c36de2ed30fb','送紹明上人之毘陵','李中','唐','唐诗','tang','','[]','忽起毘陵念，飄然不可留。',48,'全唐诗/poet.tang.42000.json','["忽起毘陵念，飄然不可留。", "聽蟬離古寺，攜錫上扁舟。", "月出沙汀冷，風高葦岸秋。", "回期端的否，千里路悠悠。"]'),
('69890563-827a-4195-af62-37112cc6e1fc','再到山陽尋故人不遇二首 一','李中','唐','唐诗','tang','','[]','維舟登野岸，因訪故人居。',24,'全唐诗/poet.tang.42000.json','["維舟登野岸，因訪故人居。", "亂後知何處，荆榛匝弊廬。"]'),
('f5f56f0a-0020-447c-b3d8-c948215ad02c','再到山陽尋故人不遇二首 二','李中','唐','唐诗','tang','','[]','欲問當年事，耕人都不知。',24,'全唐诗/poet.tang.42000.json','["欲問當年事，耕人都不知。", "空餘堤上柳，依舊自垂絲。"]'),
('ff573e8f-c78d-46de-b966-cde05949c91e','寄廬山簡寂觀重道者','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','憶昔採芝廬岳頂，清宮常接絳霄人。',64,'全唐诗/poet.tang.42000.json','["憶昔採芝廬岳頂，清宮常接絳霄人。", "玉書閑展石樓曉，瑤瑟醉彈琪樹春。", "惟恨仙桃遲結實，不憂滄海易成塵。", "似醒一夢歸凡世，空向彤霞寄夢頻。"]'),
('5b508fd6-df55-44c1-b913-fa556273b2b4','思湓渚舊居','李中','唐','唐诗','tang','','[]','昔歲曾居湓水頭，草堂吟嘯興何幽。',64,'全唐诗/poet.tang.42000.json','["昔歲曾居湓水頭，草堂吟嘯興何幽。", "迎僧常踏竹間蘚，愛月獨登溪上樓。", "寒翠入簷嵐岫曉，冷聲縈枕野泉秋。", "從拘宦路無由到，昨夜分明夢去遊。"]'),
('d13625c5-0a52-4e07-85d3-ea6941a4fef2','思朐陽春遊感舊寄柴司徒五首 一','李中','唐','唐诗','tang','','[]','王孫昔日甚相親，共賞西園正媚春。',32,'全唐诗/poet.tang.42000.json','["王孫昔日甚相親，共賞西園正媚春。", "醉臥如茵芳草上，覺來花月影籠身。"]'),
('0bf88eb6-51a5-4d5b-9bdb-33968ea9e0d2','思朐陽春遊感舊寄柴司徒五首 二','李中','唐','唐诗','tang','','[]','煙鋪芳草正綿綿，藉草傳杯似列仙。',32,'全唐诗/poet.tang.42000.json','["煙鋪芳草正綿綿，藉草傳杯似列仙。", "暫輟笙歌且聯句，含毫花下破香牋。"]'),
('f31be9f0-026c-4786-93ce-787b214f240b','思朐陽春遊感舊寄柴司徒五首 三','李中','唐','唐诗','tang','','[]','南陌風和舞蝶狂，惜春公子戀斜陽。',32,'全唐诗/poet.tang.42000.json','["南陌風和舞蝶狂，惜春公子戀斜陽。", "高歌飲罷將迴轡，衣上花兼百草香。"]'),
('23131d8f-266b-46b0-807f-ecdc1e11ecec','思朐陽春遊感舊寄柴司徒五首 四','李中','唐','唐诗','tang','','[]','春郊飲散暮煙收，却引絲簧上翠樓。',32,'全唐诗/poet.tang.42000.json','["春郊飲散暮煙收，却引絲簧上翠樓。", "紅袖歌長金斝亂，銀蟾飛出海東頭。"]'),
('1edd9186-6010-47e2-a17d-cfeacd8c0e2d','思朐陽春遊感舊寄柴司徒五首 五','李中','唐','唐诗','tang','','[]','昔年常接五陵狂，洪飲花間數十場。',32,'全唐诗/poet.tang.42000.json','["昔年常接五陵狂，洪飲花間數十場。", "別後或驚如夢覺，音塵難問水茫茫。"]'),
('36a1d100-fa9e-42e1-b803-eabbdb39e865','泉','李中','唐','唐诗','tang','','[]','潺潺青嶂底，來處一何長。',48,'全唐诗/poet.tang.42000.json','["潺潺青嶂底，來處一何長。", "漱石苔痕滑，侵松鶴夢涼。", "泛花穿竹塢，瀉月下蓮塘。", "想得歸何處，天涯助渺茫。"]'),
('4d4f3f56-0ecf-44c1-90a2-5b10653eaa0f','題徐五教池亭','李中','唐','唐诗','tang','','[]','多士池塘好，塵中景恐無。',122,'全唐诗/poet.tang.42000.json','["多士池塘好，塵中景恐無。", "年來養鷗鷺，夢不去江湖。", "泉脈通深澗，風聲起短蘆。", "驚魚跳藻荇，戲蝶上菰蒲。", "泛泛容漁艇，閑閑載酒壺。", "漲痕山雨過，翠積岸苔鋪。", "花影沈波底，煙光入座隅。", "曉香憐杜若，夜浸愛[蟾]蜍。", "步逸心難厭，看吟興不辜。", "憑君命奇筆，爲我寫成圖。"]'),
('f3dabb46-25b6-4fc8-b85d-a9bc688dd4bb','遙賦義興潛泉','李中','唐','唐诗','tang','','[]','見說靈泉好，潺湲興莫窮。',48,'全唐诗/poet.tang.42000.json','["見說靈泉好，潺湲興莫窮。", "誰當秋霽後，獨聽月明中。", "濺石苔花潤，隨流木葉紅。", "何當化霖雨，濟物顯殊功。"]'),
('0aec44a0-f998-4f66-a393-dfbb48ed866c','和毘陵尉曹昭用見寄','李中','唐','唐诗','tang','','[]','決獄多餘暇，冥搜萬家空。',48,'全唐诗/poet.tang.42000.json','["決獄多餘暇，冥搜萬家空。", "卷簾疎雨後，鏁印夕陽中。", "還往多名士，編題尚古風。", "宦途知此味，能有幾人同。"]'),
('50a7c838-57fd-48ae-b898-e77c81bd74ac','梅花','李中','唐','唐诗','tang','','[]','羣木方憎雪，開花長在先。',24,'全唐诗/poet.tang.42000.json','["羣木方憎雪，開花長在先。", "流鶯與舞蝶，不見許因緣。"]'),
('0cbadf48-ccd6-4a78-a930-689af07509c6','舟次吉水逢蔡文慶秀才','李中','唐','唐诗','tang','','[]','別後音塵斷，相逢又共吟。',48,'全唐诗/poet.tang.42000.json','["別後音塵斷，相逢又共吟。", "雪霜今日鬢，煙月舊時心。", "艤櫂夕陽在，聽鴻秋色深。", "一尊開口笑，不必話升沈。"]'),
('7a2d1f99-7e58-424b-8aa5-9a3d734d595e','新喻縣偶寄彭仁正字','李中','唐','唐诗','tang','','[]','經年離象魏，孤宦在南荒。',48,'全唐诗/poet.tang.42000.json','["經年離象魏，孤宦在南荒。", "酒醒公齋冷，雨多歸夢長。", "志難酬國澤，術欠致民康。", "吾子應相笑，區區道未光。"]'),
('119a47d7-a249-404e-a9ec-774210b35e8e','和彭正字喜雪見寄','李中','唐','唐诗','tang','','[]','千門忻應瑞，偏稱上樓看。',48,'全唐诗/poet.tang.42000.json','["千門忻應瑞，偏稱上樓看。", "密灑虛窗曉，狂飄大野寒。", "園深宜竹樹，簾卷洽杯盤。", "已作豐年兆，黎民意盡安。"]'),
('2e8cb722-01dc-46fd-8325-eaf5e8d6c24d','海上和柴軍使清明書事','李中','唐','唐诗','tang','','[]','清明時節好煙光，英傑高吟興味長。',64,'全唐诗/poet.tang.42000.json','["清明時節好煙光，英傑高吟興味長。", "捧日即應還禁衛，當春何惜醉朐陽。", "千山過雨難藏翠，百卉臨風不藉香。", "却是旅人悽屑甚，夜來魂夢到家鄉。"]'),
('5e59ad78-3bb8-448e-8b17-350927114015','壬申歲承命之任淦陽再過廬山國學感舊寄劉鈞明府','李中','唐','唐诗','tang','','["\u5e90\u5c71"]','三十年前共苦辛，囊螢曾寄此煙岑。',64,'全唐诗/poet.tang.42000.json','["三十年前共苦辛，囊螢曾寄此煙岑。", "讀書燈暗嫌雲重，搜句石平憐蘚深。", "各歷宦途悲聚散，幾看時輩或浮沈。", "再來物景還依舊，風冷松高猨狖吟。"]'),
('246652fd-96b0-438b-8e1e-af4d3e24fdb4','留題胡參卿秀才幽居','李中','唐','唐诗','tang','','[]','竹蔭亭除蘚色濃，道心安逸寂寥中。',64,'全唐诗/poet.tang.42000.json','["竹蔭亭除蘚色濃，道心安逸寂寥中。", "扣門時有棲禪客，灑酒多招採藥翁。", "江近好聽菱芡雨，徑香偏愛蕙蘭風。", "我慙名宦猶拘束，脫屣心情未得同。"]'),
('d41ff93f-ae5f-4fe7-b099-b937ad850eb2','放鷺鷥','李中','唐','唐诗','tang','','[]','池塘多謝久淹留，長得霜翎放自由。',32,'全唐诗/poet.tang.42000.json','["池塘多謝久淹留，長得霜翎放自由。", "好去蒹葭深處宿，月明應認舊江秋。"]'),
('262acfe8-c0c8-49b4-bf63-6f9223c387d9','柳絮','李中','唐','唐诗','tang','','[]','年年二月暮，散亂雜飛花。',24,'全唐诗/poet.tang.42000.json','["年年二月暮，散亂雜飛花。", "雨過微風起，狂飄千萬家。"]'),
('d32694f9-eca2-4c35-a7fc-58ec5def8870','早春','李中','唐','唐诗','tang','','[]','一種和風至，千花未放妍。',24,'全唐诗/poet.tang.42000.json','["一種和風至，千花未放妍。", "草心並柳眼，長是被恩先。"]'),
('3ee9ba83-e38d-4778-92a2-d564a109cefe','春雲','李中','唐','唐诗','tang','','[]','陰去爲膏澤，晴來媚曉空。',24,'全唐诗/poet.tang.42000.json','["陰去爲膏澤，晴來媚曉空。", "無心亦無滯，舒卷在東風。"]'),
('90289808-3ac4-45cc-8b5b-7f4ec5adbfaf','送姚端秀才遊毘陵','李中','唐','唐诗','tang','','["\u592a\u6e56"]','毘陵嘉景太湖邊，才子經遊稱少年。',64,'全唐诗/poet.tang.42000.json','["毘陵嘉景太湖邊，才子經遊稱少年。", "風弄輕帘沽酒市，月明紅袖採蓮船。", "若耶罨畫應相似，越岫吳峰盡接連。", "此去高吟須早返，廣寒丹桂莫遷延。"]'),
('c18a3b52-78c8-4bfb-ae9d-f0179b5f7c29','和朐陽載筆魯裕見寄','李中','唐','唐诗','tang','','[]','燕臺多事每開顏，相許論交淡薄間。',64,'全唐诗/poet.tang.42000.json','["燕臺多事每開顏，相許論交淡薄間。", "飲興共憐芳草岸，吟情同愛夕陽山。", "露濃小徑蛩聲咽，月冷空庭竹影閑。", "何事此時攀憶甚，與君俱是別鄉關。"]'),
('f701b4c0-751d-432e-a716-d04b00b9d5d1','敘吟二首 一','李中','唐','唐诗','tang','','[]','往哲搜羅妙入神，隋珠和璧未爲珍。',32,'全唐诗/poet.tang.42000.json','["往哲搜羅妙入神，隋珠和璧未爲珍。", "而今所得慙難繼，謬向平生著苦辛。"]'),
('6d30cf87-ce23-4af4-8f75-beeb2e41eae0','敘吟二首 二','李中','唐','唐诗','tang','','[]','成僻成魔二雅中，每逢知己是亨通。',32,'全唐诗/poet.tang.42000.json','["成僻成魔二雅中，每逢知己是亨通。", "言之無罪終難厭，欲把風騷繼古風。"]'),
('0db1fb7c-b12a-4269-aec5-23a22b3b4519','貽毘陵正勤禪院奉長老','李中','唐','唐诗','tang','','[]','隨緣駐瓶錫，心已悟無生。',48,'全唐诗/poet.tang.42000.json','["隨緣駐瓶錫，心已悟無生。", "默坐煙霞散，閑觀水月明。", "竹深風倍冷，堂迥磬偏清。", "願作傳燈者，忘言學淨名。"]'),
('423942ed-0dd2-4d97-b825-5e517875f83b','冬日書懷寄惟真大師','李中','唐','唐诗','tang','','[]','自別吾師後，風騷道甚孤。',96,'全唐诗/poet.tang.42000.json','["自別吾師後，風騷道甚孤。", "雪霜侵鬢髮，音信隔江湖。", "擾擾悲時世，悠悠役夢途。", "向公期盡節，多病怕傾壺。", "賤跡雖慙滯，幽情忍使辜。", "詩成天外句，棊覆夜中圖。", "落壁燈花碎，飄窗雪片麤。", "煮茶燒栗興，早晚復圍爐。"]'),
('b77dbf7e-94c1-4c72-9ebd-006acec08388','獻中書潘舍人','李中','唐','唐诗','tang','','[]','運叶半千數，天鍾許國臣。',290,'全唐诗/poet.tang.42000.json','["運叶半千數，天鍾許國臣。", "鵬霄開羽翼，鳳闕演絲綸。", "顧問當清夜，從容向紫宸。", "立言成雅誥，正意敘彝倫。", "樸素偕前哲，馨香越搢紳。", "褒辭光萬代，優旨重千鈞。", "公退誰堪接，清閑道是鄰。", "世間身屬幻，物外意通津。", "弔往兼春夢，文高賦復新。", "琴彈三峽水，屏畫十洲春。", "庭冷鋪苔色，池寒浸月輪。", "竹風來枕簟，藥氣上衣巾。", "茶譜傳溪叟，棊經受羽人。", "清虛雖得趣，獻替不妨陳。", "杞梓呈才後，神仙入侍頻。", "孤寒皆有賴，中外亦同忻。", "有士曾多難，無門得望塵。", "忙忙罹險阻，往往耗精神。", "尋果巢枝願，終全負米身。", "[遭]逢敦孝治，蹇塞值通津。", "最慶清朝祿，還霑白髮親。", "甘柔心既遂，虛薄報何因。", "遠宦聯綿歷，卑棲夙夜勤。", "良時空愛惜，末路每悲辛。"]'),
('0ff2dd5d-f454-4cf7-ba55-547b4821fe1b','早春左省寓直','徐鉉','唐','唐诗','tang','','[]','旭景鸞臺上，微雲象闕間。',48,'全唐诗/poet.tang.42000.json','["旭景鸞臺上，微雲象闕間。", "時清政事少，日永直官閑。", "遠籟飛簫管，零冰響珮環。", "終軍年二十，默坐叩玄關。"]'),
('e6472e5e-a2a3-4ac8-bbfe-bd6e669e510d','寒食宿陳公塘上','徐鉉','唐','唐诗','tang','','[]','垂楊界官道，茅屋倚高坡。',48,'全唐诗/poet.tang.42000.json','["垂楊界官道，茅屋倚高坡。", "月下春塘水，風中牧豎歌。", "折花閑立久，對酒遠情多。", "今夜孤亭夢，悠揚奈爾何。"]'),
('44b117fc-8d76-4428-8edc-191f2e89a093','將去廣陵別史員外南齋','徐鉉','唐','唐诗','tang','','[]','家聲曾與金張輩，官署今居何宋間。',64,'全唐诗/poet.tang.42000.json','["家聲曾與金張輩，官署今居何宋間。", "起得高齋臨靜曲，種成奇樹學他山。", "鴛鸞終日同醒醉，蘿薜常時共往還。", "賤子今朝獨南去，不堪迴首望清閑。"]'),
('e2cd257f-3540-43c1-8a83-d4bee46ccce2','將過江題白沙館','徐鉉','唐','唐诗','tang','','[]','少長在維揚，依然認故鄉。',48,'全唐诗/poet.tang.42000.json','["少長在維揚，依然認故鄉。", "金陵佳麗地，不道少風光。", "稍望吳臺遠，行登楚塞長。", "殷勤語江嶺，歸夢莫相妨。"]'),
('84ff2c04-2674-452c-a4d2-1ec9164614b4','登甘露寺北望','徐鉉','唐','唐诗','tang','','[]','京口潮來曲岸平，海門風起浪花生。',64,'全唐诗/poet.tang.42000.json','["京口潮來曲岸平，海門風起浪花生。", "人行沙上見日影，舟過江中聞櫓聲。", "芳草遠迷楊子渡，宿煙深映廣陵城。", "游人鄉思應如橘，相望須含兩地情。"]'),
('7a26487e-20e8-4084-bb08-560b5384723f','山路花','徐鉉','唐','唐诗','tang','','[]','不共垂楊映綺寮，倚山臨路自嬌饒。',64,'全唐诗/poet.tang.42000.json','["不共垂楊映綺寮，倚山臨路自嬌饒。", "游人過去知香遠，谷鳥飛來見影搖。", "半隔煙嵐遙隱隱，可堪風雨暮蕭蕭。", "城中春色還如此，幾處笙歌按舞腰。"]'),
('031a3154-5c09-49a5-b3cc-1c96465ca07b','京口江際弄水','徐鉉','唐','唐诗','tang','','[]','退公求靜獨臨川，楊子江南二月天。',64,'全唐诗/poet.tang.42000.json','["退公求靜獨臨川，楊子江南二月天。", "百尺翠屏甘露閣，數帆晴日海門船。", "波澄瀨石寒如玉，草接汀蘋綠似煙。", "安得乘槎更東去，十洲風外弄潺湲。"]'),
('7fe76500-573b-44e3-bb72-0f3f3747a49f','早春旬假獨直寄江舍人','徐鉉','唐','唐诗','tang','','[]','省署皆歸沐，西垣公事稀。',48,'全唐诗/poet.tang.42000.json','["省署皆歸沐，西垣公事稀。", "詠詩前砌立，聽漏向申歸。", "遠思風醒酒，餘寒雨濕衣。", "春光已堪探，芝蓋共誰飛。"]'),
('cbd77ce3-6700-4709-a829-33ec8afa57d0','從駕東幸呈諸公','徐鉉','唐','唐诗','tang','','[]','吳公臺下舊京城，曾掩衡門過十春。',64,'全唐诗/poet.tang.42000.json','["吳公臺下舊京城，曾掩衡門過十春。", "別後不知新景象，信來空問故交親。", "宦游京口無高興，習隱鍾山限俗塵。", "今日喜爲華表鶴，況陪鵷鷺免迷津。"]'),
('02c923a2-c7b4-4464-a46c-e5e4a1156933','重游木蘭亭','徐鉉','唐','唐诗','tang','','[]','繚繞長隄帶碧潯，昔年游此尚青衿。',64,'全唐诗/poet.tang.42000.json','["繚繞長隄帶碧潯，昔年游此尚青衿。", "蘭橈破浪城陰直，玉勒穿花苑樹深。", "宦路塵埃成久別，仙家風景有誰尋。", "那知年長多情後，重憑欄干一獨吟。"]'),
('17a9bfce-2af3-4f2a-b5ca-2469b652665d','賦得綵鷰','徐鉉','唐','唐诗','tang','','[]','縷綵成飛鷰，迎和啓蟄時。',48,'全唐诗/poet.tang.42000.json','["縷綵成飛鷰，迎和啓蟄時。", "翠翹生玉指，繡羽拂文楣。", "詎費銜泥力，無勞剪爪期。", "化工今在此，翻怪社來遲。"]'),
('f1c3a512-1818-440c-b125-074e2098cfc6','送魏舍人仲甫爲蘄州判官','徐鉉','唐','唐诗','tang','','[]','從事蘄春興自長，蘄人應識紫薇郎。',64,'全唐诗/poet.tang.42000.json','["從事蘄春興自長，蘄人應識紫薇郎。", "山資足後拋名路，蒓菜秋來憶故鄉。", "以道卷舒猶自適，臨戎談笑固無妨。", "如聞郡閣吹橫笛，時望青谿憶野王。"]'),
('d44a4471-c9de-4c67-b98c-87f0dbed45fc','題殷舍人宅木芙蓉','徐鉉','唐','唐诗','tang','','[]','憐君庭下木芙蓉，嫋嫋纖枝淡淡紅。',64,'全唐诗/poet.tang.42000.json','["憐君庭下木芙蓉，嫋嫋纖枝淡淡紅。", "曉吐芳心零宿露，晚搖嬌影媚清風。", "似含情態愁秋雨，暗減馨香借菊叢。", "默飲數盃應未稱，不知歌管與誰同。"]'),
('ce5c311d-01fa-4a30-aaba-466271c2c6f4','送史館高員外使嶺南','徐鉉','唐','唐诗','tang','','[]','東觀時閑暇，還修喻蜀書。',48,'全唐诗/poet.tang.42000.json','["東觀時閑暇，還修喻蜀書。", "雙旌馳縣道，百越從軺車。", "桂蠹晨餐罷，貪泉訪古初。", "春江多好景，莫使醉吟疎。"]'),
('e7498113-016b-4dfc-92ad-67618db85edf','春日紫巖山期客不至','徐鉉','唐','唐诗','tang','','[]','郊外春華好，人家帶碧谿。',48,'全唐诗/poet.tang.42000.json','["郊外春華好，人家帶碧谿。", "淺莎藏鴨戲，輕靄隔雞啼。", "掩映紅桃谷，夤緣翠柳堤。", "王孫竟不至，芳草自萋萋。"]'),
('91d74810-0d3e-45d1-90aa-806aa8445b3c','宿蔣帝廟明日遊山南諸寺','徐鉉','唐','唐诗','tang','','[]','便返城闉尚未甘，更從山北到山南。',64,'全唐诗/poet.tang.42000.json','["便返城闉尚未甘，更從山北到山南。", "花枝似雪春雖半，桂魄如眉日始三。", "松蓋遮門寒黯黯，柳絲妨路翠𣯶𣯶。", "登臨莫怪偏留戀，游宦多年事事諳。"]'),
('28ddc2ee-b797-4756-af2b-f7bf12dd6798','賦得有所思','徐鉉','唐','唐诗','tang','','[]','所思何在杳難尋，路遠山長水復深。',64,'全唐诗/poet.tang.42000.json','["所思何在杳難尋，路遠山長水復深。", "衰草滿庭空佇立，清風吹袂更長吟。", "忘情好醉青田酒，寄恨宜調綠綺琴。", "落日鮮雲偏聚散，可能知我獨傷心。"]'),
('4208d61f-284b-475e-be78-848aee139efe','贈王貞素先生','徐鉉','唐','唐诗','tang','','[]','先生嘗已佩真形，紺髮朱顏骨氣清。',64,'全唐诗/poet.tang.42000.json','["先生嘗已佩真形，紺髮朱顏骨氣清。", "道祕未傳鴻寶術，院深時聽步虛聲。", "遼東幾度悲城郭，吳市終應變姓名。", "三十六天皆有籍，他年何處問歸程。"]'),
('4663ace2-fe92-448a-a9fb-d69d3efaf494','春夜月','徐鉉','唐','唐诗','tang','','[]','幽人春望本多情，況是花繁月正明。',32,'全唐诗/poet.tang.42000.json','["幽人春望本多情，況是花繁月正明。", "竟夕無言亦無寐，繞堦芳草影隨行。"]'),
('76d58a80-1571-4db2-ba6f-841c13efe832','愛敬寺有老僧嘗游長安言秦雍間事歷歷可聽因贈此詩兼示同行客','徐鉉','唐','唐诗','tang','','[]','白首棲禪者，嘗談灞滻游。',48,'全唐诗/poet.tang.42000.json','["白首棲禪者，嘗談灞滻游。", "能令過江客，偏起失鄉愁。", "室倚桃花崦，門臨杜若洲。", "城中無此景，將子剩淹留。"]'),
('7e1cca4b-fd18-4434-af1b-8591054bb7a2','游蔣山題辛夷花寄陳奉禮','徐鉉','唐','唐诗','tang','','[]','今歲游山已恨遲，山中仍喜見辛夷。',64,'全唐诗/poet.tang.42000.json','["今歲游山已恨遲，山中仍喜見辛夷。", "簪纓且免全爲累，桃李猶堪別作期。", "晴後日高偏照灼，晚來風急漸離披。", "山郎不作同行伴，折得何由寄所思。"]'),
('ff738be7-c3fe-46cb-961b-c4de283a1a5b','和殷舍人蕭員外春雪','徐鉉','唐','唐诗','tang','','[]','萬里春陰乍履端，廣庭風起玉塵乾。',64,'全唐诗/poet.tang.42000.json','["萬里春陰乍履端，廣庭風起玉塵乾。", "梅花嶺上連天白，蕙草堦前特地寒。", "晴去便爲經歲別，興來何惜徹宵看。", "此時鴛侶皆閑暇，贈答詩成禁漏殘。"]'),
('3a414e00-3d63-442b-8d22-f493f41a3072','寄蘄州高郎中','徐鉉','唐','唐诗','tang','','[]','賈傅棲遲楚澤東，蘭皋三度換秋風。',64,'全唐诗/poet.tang.42000.json','["賈傅棲遲楚澤東，蘭皋三度換秋風。", "紛紛世事來無盡，黯黯離魂去不通。", "直道未能勝社鼠，孤飛徒自歎冥鴻。", "知君多少思鄉恨，併在山城一笛中。"]'),
('d09ecd28-4f1f-4de9-9eab-a7836bec9638','寄和州韓舍人','徐鉉','唐','唐诗','tang','','[]','急景駸駸度，遙懷處處生。',48,'全唐诗/poet.tang.42000.json','["急景駸駸度，遙懷處處生。", "風頭乍寒暖，天色半陰晴。", "久別魂空斷，終年道不行。", "殷勤雲上雁，爲過歷陽城。"]'),
('338928c0-b7c4-4e78-8343-8ec7b47a50ad','從兄龍武將軍沒於邊戍過舊營宅作','徐鉉','唐','唐诗','tang','','[]','前年都尉沒邊城，帳下何人領舊兵。',64,'全唐诗/poet.tang.42000.json','["前年都尉沒邊城，帳下何人領舊兵。", "徼外瘴煙沉鼓角，山前秋日照銘旌。", "笙歌却返烏衣巷，部曲皆還細柳營。", "今日園林過寒食，馬蹄猶擬入門行。"]'),
('e3d7fac4-b17a-43f1-9780-2439d1459c9a','景陽臺懷古','徐鉉','唐','唐诗','tang','','[]','後主忘家不悔，江南異代長春。',28,'全唐诗/poet.tang.42000.json','["後主忘家不悔，江南異代長春。", "今日景陽臺上，閑人何用傷神。"]'),
('9010faab-12b5-4001-a7f7-0449fdaeafef','春分日','徐鉉','唐','唐诗','tang','','[]','仲春初四日，春色正中分。',48,'全唐诗/poet.tang.42000.json','["仲春初四日，春色正中分。", "綠野徘徊月，晴天斷續雲。", "鷰飛猶箇箇，花落已紛紛。", "思婦高樓晚，歌聲不可聞。"]'),
('24b081e5-e3f6-4779-8693-b62ad1959028','寄駕部郎中','徐鉉','唐','唐诗','tang','','[]','賤子乖慵性，頻爲省直牽。',48,'全唐诗/poet.tang.42000.json','["賤子乖慵性，頻爲省直牽。", "交親每相見，多在相門前。", "君獨疎名路，爲郎過十年。", "炎風久成別，南望思悠然。"]'),
('f98aa627-faf1-45f1-9cc6-265a8c266f0e','和王庶子寄題兄長建州廉使新亭','徐鉉','唐','唐诗','tang','','[]','謝守高齋結構新，一方風景萬家情。',64,'全唐诗/poet.tang.42000.json','["謝守高齋結構新，一方風景萬家情。", "羣賢詎減山陰會，遠俗初聞正始聲。", "水檻片雲長不去，訟庭纖草轉應生。", "阿連詩句偏多思，遙想池塘晝夢成。"]'),
('45bd7a93-acd1-474a-a273-9c453b408233','謝文靖墓下作','徐鉉','唐','唐诗','tang','','[]','越徼稽天討，周京亂虜塵。',48,'全唐诗/poet.tang.42000.json','["越徼稽天討，周京亂虜塵。", "蒼生何可奈，江表更無人。", "豈憚尋荒壟，猶思認後身。", "春風白楊裏，獨步淚霑巾。"]'),
('6f6f5c63-04a7-453f-baed-ea7d78085059','觀人讀春秋','徐鉉','唐','唐诗','tang','','[]','日覺儒風薄，誰將霸道羞。',24,'全唐诗/poet.tang.42000.json','["日覺儒風薄，誰將霸道羞。", "亂臣無所懼，何用讀春秋。"]'),
('a138fe7f-c6fa-41b6-9e49-4248352cf1c7','秋日雨中與蕭贊善訪殷舍人於翰林座中作','徐鉉','唐','唐诗','tang','','[]','野出西垣步步遲，秋光如水雨如絲。',64,'全唐诗/poet.tang.42000.json','["野出西垣步步遲，秋光如水雨如絲。", "銅龍樓下逢閑客，紅藥堦前訪舊知。", "亂點乍滋承露處，碎聲因想滴蓬時。", "銀臺鑰入須歸去，不惜餘歡盡酒巵。"]'),
('6ad18885-a508-421b-b0cc-921ffc92bc8c','送和州張員外爲江都令','徐鉉','唐','唐诗','tang','','[]','經年相望隔重湖，一旦相逢在上都。',64,'全唐诗/poet.tang.42000.json','["經年相望隔重湖，一旦相逢在上都。", "塞詔官班聊慰否，埋輪意氣尚存無。", "由來聖代憐才子，始覺清風激懦夫。", "若向西岡尋勝賞，舊題名處爲躊躇。"]'),
('8c374c77-43ec-4d9b-b4d1-770f6219ee31','和明道人宿山寺','徐鉉','唐','唐诗','tang','','[]','聞道經行處，山前與水陽。',48,'全唐诗/poet.tang.42000.json','["聞道經行處，山前與水陽。", "磐聲深小院，燈影逈高房。", "落宿依樓角，歸雲擁殿廊。", "羨師閑未得，早起逐班行。"]'),
('cb01ada0-22ad-41e3-b1b1-f40f48e61933','晚歸','徐鉉','唐','唐诗','tang','','[]','暑服道情出，煙街薄暮還。',48,'全唐诗/poet.tang.42000.json','["暑服道情出，煙街薄暮還。", "風清飄短袂，馬健弄連環。", "水靜聞歸櫓，霞明見遠山。", "過從本無事，從此涉旬間。"]'),
('698cc181-ac28-4e57-b0e4-5ac453438325','月真歌','徐鉉','唐','唐诗','tang','','[]','揚州勝地多麗人，其間麗者名月真。',352,'全唐诗/poet.tang.42000.json','["揚州勝地多麗人，其間麗者名月真。", "月真初年十四五，能彈琵琶善歌舞。", "風前弱柳一枝春，花裏嬌鶯百般語。", "揚州帝京多名賢，其間賢者殷德川。", "德川初秉綸闈筆，職近名高常罕出。", "花前月下或遊從，一見月真如舊識。", "閑庭深院資賢宅，宅門嚴峻無凡客。", "垂簾偶坐唯月真，調弄琵琶郎爲拍。", "殷郎一旦過江去，鏡中嬾作孤鸞舞。", "朝雲暮雨鎮相隨，石頭城下還相遇。", "二月三月江南春，滿城濛濛起香塵。", "隔牆試聽歌一曲，乃是資賢宅裏人。", "綠窗繡幌天將曉，殘燭依依香褭褭。", "離腸却恨苦多情，輭障薰籠空悄悄。", "殷郎去冬入翰林，九霄官署轉深沉。", "人間想望不可見，唯向月真存舊心。", "我慙闒茸何爲者，長感餘光每相假。", "陋巷蕭條正掩扉，相攜訪我衡茅下。", "我本山人愚且貞，歌筵歌席常無情。", "自從一見月真後，至今贏得顛狂名。", "殷郎月真聽我語，少壯光陰能幾許。", "良辰美景數追隨，莫教長說相思苦。"]'),
('f7098bca-6ddb-45d8-8b0c-9e21f2487c01','走筆送義興令趙宣輔','徐鉉','唐','唐诗','tang','','[]','聞君孤櫂汎荆谿，隴首雲隨別恨飛。',32,'全唐诗/poet.tang.42000.json','["聞君孤櫂汎荆谿，隴首雲隨別恨飛。", "杜牧舊居憑買取，他年藜杖願同歸。"]'),
('9877e9cb-2203-455f-8e12-68fd70522f47','天闕山絕句','徐鉉','唐','唐诗','tang','','[]','散誕愛山客，淒涼懷古心。',24,'全唐诗/poet.tang.42000.json','["散誕愛山客，淒涼懷古心。", "寒風天闕晚，盡日倚軒吟。"]'),
('37b79c8e-2d44-4d27-a87a-5100334e92e8','除夜','徐鉉','唐','唐诗','tang','','[]','寒燈耿耿漏遲遲，送故迎新了不欺。',64,'全唐诗/poet.tang.42000.json','["寒燈耿耿漏遲遲，送故迎新了不欺。", "往事併隨殘曆日，春風寧識舊容儀。", "預慙歲酒難先飲，更對鄉儺羨小兒。", "吟罷明朝贈知己，便須題作去年詩。"]'),
('980748f7-c4cb-4750-92ff-9eeafff2c316','寄鍾謨','徐鉉','唐','唐诗','tang','','[]','看看潘鬢二毛生，昨日林梢又轉鶯。',64,'全唐诗/poet.tang.42000.json','["看看潘鬢二毛生，昨日林梢又轉鶯。", "欲對春風忘世慮，敢言尊酒召時英。", "假中西閣應無事，筵上南威幸有情。", "不得車公終不樂，已教紅袖出門迎。"]'),
('f8238528-257d-4c66-8739-23758c421c9b','正初答鍾郎中見招','徐鉉','唐','唐诗','tang','','[]','高齋遲景雪初晴，風拂喬枝待早鶯。',64,'全唐诗/poet.tang.42000.json','["高齋遲景雪初晴，風拂喬枝待早鶯。", "南省郎官名籍籍，東鄰妓女字英英。", "流年倏忽成陳事，春物依稀有舊情。", "新歲相思自過訪，不煩虛左遠相迎。"]'),
('08037e76-570b-44c9-b01f-5847fba1c9e2','聞雁寄故人','徐鉉','唐','唐诗','tang','','[]','久作他鄉客，深慙薄宦非。',48,'全唐诗/poet.tang.42000.json','["久作他鄉客，深慙薄宦非。", "不知雲上雁，何得每年歸。", "夜靜聲彌怨，天空影更微。", "往年離別淚，今夕重霑衣。"]'),
('491d3756-ae5f-4e30-b20e-77b4314f582d','江舍人宅筵上有妓唱和州韓舍人歌辭因以寄','徐鉉','唐','唐诗','tang','','[]','良宵絲竹偶成歡，中有佳人俯翠鬟。',64,'全唐诗/poet.tang.42000.json','["良宵絲竹偶成歡，中有佳人俯翠鬟。", "白雪飄颻傳樂府，阮郎憔悴在人間。", "清風朗月長相憶，佩蕙紉蘭早晚還。", "深夜酒空筵欲散，向隅惆悵鬢堪斑。"]'),
('36c557f4-367f-4063-82ae-d4ce4ad7dc09','寒食日作','徐鉉','唐','唐诗','tang','','[]','廚冷煙初禁，門閑日更斜。',48,'全唐诗/poet.tang.42000.json','["廚冷煙初禁，門閑日更斜。", "東風不好事，吹落滿庭花。", "過社紛紛鷰，新晴淡淡霞。", "京都盛游觀，誰訪子雲家。"]'),
('7f8e6169-8bcc-49a8-aae1-5e2dbe483619','賀殷游二舍人入翰林江給事拜中丞','徐鉉','唐','唐诗','tang','','[]','清晨待漏獨徘徊，霄漢懸心不易裁。',64,'全唐诗/poet.tang.42000.json','["清晨待漏獨徘徊，霄漢懸心不易裁。", "閣老深嚴歸翰苑，夕郎威望拜霜臺。", "青綾對覆蓬壺晚，赤棒前驅道路開。", "猶有西垣廳記在，莫忘同草紫泥來。"]'),
('c550d206-5233-4fb0-a38a-fd79d8772b3e','歐陽太監雨中視決堤因墮水明日見於省中因戲之','徐鉉','唐','唐诗','tang','','[]','聞道張晨蓋，徘徊石首東。',48,'全唐诗/poet.tang.42000.json','["聞道張晨蓋，徘徊石首東。", "濬川非伯禹，落水異三公。", "衣濕仍愁雨，冠欹更怯風。", "今朝復相見，疑是葛仙翁。"]'),
('3469fb45-996a-472c-b081-91b2501a42e6','送吳郎中爲宣州推官知涇縣','徐鉉','唐','唐诗','tang','','[]','征虜亭邊月，雞鳴伴客行。',48,'全唐诗/poet.tang.42000.json','["征虜亭邊月，雞鳴伴客行。", "可憐何水部，今事謝宣城。", "風物聊供賞，班資莫繫情。", "同心不同載，留滯爲浮名。"]'),
('24f564f9-490e-47c3-8640-6d4c13b43b04','寄舒州杜員外','徐鉉','唐','唐诗','tang','','[]','信到得君書，知君已下車。',48,'全唐诗/poet.tang.42000.json','["信到得君書，知君已下車。", "粉闈情在否，蓮幕興何如。", "人望徵賢入，余思從子居。", "灊山真隱地，憑爲卜茅廬。"]'),
('fbe2abc4-1569-4a65-8b96-60b0f5e545bf','九月十一日寄陳郎中','徐鉉','唐','唐诗','tang','','[]','我多吏事君多病，寂絕過從又幾旬。',32,'全唐诗/poet.tang.42000.json','["我多吏事君多病，寂絕過從又幾旬。", "前日龍山煙景好，風前落帽是何人。"]'),
('d0ced71f-21c8-4a86-92fe-7292e531d3a2','和司門郎中陳彥','徐鉉','唐','唐诗','tang','','[]','衡門寂寂逢迎少，不見仙郎向五旬。',32,'全唐诗/poet.tang.42000.json','["衡門寂寂逢迎少，不見仙郎向五旬。", "莫問龍山前日事，菊花開却爲閑人。"]'),
('f7f83c54-b0ef-4d06-8f51-205a95f37dd2','賦得擣衣','徐鉉','唐','唐诗','tang','','[]','江上多離別，居人夜擣衣。',48,'全唐诗/poet.tang.42000.json','["江上多離別，居人夜擣衣。", "拂砧知露滴，促杵恐霜飛。", "漏轉聲頻斷，愁多力自微。", "裁縫依夢見，腰帶定應非。"]'),
('49cea7d9-7f67-47f5-aa03-7c6b00ba1c65','九月三十夜雨寄故人','徐鉉','唐','唐诗','tang','','[]','獨聽空堦雨，方知愁事悲。',48,'全唐诗/poet.tang.42000.json','["獨聽空堦雨，方知愁事悲。", "寂寥旬假日，蕭颯夜長時。", "別念紛紛起，寒更故故遲。", "情人如不醉，定是兩相思。"]'),
('115008dc-81dc-4112-9448-e7c30f06d290','寄撫州鍾郎中','徐鉉','唐','唐诗','tang','','[]','去載分襟後，尋聞在建安。',48,'全唐诗/poet.tang.42000.json','["去載分襟後，尋聞在建安。", "封疆正多事，尊俎若爲歡。", "都護空遺鏃，明君欲舞干。", "繞朝時不用，非是殺身難。"]'),
('e1d3d081-709a-44d7-a256-386cd01b24f6','送歐陽太監游廬山','徐鉉','唐','唐诗','tang','','["\u5e90\u5c71"]','家家門外廬山路，唯有夫君乞假游。',64,'全唐诗/poet.tang.42000.json','["家家門外廬山路，唯有夫君乞假游。", "案牘乍拋公署晚，林泉已近暑天秋。", "海潮盡處逢陶石，江月圓時上庾樓。", "此去蕭然好長往，人間何事不悠悠。"]'),
('79518155-2c59-4fbb-b4cf-f19930322676','立秋後一日與朱舍人同直','徐鉉','唐','唐诗','tang','','[]','一宿秋風未覺涼，數聲宮漏日猶長。',32,'全唐诗/poet.tang.42000.json','["一宿秋風未覺涼，數聲宮漏日猶長。", "林泉無計消殘暑，虛向華池費稻粱。"]'),
('cf1d8f48-0cc9-405f-8867-7bfd38e99403','賦得霍將軍辭第','徐鉉','唐','唐诗','tang','','[]','漢將承恩久，圖勳肯顧私。',72,'全唐诗/poet.tang.42000.json','["漢將承恩久，圖勳肯顧私。", "匈奴猶未滅，安用以家爲。", "郢匠雖聞詔，衡門竟不移。", "寧煩張老頌，無待晏嬰辭。", "甲乙人徒費，親鄰我自持。", "悠悠千載下，常作帥臣師。"]'),
('c22afa36-25cc-453c-ab4b-106c58d184a6','和元帥書記蕭郎中觀習水師','徐鉉','唐','唐诗','tang','','[]','元帥樓船出治兵，落星山外火旗明。',64,'全唐诗/poet.tang.42000.json','["元帥樓船出治兵，落星山外火旗明。", "千帆日助江陵勢，萬里風馳下瀨聲。", "殺氣曉嚴波上鷁，凱歌遙駭海邊鯨。", "仲宣一作從軍詠，迴顧儒衣自不平。"]'),
('9ee5e692-1758-4b76-91c8-dc9b692cf5a7','秋日盧龍村舍','徐鉉','唐','唐诗','tang','','[]','置却人間事，閑從野老游。',48,'全唐诗/poet.tang.42000.json','["置却人間事，閑從野老游。", "樹聲村店晚，草色古城秋。", "獨鳥飛天外，閑雲度隴頭。", "姓名君莫問，山木與虛舟。"]'),
('b468b1a2-e395-471a-98b3-b2cc382ebda4','和蕭郎中小雪日作','徐鉉','唐','唐诗','tang','','[]','征西府裏日西斜，獨試新爐自煮茶。',64,'全唐诗/poet.tang.42000.json','["征西府裏日西斜，獨試新爐自煮茶。", "籬菊盡來低覆水，塞鴻飛去遠連霞。", "寂寥小雪閑中過，斑駁輕霜鬢上加。", "算得流年無奈處，莫將詩句祝蒼華。"]'),
('429cdb41-3b5e-43e4-b1a6-4a2cd48ad6a8','中書相公谿亭閑宴依韻','徐鉉','唐','唐诗','tang','','[]','雨霽秋光晚，亭虛野興迴。',48,'全唐诗/poet.tang.42000.json','["雨霽秋光晚，亭虛野興迴。", "沙鷗掠岸去，谿水上堦來。", "客傲風欹幘，筵香菊在盃。", "東山長許醉，何事憶天台。"]'),
('14abc826-a06f-41e4-b6cf-610adbe682a3','寄饒州王郎中效李白體','徐鉉','唐','唐诗','tang','','[]','珍重王光嗣，交情尚在不。',48,'全唐诗/poet.tang.42000.json','["珍重王光嗣，交情尚在不。", "蕪城連宅住，楚塞並車游。", "別後官三改，年來歲六周。", "銀鉤無一字，何以緩離愁。"]'),
('a2dfd91e-66de-4634-a3c4-fc0518b2c99f','寄歙州呂判官','徐鉉','唐','唐诗','tang','','[]','任公郡占好山川，谿水縈迴路屈盤。',64,'全唐诗/poet.tang.42000.json','["任公郡占好山川，谿水縈迴路屈盤。", "南國自來推勝境，故人此地作郎官。", "風光適意須留戀，祿秩資貧且喜歡。", "莫憶班行重迴首，是非多處是長安。"]'),
('3d2c76cd-6fe3-4ea8-a8a9-5c79a16a52d6','宣威苗將軍貶官後重經故宅','徐鉉','唐','唐诗','tang','','[]','蔣山南望近西坊，亭館依然鎖院牆。',64,'全唐诗/poet.tang.42000.json','["蔣山南望近西坊，亭館依然鎖院牆。", "天子未嘗過細柳，將軍尋已戍燉煌。", "敧傾怪石山無色，零落圓荷水不香。", "爲將爲儒皆寂寞，門前愁殺馬中郎。"]'),
('5c0119fd-8ea8-4933-9ea0-d673f3f47a51','附池州薛郎中書因寄歙州張員外','徐鉉','唐','唐诗','tang','','[]','新安從事舊臺郎，直氣多才不可忘。',64,'全唐诗/poet.tang.42000.json','["新安從事舊臺郎，直氣多才不可忘。", "一旦江山馳別夢，幾年簪紱共周行。", "岐分出處何方是，情共窮通此義長。", "因附鄰州寄消息，接輿今日信爲狂。"]'),
('27c0900d-5719-4e49-be3a-4e74a1dca0fd','寄江都路員外','徐鉉','唐','唐诗','tang','','[]','吾兄失意在東都，聞說襟懷任所如。',64,'全唐诗/poet.tang.42000.json','["吾兄失意在東都，聞說襟懷任所如。", "已縱乖慵爲傲吏，有何關鍵制豪胥。", "縣齋曉閉多移病，南畝秋荒憶遂初。", "知道故人相憶否，嵇康不得嬾修書。"]'),
('f3c6c86f-5091-4dca-9ba0-b7119bf0e460','張員外好茅山風景求爲句容令作此送','徐鉉','唐','唐诗','tang','','[]','句曲山前縣，依依數舍程。',48,'全唐诗/poet.tang.42000.json','["句曲山前縣，依依數舍程。", "還同適勾漏，非是厭承明。", "柳谷供詩景，華陽契道情。", "金門容傲吏，官滿且還城。"]'),
('5bc0fde3-7995-4dac-a5b2-4072e23701eb','送應之道人歸江西','徐鉉','唐','唐诗','tang','','[]','曾騎竹馬傍洪厓，二十餘年變物華。',64,'全唐诗/poet.tang.42000.json','["曾騎竹馬傍洪厓，二十餘年變物華。", "客夢等閑過驛閣，歸帆遙羨指龍沙。", "名垂小篆矜垂露，詩作吳吟對綺霞。", "歲暮定知迴未得，信來憑爲寄梅花。"]'),
('b8674b09-516b-46e8-a884-ebe83121767c','送元帥書記高郎中出爲婺源建威軍使','徐鉉','唐','唐诗','tang','','[]','寒風蕭瑟楚江南，記室戎裝挂錦帆。',64,'全唐诗/poet.tang.42000.json','["寒風蕭瑟楚江南，記室戎裝挂錦帆。", "倚馬未曾妨笑傲，斬牲先要厲威嚴。", "危言昔日嘗無隱，壯節今來信不凡。", "惟有杯盤思上國，酒醪甜淡菜蔬甘。"]'),
('153556cc-132b-4ea6-8184-d52b005ad81f','遊方山宿李道士房','徐鉉','唐','唐诗','tang','','[]','從來未面李先生，借我西窗臥月明。',32,'全唐诗/poet.tang.42000.json','["從來未面李先生，借我西窗臥月明。", "二十三家同願識，素騾何日暫還城。"]'),
('4bdc0779-dfa4-4f54-8b25-516317726ab4','題畫石山','徐鉉','唐','唐诗','tang','','[]','彼美巉巖石，誰施黼藻功。',96,'全唐诗/poet.tang.42000.json','["彼美巉巖石，誰施黼藻功。", "回巖明照地，絕壁爛臨空。", "錦段鮮須濯，羅屏展易窮。", "不因秋蘚綠，非假晚霞紅。", "羽客藏書洞，樵人取箭風。", "靈蹤理難問，仙路去何通。", "返駕歸塵裏，留情向此中。", "迴瞻畫圖畔，遙羨面山翁。"]'),
('7bcb03fd-0659-479d-ba0b-49ba056c39d1','臨石步港','徐鉉','唐','唐诗','tang','','[]','碕岸墮縈帶，微風起細漣。',48,'全唐诗/poet.tang.42000.json','["碕岸墮縈帶，微風起細漣。", "綠陰三月後，倒影亂峰前。", "吹浪游鱗小，黏苔碎石圓。", "會將腰下組，換取釣魚船。"]'),
('78db4949-4c9f-4fef-b446-51453e1e67cd','病題二首 一','徐鉉','唐','唐诗','tang','','[]','性靈慵嬾百無能，唯被朝參遣夙興。',64,'全唐诗/poet.tang.42000.json','["性靈慵嬾百無能，唯被朝參遣夙興。", "聖主優容恩未答，丹經疎闊病相陵。", "脾傷對客偏愁酒，眼暗看書每媿燈。", "進與時乖不知退，可憐身計謾騰騰。"]'),
('0db4e706-43cc-4ac4-8085-4007eff47ae0','病題二首 二','徐鉉','唐','唐诗','tang','','[]','人間多事本難論，況是人間嬾慢人。',64,'全唐诗/poet.tang.42000.json','["人間多事本難論，況是人間嬾慢人。", "不解養生何怪病，已能知命敢辭貧。", "向空咄咄煩書字，舉世滔滔莫問津。", "金馬門前君識否，東方曼倩是前身。"]'),
('8e8bdf70-5797-4a26-9388-1c036ae2444c','寄江州蕭給事','徐鉉','唐','唐诗','tang','','[]','夕郎憂國不憂身，今向天涯作逐臣。',64,'全唐诗/poet.tang.42000.json','["夕郎憂國不憂身，今向天涯作逐臣。", "魂夢暗馳龍闕曙，嘯吟閑繞虎谿春。", "朝車載酒過山寺，諫紙題詩寄野人。", "惆悵懦夫何足道，自離羣後已同塵。"]'),
('5779db4d-ca4a-42cb-8a4d-ffc2063e4eff','和江州江中丞見寄','徐鉉','唐','唐诗','tang','','[]','賈傅南遷久，江關道路遙。',48,'全唐诗/poet.tang.42000.json','["賈傅南遷久，江關道路遙。", "北來空見雁，西去不如潮。", "鼠穴依城社，鴻飛在泬寥。", "高低各有處，不擬更相招。"]'),
('df59fbc4-c9ce-47e6-a03c-6c0718af2de7','和鍾郎中送朱先輩還京垂寄','徐鉉','唐','唐诗','tang','','[]','分司洗馬無人問，辭客殷勤輟棹歌。',64,'全唐诗/poet.tang.42000.json','["分司洗馬無人問，辭客殷勤輟棹歌。", "蒼蘚滿庭行徑小，高梧臨檻雨聲多。", "春愁盡付千盃酒，鄉思遙聞一曲歌。", "且共勝遊消永日，西岡風物近如何。"]'),
('3690db2b-c05a-487a-8d1c-be812521d2f3','送郝郎中爲浙西判官','徐鉉','唐','唐诗','tang','','[]','大藩從事本優賢，幕府仍當北固前。',64,'全唐诗/poet.tang.42000.json','["大藩從事本優賢，幕府仍當北固前。", "花繞樓臺山倚郭，寺臨江海水連天。", "恐君到即忘歸日，憶我遊曾歷二年。", "若許他時作閑伴，殷勤爲買釣魚船。"]'),
('7f4f32c1-0a14-4281-b5f3-ae7ef7cf5432','翰林游舍人清明日入院中途見過余明日亦入西省上直因寄游君','徐鉉','唐','唐诗','tang','','[]','榆柳開新焰，梨花發故枝。',48,'全唐诗/poet.tang.42000.json','["榆柳開新焰，梨花發故枝。", "輜軿隘城市，圭組坐曹司。", "獨對芝泥檢，遙憐白馬兒。", "禁林還視草，氣味兩相知。"]'),
('26991ef0-4a6a-458a-ad28-093388ae8912','陪王庶子游後湖涵虛閣','徐鉉','唐','唐诗','tang','','[]','懸圃清虛乍過秋，看山尋水上茲樓。',64,'全唐诗/poet.tang.42000.json','["懸圃清虛乍過秋，看山尋水上茲樓。", "輕鷗的的飛難沒，紅葉紛紛晚更稠。", "風卷微雲分遠岫，浪搖晴日照中洲。", "躋攀況有承華客，如在南皮奉勝遊。"]'),
('33470720-7ada-4e1c-af0c-6e578f86e7c9','柳枝辭十二首 一','徐鉉','唐','唐诗','tang','','[]','把酒憑君唱柳枝，也從絲管遞相隨。',32,'全唐诗/poet.tang.42000.json','["把酒憑君唱柳枝，也從絲管遞相隨。", "逢春只合朝朝醉，記取秋風落葉時。"]'),
('c578615e-08cf-4ac4-aaed-c91bc97b6908','柳枝辭十二首 二','徐鉉','唐','唐诗','tang','','[]','南園日暮起春風，吹散楊花雪滿空。',32,'全唐诗/poet.tang.42000.json','["南園日暮起春風，吹散楊花雪滿空。", "不惜楊花飛也得，愁君老盡臉邊紅。"]'),
('c35b8e35-cc30-497c-8d47-586a098f2d90','柳枝辭十二首 三','徐鉉','唐','唐诗','tang','','[]','陌上朱門柳映花，簾鉤半捲綠陰斜。',32,'全唐诗/poet.tang.42000.json','["陌上朱門柳映花，簾鉤半捲綠陰斜。", "憑郎暫駐青驄馬，此是錢塘小小家。"]'),
('b719d33b-da81-4344-a4a7-87757ffbfa1c','柳枝辭十二首 四','徐鉉','唐','唐诗','tang','','[]','夾岸朱欄柳映樓，綠波平幔帶花流。',32,'全唐诗/poet.tang.42000.json','["夾岸朱欄柳映樓，綠波平幔帶花流。", "歌聲不出長條密，忽地風迴見綵舟。"]'),
('6ae07455-d9f7-463a-b010-d6cab1fbeece','柳枝辭十二首 五','徐鉉','唐','唐诗','tang','','[]','老大逢春總恨春，綠楊陰裏最愁人。',32,'全唐诗/poet.tang.42000.json','["老大逢春總恨春，綠楊陰裏最愁人。", "舊游一別無因見，嫩葉如眉處處新。"]'),
('928a8f26-dca6-4e5a-a790-af305e2f964a','柳枝辭十二首 六','徐鉉','唐','唐诗','tang','','[]','濛濛堤畔柳含煙，疑是陽和二月天。',32,'全唐诗/poet.tang.42000.json','["濛濛堤畔柳含煙，疑是陽和二月天。", "醉裏不知時節改，漫隨兒女打鞦韆。"]'),
('62c1359d-d760-4722-8fae-ef18b7db5242','柳枝辭十二首 七','徐鉉','唐','唐诗','tang','','[]','水閣春來乍減寒，曉妝初罷倚欄干。',32,'全唐诗/poet.tang.42000.json','["水閣春來乍減寒，曉妝初罷倚欄干。", "長條亂拂春波動，不許佳人照影看。"]'),
('19cea838-66fb-4ef2-a9aa-14009c6f27fa','柳枝辭十二首 八','徐鉉','唐','唐诗','tang','','[]','柳岸煙昏醉裏歸，不知深處有芳菲。',32,'全唐诗/poet.tang.42000.json','["柳岸煙昏醉裏歸，不知深處有芳菲。", "重來已見花飄盡，唯有黃鶯囀樹飛。"]'),
('5762a59d-15b6-43f0-ba85-e66073d73a02','柳枝辭十二首 九','徐鉉','唐','唐诗','tang','','[]','此去仙源不是遙，垂楊深處有朱橋。',32,'全唐诗/poet.tang.42000.json','["此去仙源不是遙，垂楊深處有朱橋。", "共君同過朱橋去，索映垂楊聽洞簫。"]'),
('c68bd289-5728-464f-9847-29d7a46f3d85','柳枝辭十二首 十','徐鉉','唐','唐诗','tang','','[]','暫別揚州十度春，不知光景屬何人。',32,'全唐诗/poet.tang.42000.json','["暫別揚州十度春，不知光景屬何人。", "一帆歸客千條柳，腸斷東風楊子津。"]'),
('41f8bb1c-6a33-4d2f-9038-0af59408b7c7','柳枝辭十二首 十一','徐鉉','唐','唐诗','tang','','[]','仙樂春來按舞腰，清聲偏似傍嬌饒。',32,'全唐诗/poet.tang.42000.json','["仙樂春來按舞腰，清聲偏似傍嬌饒。", "應緣鶯舌多情賴，長向雙成說翠條。"]'),
('ac96d445-b720-4fde-b4f0-533957859b8f','柳枝辭十二首 十二','徐鉉','唐','唐诗','tang','','[]','鳳笙臨檻不能吹，舞袖當筵亦自疑。',32,'全唐诗/poet.tang.42000.json','["鳳笙臨檻不能吹，舞袖當筵亦自疑。", "唯有美人多意緒，解依芳態畫雙眉。"]'),
('cc5ef5e5-1bf9-4926-b982-3c1185f4d3cc','貶官泰州出城作','徐鉉','唐','唐诗','tang','','[]','浮名浮利信悠悠，四海干戈痛主憂。',64,'全唐诗/poet.tang.42000.json','["浮名浮利信悠悠，四海干戈痛主憂。", "三諫不從爲逐客，一身無累似虛舟。", "滿朝權貴皆曾忤，繞郭林泉已徧游。", "惟有戀恩終不改，半程猶自望城樓。"]'),
('a53ce8d0-ac2a-4ecc-aa00-4653f367aca6','過江','徐鉉','唐','唐诗','tang','','[]','別路知何極，離腸有所思。',48,'全唐诗/poet.tang.42000.json','["別路知何極，離腸有所思。", "登艫望城遠，搖樐過江遲。", "斷岸煙中失，長天水際垂。", "此心非橘柚，不爲兩鄉移。"]'),
('a4f32b6e-4f7d-42e8-af43-080045be6e55','經東都太子橋','徐鉉','唐','唐诗','tang','','[]','綸闈放逐知何道，桂苑風流且暫歸。',32,'全唐诗/poet.tang.42000.json','["綸闈放逐知何道，桂苑風流且暫歸。", "莫問升遷橋上客，身謀疎拙舊心違。"]'),
('041ff655-80c6-45c4-90fb-47e86b980400','贈維揚故人','徐鉉','唐','唐诗','tang','','[]','東京少長認維桑，書劒誰教入帝鄉。',64,'全唐诗/poet.tang.42000.json','["東京少長認維桑，書劒誰教入帝鄉。", "一事無成空放逐，故人相見重淒涼。", "樓臺寂寞官河晚，人物稀疎驛路長。", "莫怪臨風惆悵久，十年春色憶維揚。"]'),
('9f641bb0-35ce-42e6-a543-00da88c2b94f','泰州道中却寄東京故人','徐鉉','唐','唐诗','tang','','[]','風緊雨淒淒，川迴岸漸低。',48,'全唐诗/poet.tang.42000.json','["風緊雨淒淒，川迴岸漸低。", "吳州林外近，隋苑霧中迷。", "聚散紛如此，悲歡豈易齊。", "料君殘酒醒，還聽子規啼。"]'),
('e527504d-0c23-4719-8b5b-c94747ae3d51','得浙西郝判官書未及報聞燕王移鎮京口因寄此詩問方判官田書記消息','徐鉉','唐','唐诗','tang','','[]','秋風海上久離居，曾得劉公一紙書。',64,'全唐诗/poet.tang.42000.json','["秋風海上久離居，曾得劉公一紙書。", "淡水心情長若此，銀鉤蹤迹更無如。", "嘗憂座側飛鴞鳥，未暇江中覓鯉魚。", "今日京吳建朱邸，問君誰共曳長裾。"]'),
('f6c4737c-b9d3-4cf5-8410-f296cceb839a','贈陶使君求梨','徐鉉','唐','唐诗','tang','','[]','昨宵宴罷醉如泥，惟憶張公大谷梨。',64,'全唐诗/poet.tang.42000.json','["昨宵宴罷醉如泥，惟憶張公大谷梨。", "白玉花繁曾綴處，黃金色嫩乍成時。", "冷侵肺腑醒偏早，香惹衣襟歇倍遲。", "今旦中山方酒渴，唯應此物最相宜。"]'),
('3597c41d-b221-4ea8-badc-72e04c57cb47','陳覺放還至泰州以詩見寄作此答之','徐鉉','唐','唐诗','tang','','[]','朱雲曾爲漢家憂，不怕交親作世仇。',64,'全唐诗/poet.tang.42000.json','["朱雲曾爲漢家憂，不怕交親作世仇。", "壯氣未平空咄咄，狂言無騐信悠悠。", "今朝我作傷弓鳥，却羨君爲不繫舟。", "勞寄新詩平宿憾，此生心氣貫清秋。"]'),
('be36ebfd-6e0b-498c-96b6-cbf92b7fde4c','王三十七自京垂訪作此送之','徐鉉','唐','唐诗','tang','','[]','失鄉遷客在天涯，門掩苔垣向水斜。',64,'全唐诗/poet.tang.42000.json','["失鄉遷客在天涯，門掩苔垣向水斜。", "只就鱗鴻求遠信，敢言車馬訪貧家。", "煙生柳岸將垂縷，雪壓梅園半是花。", "惆悵明朝尊酒散，夢魂相送到京華。"]'),
('5f8d275d-0224-4cb1-83e0-5ab78a32b015','陶使君挽歌二首 一','徐鉉','唐','唐诗','tang','','[]','太守今何在，行春去不歸。',48,'全唐诗/poet.tang.42000.json','["太守今何在，行春去不歸。", "筵空收管吹，郊逈儼驂騑。", "營外星纔落，園中露已稀。", "傷心梁上鷰，猶解向人飛。"]'),
('9dab949d-6608-4122-8e01-dfd36a2c2ec3','陶使君挽歌二首 二','徐鉉','唐','唐诗','tang','','[]','始憶花前宴，笙歌醉夕陽。',48,'全唐诗/poet.tang.42000.json','["始憶花前宴，笙歌醉夕陽。", "那堪城外送，哀挽逐歸艎。", "鈴閣朝猶閉，風亭日已荒。", "唯餘遷客淚，霑灑後池傍。"]'),
('358fdcb0-38bf-4f6d-9bbe-9c8aa534e2a3','雪中作','徐鉉','唐','唐诗','tang','','[]','賦分多情客，經年去國心。',48,'全唐诗/poet.tang.42000.json','["賦分多情客，經年去國心。", "疎鐘寒郭晚，密雪水亭深。", "影逈鴻投渚，聲愁雀噪林。", "他鄉一尊酒，獨坐不成斟。"]'),
('605d770e-6091-4d79-b58a-9db0a5ebbd38','賦得風光草際浮','徐鉉','唐','唐诗','tang','','[]','宿露依芳草，春郊古陌旁。',72,'全唐诗/poet.tang.42000.json','["宿露依芳草，春郊古陌旁。", "風輕不盡偃，日早未晞陽。", "耿耿依平遠，離離入望長。", "映空無定彩，飄逕有餘光。", "颭若荷珠亂，紛如爝火颺。", "詩人多感物，凝思繞池塘。"]'),
('b3c67c71-418b-4a51-98bd-b5354aeef578','寒食成判官垂訪因贈','徐鉉','唐','唐诗','tang','','[]','常年寒食在京華，今歲清明在海涯。',64,'全唐诗/poet.tang.42000.json','["常年寒食在京華，今歲清明在海涯。", "遠巷蹋歌深夜月，隔牆吹管數枝花。", "鴛鸞得路音塵闊，鴻雁分飛道里賒。", "不是多情成二十，斷無人解訪貧家。"]'),
('f4d17183-9436-4666-89a5-852c6566379f','送客至城西望圖山因寄浙西府中','徐鉉','唐','唐诗','tang','','[]','牧叟鄒生笑語同，莫嗟江上聽秋風。',32,'全唐诗/poet.tang.42000.json','["牧叟鄒生笑語同，莫嗟江上聽秋風。", "君看逐客思鄉處，猶在圖山更向東。"]'),
('52b3e9a8-edb4-40e5-8b66-d9f6da5e0338','送寫真成處士入京','徐鉉','唐','唐诗','tang','','[]','傳神蹤迹本來高，澤畔形容媿彩毫。',32,'全唐诗/poet.tang.42000.json','["傳神蹤迹本來高，澤畔形容媿彩毫。", "京邑功臣多佇望，凌煙閣上莫辭勞。"]'),
('0d1ac3ce-1769-4518-acd5-3d784a3e4750','九日雨中','徐鉉','唐','唐诗','tang','','[]','茱萸房重雨霏微，去國逢秋此恨稀。',64,'全唐诗/poet.tang.42000.json','["茱萸房重雨霏微，去國逢秋此恨稀。", "目極暫登臺上望，心遙長向夢中歸。", "荃蘪路遠愁霜早，兄弟鄉遙羨雁飛。", "唯有多情一枝菊，滿杯顏色自依依。"]'),
('bf2900ff-217a-4079-bc32-fcef34e43937','寄外甥苗武仲','徐鉉','唐','唐诗','tang','','[]','放逐今來漲海邊，親情多在鳳臺前。',64,'全唐诗/poet.tang.42000.json','["放逐今來漲海邊，親情多在鳳臺前。", "且將聚散爲閑事，須信華枯是偶然。", "蟬噪疎林村倚郭，鳥飛殘照水連天。", "此中唯欠韓康伯，共對秋風詠數篇。"]'),
('2299b8df-e88f-499b-8c7b-803919b4ac1a','寄從兄憲兼示二弟','徐鉉','唐','唐诗','tang','','[]','別路吳將楚，離憂弟與兄。',48,'全唐诗/poet.tang.42000.json','["別路吳將楚，離憂弟與兄。", "斷雲驚晚吹，秋色滿孤城。", "信遠鴻初下，鄉遙月共明。", "一枝棲未穩，迴首望三京。"]'),
('9210e240-f81c-4d6c-bf3c-a2bf98164003','附書與鍾郎中因寄京妓越賓','徐鉉','唐','唐诗','tang','','[]','暮春橋下手封書，寄向江南問越姑。',32,'全唐诗/poet.tang.42000.json','["暮春橋下手封書，寄向江南問越姑。", "不道諸郎少歡笑，經年相別憶儂無。"]'),
('9e33a4dd-7498-415d-abaa-c2ad2c9e7b93','代鍾答','徐鉉','唐','唐诗','tang','','[]','一幅輕綃寄海濱，越姑長感昔時恩。',32,'全唐诗/poet.tang.42000.json','["一幅輕綃寄海濱，越姑長感昔時恩。", "欲知別後情多少，點點憑君看淚痕。"]'),
('5e853f33-883c-47c7-a8c9-4602a3e4b67a','亞元舍人不替深知猥貽佳作三篇清絕不敢輕酬因爲長歌聊以爲報未竟復得子喬校書示問故兼寄陳君庶資一笑耳','徐鉉','唐','唐诗','tang','','[]','海陵城裏春正月，海畔朝陽照殘雪。',384,'全唐诗/poet.tang.42000.json','["海陵城裏春正月，海畔朝陽照殘雪。", "城中有客獨登樓，遙望天邊白銀闕。", "白銀闕下何英英，雕鞍繡轂趨承明。", "閶門曉闢旌旗影，玉墀風細佩環聲。", "此處追飛皆俊彥，當年何事容疵賤。", "懷鉛晝坐紫微宮，焚香夜直明光殿。", "王言簡靜官司閑，朋好殷勤多往還。", "新亭風景如東洛，邙嶺林泉似北山。", "光陰暗度盃盂裏，職業未妨談笑間。", "有時邀賓復攜妓，造門不問都非是。", "酣歌呌笑驚四鄰，賦筆縱橫動千字。", "任他銀箭轉更籌，不怕金吾司夜吏。", "可憐諸貴賢且才，時情物望兩無猜。", "伊余獨稟狂狷性，褊量多言仍薄命。", "吞舟可漏豈無恩，負乘自貽非不幸。", "一朝削跡爲遷客，旦暮青雲千里隔。", "離鴻別雁各分飛，折柳攀花兩無色。", "盧龍渡口問迷津，瓜步山前送暮春。", "白沙江上曾行路，青林花落何紛紛。", "漢皇昔幸回中道，極目牛羊臥芳草。", "舊宅重游盡隟荒，故人相見多衰老。", "禪智寺，山光橋，風瑟瑟兮雨蕭蕭。", "行盃已醒殘夢斷，征途未極離魂消。", "海陵郡中陶太守，相逢本是隨行舊。"]'),
('6f60ae21-86a1-449f-a5f2-e9fe9bf116a7','送蒯司錄歸京','徐鉉','唐','唐诗','tang','','[]','早年聞有蒯先生，二十餘年道不行。',64,'全唐诗/poet.tang.42000.json','["早年聞有蒯先生，二十餘年道不行。", "抵掌曾論天下事，折腰猶悟俗人情。", "老還上國歡娛少，貧聚歸資結束輕。", "遷客臨流倍惆悵，冷風黃葉滿山城。"]'),
('dd9cce51-0b70-4f2f-abf9-61fa4a9626d0','聞查建州陷賊寄鍾郎中','徐鉉','唐','唐诗','tang','','[]','聞道將軍輕壯圖，螺江城下委犀渠。',64,'全唐诗/poet.tang.42000.json','["聞道將軍輕壯圖，螺江城下委犀渠。", "旌旗零落沉荒服，簪履蕭條返故居。", "皓首應全蘇武節，故人誰得李陵書。", "自憐放逐無長策，空使盧諶淚滿裾。"]'),
('b9a7c874-776d-4ff5-b801-8799fa267035','還過東都留守周公筵上贈座客','徐鉉','唐','唐诗','tang','','[]','賈生三載在長沙，故友相思道路賒。',64,'全唐诗/poet.tang.42000.json','["賈生三載在長沙，故友相思道路賒。", "已分終年甘寂寞，豈知今日還京華。", "麟符上相恩偏厚，隋苑留歡日欲斜。", "明旦江頭倍惆悵，遠山芳草映殘霞。"]'),
('b0d4d8fd-669d-448a-ab60-9e54e732e62f','送楊郎中唐員外奉使湖南','徐鉉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','江邊微雨柳條新，握節含香二使臣。',64,'全唐诗/poet.tang.42000.json','["江邊微雨柳條新，握節含香二使臣。", "兩綬對懸雲夢日，方舟齊汎洞庭春。", "今朝草木逢新律，昨日山川滿戰塵。", "同是多情懷古客，不妨爲賦弔靈均。"]'),
('bdbe6b5c-d268-424a-9223-502bbcb2727b','表弟包潁見寄','徐鉉','唐','唐诗','tang','','[]','常思帝里奉交親，別後光陰屈指頻。',64,'全唐诗/poet.tang.42000.json','["常思帝里奉交親，別後光陰屈指頻。", "蘭佩却歸綸閣下，荆枝猶寄楚江濱。", "十程山水勞幽夢，滿院煙花醉別人。", "料得此生強健在，會須重賞昔年春。"]'),
('376402d1-4dce-4044-972b-fb66b355f0c4','寄蕭給事','徐鉉','唐','唐诗','tang','','[]','危言危行古時人，歸向西山臥白雲。',64,'全唐诗/poet.tang.42000.json','["危言危行古時人，歸向西山臥白雲。", "買宅尚尋徐處士，餐霞終訪許真君。", "容顏別後應如故，詩詠年來更不聞。", "今日城中春又至，落梅愁緒共紛紛。"]'),
('006330ba-c3c2-46e4-9645-ac915a200272','賦石奉送鍾德林少尹員外','徐鉉','唐','唐诗','tang','','[]','我愛他山石，中含絕代珍。',48,'全唐诗/poet.tang.42000.json','["我愛他山石，中含絕代珍。", "煙披寒落落，沙淺靜磷磷。", "翠色辭文陛，清聲出泗濱。", "扁舟載歸去，知是汎槎人。"]'),
('9547f73e-b5a6-44d8-bf15-4fd3bd7387a6','贈泰州掾令狐克己','徐鉉','唐','唐诗','tang','','[]','念子才多命且奇，亂中拋擲少年時。',64,'全唐诗/poet.tang.42000.json','["念子才多命且奇，亂中拋擲少年時。", "深藏七澤衣如雪，却見中朝鬢似絲。", "舊德在人終遠大，扁舟爲吏莫推辭。", "孤芳自愛凌霜處，詠取文公白菊詩。"]'),
('939561ce-a831-4b31-891a-a51744ed3d7b','送荻栽與秀才朱觀','徐鉉','唐','唐诗','tang','','[]','羨子清吟處，茅齋面碧流。',48,'全唐诗/poet.tang.42000.json','["羨子清吟處，茅齋面碧流。", "解憎蓮豔俗，唯欠荻花幽。", "鷺立低枝晚，風驚折葉秋。", "贈君須種取，不必樹忘憂。"]'),
('f3d65101-8a2c-4478-99d3-8d0fdd17083a','使浙西先寄獻燕王侍中','徐鉉','唐','唐诗','tang','','[]','京江風靜喜乘流，極目遙瞻萬歲樓。',64,'全唐诗/poet.tang.42000.json','["京江風靜喜乘流，極目遙瞻萬歲樓。", "喜氣蘢葱甘露晚，水煙波淡海門秋。", "五年不見鸞臺長，明日將陪兔苑遊。", "欲問平臺門下吏，相君還許吐茵不。"]'),
('27ab48ec-85c4-42b4-8faf-f9f2ef73871e','常州驛中喜雨','徐鉉','唐','唐诗','tang','','[]','颯颯旱天雨，涼風一夕迴。',48,'全唐诗/poet.tang.42000.json','["颯颯旱天雨，涼風一夕迴。", "遠尋南畝去，細入驛亭來。", "蓑唱牛初牧，漁歌棹正開。", "盈庭頓無事，歸思酌金罍。"]'),
('6f501519-b77a-464a-88a6-4e0ba7e6d220','驛中七夕','徐鉉','唐','唐诗','tang','','[]','七夕雨初霽，行人正憶家。',48,'全唐诗/poet.tang.42000.json','["七夕雨初霽，行人正憶家。", "江天望河漢，水館折蓮花。", "獨坐涼何甚，微吟月易斜。", "今年不乞巧，鈍拙轉堪嗟。"]'),
('2c222a47-2d1f-4447-b497-8a9fc371a3a6','贈浙西顧推官','徐鉉','唐','唐诗','tang','','[]','盛府賓寮八十餘，閉門高臥興無如。',64,'全唐诗/poet.tang.42000.json','["盛府賓寮八十餘，閉門高臥興無如。", "梁王苑裏相逢早，潤浦城中得信疎。", "狼藉盃盤重會面，風流才調一如初。", "願君百歲猶強健，他日相尋隱士廬。"]'),
('654f1878-571a-4b2d-ad6d-d5b273eba014','贈浙西妓亞仙','徐鉉','唐','唐诗','tang','','[]','翠黛嚬如怨，朱顏醉更春。',48,'全唐诗/poet.tang.42000.json','["翠黛嚬如怨，朱顏醉更春。", "占將南國貌，惱殺別家人。", "粉汗沾巡盞，花鈿逐舞茵。", "明朝綺窗下，離恨兩殷勤。"]'),
('9e9cd727-1956-4b3d-b227-a095fd1b64a9','迴至瓜洲獻侍中','徐鉉','唐','唐诗','tang','','[]','紫微垣裏舊賓從，來向吳門謁府公。',64,'全唐诗/poet.tang.42000.json','["紫微垣裏舊賓從，來向吳門謁府公。", "奉使謬持嚴助節，登門初識魯王宮。", "笙歌隱隱違離後，煙水茫茫悵望中。", "日暮瓜洲江北岸，兩行情淚滴西風。"]'),
('d136f3c0-604e-4635-8314-4fbb98060ef3','邵伯埭下寄高郵陳郎中','徐鉉','唐','唐诗','tang','','[]','故人相別動經年，候館相逢倍慘然。',64,'全唐诗/poet.tang.42000.json','["故人相別動經年，候館相逢倍慘然。", "顧我飲冰難輟櫂，感君扶病爲開筵。", "河灣水淺翹秋鷺，柳岸風微噪暮蟬。", "欲識酒醒魂斷處，謝公祠畔客亭前。"]'),
('b1ed858c-45a5-47c8-a67b-874c1a637bc6','謫居舒州累得韓高二舍人書作此寄之','徐鉉','唐','唐诗','tang','','[]','三峰煙靄碧臨谿，中有騷人理釣絲。',64,'全唐诗/poet.tang.42000.json','["三峰煙靄碧臨谿，中有騷人理釣絲。", "會友少於分袂日，謫居多却在朝時。", "丹心歷歷吾終信，俗慮悠悠爾不知。", "珍重韓君與高子，殷勤書札寄相思。"]'),
('3a8b61e2-dd27-44e4-aa4c-62181765cd71','和張先輩見寄二首 一','徐鉉','唐','唐诗','tang','','[]','去國離羣擲歲華，病容憔悴媿丹砂。',64,'全唐诗/poet.tang.42000.json','["去國離羣擲歲華，病容憔悴媿丹砂。", "谿連舍下衣長潤，山帶城邊日易斜。", "幾處垂鉤依野岸，有時披褐到鄰家。", "故人書札頻相慰，誰道西京道路賒。"]'),
('29db4d85-612a-4333-89f8-bb0b4d43121e','和張先輩見寄二首 二','徐鉉','唐','唐诗','tang','','[]','清時淪放在山州，邛竹紗巾處處游。',64,'全唐诗/poet.tang.42000.json','["清時淪放在山州，邛竹紗巾處處游。", "野日蒼茫悲鵩舍，水風陰濕弊貂裘。", "雞鳴候旦寧辭晦，松節凌霜幾換秋。", "兩首新詩千里道，感君情分獨知丘。"]'),
('abbe850b-cf58-4496-b6d8-2ade63a84335','印秀才至舒州見尋別後寄詩依韻和','徐鉉','唐','唐诗','tang','','[]','羈游白社身雖屈，高步辭場道不卑。',64,'全唐诗/poet.tang.42000.json','["羈游白社身雖屈，高步辭場道不卑。", "投分共爲知我者，相尋多媿謫居時。", "離懷耿耿年來夢，厚意勤勤別後詩。", "今日谿邊正相憶，雪晴山秀柳絲垂。"]'),
('b0bf247f-1344-48e2-98b6-d1fec55a773e','行園樹','徐鉉','唐','唐诗','tang','','[]','松節凌霜久，蓬根逐吹頻。',24,'全唐诗/poet.tang.42000.json','["松節凌霜久，蓬根逐吹頻。", "羣生各有性，桃李但爭春。"]'),
('44967ba5-12cd-40f7-8c73-af62c82a5e89','題雷公井','徐鉉','唐','唐诗','tang','','[]','揜靄愚公谷，蕭寥羽客家。',24,'全唐诗/poet.tang.42000.json','["揜靄愚公谷，蕭寥羽客家。", "俗人知處所，應爲有桃花。"]'),
('1a6cd84a-f7e8-43ee-a575-f7481b7c45f2','送彭秀才','徐鉉','唐','唐诗','tang','','[]','賈生去國已三年，短褐閑行皖水邊。',64,'全唐诗/poet.tang.42000.json','["賈生去國已三年，短褐閑行皖水邊。", "盡日野雲生舍下，有時京信到門前。", "無人與和投湘賦，媿子來浮訪戴船。", "滿袖新詩好迴去，莫隨騷客醉林泉。"]'),
('ba3354a0-2b2b-4b3a-b404-fbff88ca15b6','移饒州別周使君','徐鉉','唐','唐诗','tang','','[]','正憐東道感賢侯，何幸南冠脫楚囚。',64,'全唐诗/poet.tang.42000.json','["正憐東道感賢侯，何幸南冠脫楚囚。", "睆伯臺前收別宴，喬公亭下艤行舟。", "四年去國身將老，百郡徵兵主尚憂。", "更向鄱陽湖上去，青衫憔悴淚交流。"]'),
('270d19d7-e7b8-4b8a-b337-4d4726983ada','避難東歸依韻和黃秀才見寄','徐鉉','唐','唐诗','tang','','[]','慼慼逢人問所之，東流相送向京畿。',64,'全唐诗/poet.tang.42000.json','["慼慼逢人問所之，東流相送向京畿。", "自甘逐客紉蘭佩，不料平民著戰衣。", "樹帶荒村春冷落，江澄霽色霧霏微。", "時危道喪無才術，空手徘徊不忍歸。"]'),
('066e5f06-6d53-47d1-81f8-982462f0281d','酬郭先輩','徐鉉','唐','唐诗','tang','','[]','太原郭夫子，行高文炳蔚。',192,'全唐诗/poet.tang.42000.json','["太原郭夫子，行高文炳蔚。", "弱齡負世譽，一舉游月窟。", "仙籍第三人，時人故稱屈。", "昔余吏西省，傾蓋名籍籍。", "及我竄羣舒，向風心鬱鬱。", "歸來暮江上，雲霧一披拂。", "雷雨不下施，猶作池中物。", "念君介然氣，感時思奮發。", "示我數篇文，與古爭馳突。", "綵褥粲英華，理深刮肌骨。", "古詩尤精奧，史論皆宏拔。", "舉此措諸民，何憂民不活。", "吁嗟吾道薄，與世長迂闊。", "顧我徒有心，數奇身正絀。", "論兵屬少年，經國須儒術。", "夫子無自輕，蒼生正愁疾。"]'),
('b4ae9ca1-f1ce-42db-aa7f-c30c3e5ab987','和集賢鍾郎中','徐鉉','唐','唐诗','tang','','[]','石渠冊府神仙署，當用明朝第一人。',64,'全唐诗/poet.tang.42000.json','["石渠冊府神仙署，當用明朝第一人。", "腰下別懸新印綬，座中皆是故交親。", "龍池樹色供清景，浴殿香風接近鄰。", "從此翻飛應更遠，徧尋三十六天春。"]'),
('8124d3a7-5ff6-47df-a138-396462fe3273','送劉山陽','徐鉉','唐','唐诗','tang','','[]','舊族知名士，朱衣宰楚城。',48,'全唐诗/poet.tang.42000.json','["舊族知名士，朱衣宰楚城。", "所嗟吾道薄，豈是主恩輕。", "戰鼓何時息，儒冠獨自行。", "此心多感激，相送若爲情。"]'),
('c6fe6f55-813e-4893-84b8-418a356c69ef','題伏龜山北隅','徐鉉','唐','唐诗','tang','','[]','茲山信岑寂，陰崖積蒼翠。',72,'全唐诗/poet.tang.42000.json','["茲山信岑寂，陰崖積蒼翠。", "水石何必多，宛有千巖意。", "孰知近人境，旦暮含佳氣。", "池影搖輕風，林光澹新霽。", "支頤藉芳草，自足忘世事。", "未得歸去來，聊爲宴居地。"]'),
('a0592e7d-3939-4219-be73-9eb117481305','送黃梅江明府','徐鉉','唐','唐诗','tang','','[]','封疆多難正經綸，臺閣如何不用君。',64,'全唐诗/poet.tang.42000.json','["封疆多難正經綸，臺閣如何不用君。", "江上又勞爲小邑，篋中徒自有雄文。", "書生膽氣人誰信，遠俗歌謠主不聞。", "一首新詩無限意，再三吟味向秋雲。"]'),
('748d0d2b-0254-492c-9667-6a39b76a600b','詠梅子真送郭先輩','徐鉉','唐','唐诗','tang','','[]','忠臣本愛君，仁人本愛民。',120,'全唐诗/poet.tang.42000.json','["忠臣本愛君，仁人本愛民。", "寧知貴與賤，豈計名與身。", "梅生爲一尉，獻疏來君門。", "君門深萬里，金虎重千鈞。", "向永且不用，況復論子真。", "拂衣遂長往，高節邈無鄰。", "至今仙籍中，謂之梅真人。", "郭生負逸氣，百代繼遺塵。", "進退生自知，得喪吾不陳。", "斯民苟有幸，期子一朝伸。"]'),
('27f0295b-9f57-458e-b6a1-036fe9800ea0','和蕭郎中午日見寄','徐鉉','唐','唐诗','tang','','[]','細雨輕風采藥時，褰簾隱几更何爲。',64,'全唐诗/poet.tang.42000.json','["細雨輕風采藥時，褰簾隱几更何爲。", "豈知澤畔紉蘭客，來赴城中角黍期。", "多罪靜思如剉蘗，赦書纔聽似含飴。", "謝公制勝常閑暇，願接西州敵手棊。"]'),
('86c858b5-6d73-4511-bd0e-c776c13e52e1','送黃秀才姑孰辟命','徐鉉','唐','唐诗','tang','','[]','世亂離情苦，家貧色養難。',48,'全唐诗/poet.tang.42000.json','["世亂離情苦，家貧色養難。", "水雲孤櫂去，風雨暮春寒。", "幕府才方急，騷人淚未乾。", "何時王道泰，萬里看鵬摶。"]'),
('650f35ae-fd1e-4d6a-b78f-299069daaf9e','送王四十五歸東都','徐鉉','唐','唐诗','tang','','["\u79bb\u522b", "\u9001\u522b"]','海內兵方起，離筵淚易垂。',48,'全唐诗/poet.tang.42000.json','["海內兵方起，離筵淚易垂。", "憐君負米去，惜此落花時。", "想憶看來信，相寬指後期。", "殷勤手中柳，此是向南枝。"]'),
('5ee2ecbf-37be-46f3-bb64-c4116751fd03','和太常蕭少卿近郊馬上偶吟','徐鉉','唐','唐诗','tang','','[]','田園經雨綠分畦，飛蓋閑行九里堤。',64,'全唐诗/poet.tang.42000.json','["田園經雨綠分畦，飛蓋閑行九里堤。", "拂袖清風塵不起，滿川芳草路如迷。", "林開始覺晴天逈，潮上初驚浦岸齊。", "怪得仙郎詩句好，斷霞殘照遠山西。"]'),
('c411f8a5-f71e-4e55-b8e1-8bd1309cdfc6','又和太常蕭少卿近郊馬上偶吟','徐鉉','唐','唐诗','tang','','[]','抱甕何人灌藥畦，金銜爲爾駐平堤。',64,'全唐诗/poet.tang.42000.json','["抱甕何人灌藥畦，金銜爲爾駐平堤。", "村橋野店景無限，綠水晴天思欲迷。", "橫笛乍隨輕吹斷，歸帆疑與遠山齊。", "鳳城迴望真堪畫，萬戶千門蔣嶠西。"]'),
('7f5c15d7-fb51-4e1e-ab09-b2a557909a2e','拋毬樂辭二首 一','徐鉉','唐','唐诗','tang','','[]','歌舞送飛毬，今觥碧玉籌。',36,'全唐诗/poet.tang.42000.json','["歌舞送飛毬，今觥碧玉籌。", "管弦桃李月，簾幕鳳凰樓。", "一笑千場醉，浮生任白頭。"]'),
('af044393-436b-471b-9b89-52f3d026fa20','拋毬樂辭二首 二','徐鉉','唐','唐诗','tang','','[]','灼灼傳花枝，紛紛度畫旗。',36,'全唐诗/poet.tang.42000.json','["灼灼傳花枝，紛紛度畫旗。", "不知紅燭下，照見彩毬飛。", "借勢因期尅，巫山暮雨歸。"]'),
('5659dd40-2e53-4060-8051-18f6a9c76a5f','離歌辭五首 一','徐鉉','唐','唐诗','tang','','[]','莫折紅芳樹，但知盡意看。',24,'全唐诗/poet.tang.42000.json','["莫折紅芳樹，但知盡意看。", "狂風幸無意，那忍折教殘。"]'),
('bca536cb-16fe-464e-85d5-4f517ad8a4d5','離歌辭五首 二','徐鉉','唐','唐诗','tang','','[]','朝日城南路，旌旗照綠蕪。',24,'全唐诗/poet.tang.42000.json','["朝日城南路，旌旗照綠蕪。", "使君何處去，桑下覓羅敷。"]'),
('4dc8e23e-cb42-4c1b-b3f4-61cd30df3cf1','離歌辭五首 三','徐鉉','唐','唐诗','tang','','[]','事與年俱往，情將分共深。',24,'全唐诗/poet.tang.42000.json','["事與年俱往，情將分共深。", "莫驚容鬢改，只是舊時心。"]'),
('2d4cbe1f-fccc-473e-b9d4-0b1954548ca7','離歌辭五首 四','徐鉉','唐','唐诗','tang','','[]','暫別勞相送，佳期願莫違。',24,'全唐诗/poet.tang.42000.json','["暫別勞相送，佳期願莫違。", "朱顏不須老，留取待郎歸。"]'),
('fd77bb34-b7f5-41ff-8768-bdc0ee0f02a5','離歌辭五首 五','徐鉉','唐','唐诗','tang','','[]','拂匣收珠佩，迴燈拭薄妝。',24,'全唐诗/poet.tang.42000.json','["拂匣收珠佩，迴燈拭薄妝。", "莫嫌春夜短，匹似楚襄王。"]'),
('ce1ab385-ac9b-4c73-b63a-b1389c6222f2','夢游三首 一','徐鉉','唐','唐诗','tang','','[]','魂夢悠揚不奈何，夜來還在故人家。',64,'全唐诗/poet.tang.42000.json','["魂夢悠揚不奈何，夜來還在故人家。", "香濛蠟燭時時暗，戶映屏風故故斜。", "檀的慢調銀字管，雲鬟低綴折枝花。", "天明又作人間別，洞口春深道路賒。"]'),
('7e1d1b9f-cd14-4848-b3c3-0404e56a2e22','夢游三首 二','徐鉉','唐','唐诗','tang','','[]','繡幌銀屏杳靄間，若非魂夢到應難。',64,'全唐诗/poet.tang.42000.json','["繡幌銀屏杳靄間，若非魂夢到應難。", "窗前人靜偏宜夜，戶內春濃不識寒。", "蘸甲遰觴纖似玉，含詞忍笑膩於檀。", "錦書若要知名字，滿縣花開不姓潘。"]'),
('613d1b85-e790-4ad7-89b2-65bfafd5ec41','夢游三首 三','徐鉉','唐','唐诗','tang','','[]','南國佳人字玉兒，芙蓉雙臉遠山眉。',64,'全唐诗/poet.tang.42000.json','["南國佳人字玉兒，芙蓉雙臉遠山眉。", "仙郎有約長相憶，阿母何猜不得知。", "夢裏行雲還倏忽，暗中攜手乍疑遲。", "因思別後閑窗下，織得迴文幾首詩。"]'),
('894ac887-5ecf-446e-b51c-a8ea2448e2b9','和蕭少卿見慶新居','徐鉉','唐','唐诗','tang','','[]','湘浦懷沙已不疑，京城賜第豈前期。',64,'全唐诗/poet.tang.42000.json','["湘浦懷沙已不疑，京城賜第豈前期。", "鼓聲到晚知坊遠，山色來多與靜宜。", "簪屨尚應憐故物，稻粱空自媿華池。", "新詩問我偏饒思，還念鷦鷯得一枝。"]'),
('1478da3a-f449-4021-bbf0-890eb06c3700','又和蕭少卿見慶新居','徐鉉','唐','唐诗','tang','','[]','驚蓬偶駐知多幸，斷雁重聯愜素期。',64,'全唐诗/poet.tang.42000.json','["驚蓬偶駐知多幸，斷雁重聯愜素期。", "當戶小山如舊識，上牆幽蘚最相宜。", "清風不去因栽竹，隙地無多也鑿池。", "更喜良鄰有嘉樹，綠陰分得近南枝。"]'),
('7650d501-76e6-4080-bb06-771540b037a6','送勳道人之建安','徐鉉','唐','唐诗','tang','','[]','下國兵方起，君家義獨聞。',48,'全唐诗/poet.tang.42000.json','["下國兵方起，君家義獨聞。", "若爲輕世利，歸去臥溪雲。", "挂席衝嵐翠，攜筇破蘚紋。", "離情似霜葉，江上正紛紛。"]'),
('4b8430b1-76b3-4779-a2f2-2103b5a99c4e','送許郎中歙州判官兼黟縣','徐鉉','唐','唐诗','tang','','[]','嘗聞黟縣似桃源，況是優游冠玳筵。',64,'全唐诗/poet.tang.42000.json','["嘗聞黟縣似桃源，況是優游冠玳筵。", "遺愛非遙應臥理，祖風猶在好尋仙。", "朝衣舊識熏香史，祿米初營種秫田。", "大抵宦游須自適，莫辭離別二三年。"]'),
('1801a5da-943d-4549-8a89-8eb37000e753','送彭秀才南游','徐鉉','唐','唐诗','tang','','[]','問君孤櫂去何之，玉笥春風楚水西。',64,'全唐诗/poet.tang.42000.json','["問君孤櫂去何之，玉笥春風楚水西。", "山上斷雲分翠靄，林間晴雲入澄溪。", "琴心酒趣神相會，道士仙童手共攜。", "他日時清更隨計，莫如劉阮洞中迷。"]'),
('b26bb3dd-61a1-4f44-9a5e-105ef3eb87e1','和明上人除夜見寄','徐鉉','唐','唐诗','tang','','[]','酌酒圍爐久，愁襟默自增。',48,'全唐诗/poet.tang.42000.json','["酌酒圍爐久，愁襟默自增。", "長年逢歲暮，多病見兵興。", "夜色開庭燎，寒威入硯冰。", "湯師無別念，吟坐一燈凝。"]'),
('f08d1d36-3600-43bf-864a-647a95ac2ef2','正初和鄂州邊郎中見寄','徐鉉','唐','唐诗','tang','','[]','潦倒含香客，淒涼賦鵩人。',48,'全唐诗/poet.tang.42000.json','["潦倒含香客，淒涼賦鵩人。", "未能全卷舌，終擬學垂綸。", "故友暌離久，音書問訊頻。", "相思俱老大，又見一年新。"]'),
('fe519711-c1b9-4657-addb-f61a1fc8c477','送劉司直出宰','徐鉉','唐','唐诗','tang','','[]','之子有雄文，風標秀不羣。',48,'全唐诗/poet.tang.42000.json','["之子有雄文，風標秀不羣。", "低飛從墨綬，逸志在青雲。", "柳色臨流動，春光到縣分。", "賢人多靜理，未爽醉醺醺。"]'),
('198f1dc7-b7a2-4867-bc5d-7966800a2c10','送從兄赴臨川幕','徐鉉','唐','唐诗','tang','','[]','梁王籍寵就東藩，還召鄒枚坐兔園。',64,'全唐诗/poet.tang.42000.json','["梁王籍寵就東藩，還召鄒枚坐兔園。", "今日好論天下事，昔年同受主人恩。", "石頭城下春潮滿，金柅亭邊綠樹繁。", "唯有音書慰離別，一盃相送別無言。"]'),
('c2ef0122-3504-49b1-a9f4-3a610e72f88f','送龔員外赴江州幕','徐鉉','唐','唐诗','tang','','[]','煩君更上築金臺，世難民勞藉俊才。',64,'全唐诗/poet.tang.42000.json','["煩君更上築金臺，世難民勞藉俊才。", "自有聲名馳羽檄，不妨談笑奉尊罍。", "元規樓迥清風滿，匡俗山春畫障開。", "莫忘故人離別恨，海潮迴處寄書來。"]'),
('4bbf3632-36d7-433e-ae3a-6fd8d54d24dd','送朱先輩尉廬陵','徐鉉','唐','唐诗','tang','','[]','我重朱夫子，依然見古人。',48,'全唐诗/poet.tang.42000.json','["我重朱夫子，依然見古人。", "成名無媿色，得祿及慈親。", "莫歎官資屈，寧論活計貧。", "平生心氣在，終任靜邊塵。"]'),
('436420ba-25e7-4b51-be89-b1b9565f9678','送鍾德林郎中學士赴東府詩 得酒','徐鉉','唐','唐诗','tang','','[]','酌此盃中物，茱萸滿把秋。',48,'全唐诗/poet.tang.42000.json','["酌此盃中物，茱萸滿把秋。", "今朝將送別，他日是忘憂。", "世亂方多事，年加易得愁。", "政成頻一醉，亦未減風流。"]'),
('c21c26c8-2b73-411f-a006-2a8044065681','送陳先生之洪井寄蕭少卿','徐鉉','唐','唐诗','tang','','[]','聞君仙袂指洪厓，我憶情人別路賒。',64,'全唐诗/poet.tang.42000.json','["聞君仙袂指洪厓，我憶情人別路賒。", "知有歡娛游楚澤，更無書札到京華。", "雲開驛閣連江靜，春滿西山倚漢斜。", "此處相逢應見問，爲言搔首望龍沙。"]'),
('4837f8c0-725d-44ff-8056-440f706860d5','送龔明府九江歸寧','徐鉉','唐','唐诗','tang','','[]','茂宰隳官去，扁舟著綵衣。',48,'全唐诗/poet.tang.42000.json','["茂宰隳官去，扁舟著綵衣。", "湓城春酒熟，匡阜野花稀。", "解纜垂楊綠，開帆宿鷺飛。", "一朝吾道泰，還逐落潮歸。"]'),
('fc824129-49cd-4835-9a1c-75b9efd09e92','和江西蕭少卿見寄二首 一','徐鉉','唐','唐诗','tang','','[]','亡羊岐路媿司南，二紀窮通聚散三。',64,'全唐诗/poet.tang.42000.json','["亡羊岐路媿司南，二紀窮通聚散三。", "老去何妨從笑傲，病來看欲嬾朝參。", "離腸似線常憂斷，世態如湯不可探。", "珍重加餐省思慮，時時斟酒壓山嵐。"]'),
('41380de0-b83c-4100-9f80-9d7c6c554dbd','和江西蕭少卿見寄二首 二','徐鉉','唐','唐诗','tang','','[]','身遙上國三千里，名在朝中二十春。',64,'全唐诗/poet.tang.42000.json','["身遙上國三千里，名在朝中二十春。", "金印不須辭入幕，麻衣曾此歎迷津。", "卷舒由我真齊物，憂喜忘心即養神。", "世路風波自飜覆，虛舟無計得沉淪。"]'),
('3811f14a-e515-4812-bbdd-c002ef38fced','送薛少卿赴青陽','徐鉉','唐','唐诗','tang','','[]','我愛陶靖節，吏隱從弦歌。',132,'全唐诗/poet.tang.42000.json','["我愛陶靖節，吏隱從弦歌。", "我愛費徵君，高臥歸九華。", "清風激頹波，來者無以加。", "我志兩不遂，漂淪浩無涯。", "數奇時且亂，此圖今愈賒。", "賢哉薛夫子，高舉凌晨霞。", "安民即是道，投足皆爲家。", "功名與權位，悠悠何用誇。", "攜朋出遠郊，酌酒藉平沙。", "雲收遠天靜，江闊片帆斜。", "離懷與企羨，南望長咨嗟。"]'),
('1700c6ac-d3ea-4c25-a2a6-a30b311a9a30','送高起居之涇縣','徐鉉','唐','唐诗','tang','','[]','右史罷朝歸，之官句水湄。',132,'全唐诗/poet.tang.42000.json','["右史罷朝歸，之官句水湄。", "別我行千里，送君傾一巵。", "酒罷長歎息，此歎君應悲。", "亂中吾道薄，卿族舊人稀。", "胡爲佩銅墨，去此白玉墀。", "吏事豈所堪，民病何可醫。", "藏用清其心，此外慎勿爲。", "縣郭有佳境，千峰谿水西。", "雲樹杳迴合，巖巒互蔽虧。", "彈琴坐其中，世事吾不知。", "時時寄書札，以慰長相思。"]'),
('979841ff-c472-4438-b55f-d4684c8d8a1a','宿茅山寄舍弟','徐鉉','唐','唐诗','tang','','[]','茅許稟靈氣，一家同上賓。',48,'全唐诗/poet.tang.42000.json','["茅許稟靈氣，一家同上賓。", "仙山空有廟，舉世更無人。", "獨往誠違俗，浮名亦累真。", "當年各自勉，雲洞鎮長春。"]'),
('48e7b842-bbb5-4eeb-a1ed-9034324d098d','晚憇白鶴廟寄句容張少府','徐鉉','唐','唐诗','tang','','[]','日入林初靜，山空暑更寒。',48,'全唐诗/poet.tang.42000.json','["日入林初靜，山空暑更寒。", "泉鳴細巖竇，鶴淚眇雲端。", "拂榻安棊局，焚香戴道冠。", "望君殊不見，終夕憑欄干。"]'),
('52e35538-5a11-4789-a967-de60c3fa7ab1','題紫陽觀','徐鉉','唐','唐诗','tang','','[]','南朝名士富仙才，追步東卿遂不迴。',64,'全唐诗/poet.tang.42000.json','["南朝名士富仙才，追步東卿遂不迴。", "丹井自深桐暗老，祠宮長在鶴頻來。", "巖邊桂樹攀仍倚，洞口桃花落復開。", "惆悵霓裳太平事，一函真跡鎖昭臺。"]'),
('8e582ea3-2c9b-4c36-9f8c-5eb1324077ea','贈奚道士','徐鉉','唐','唐诗','tang','','[]','先生曾有洞天期，猶傍天壇摘紫芝。',64,'全唐诗/poet.tang.42000.json','["先生曾有洞天期，猶傍天壇摘紫芝。", "處世自能心混沌，全真誰見德支離。", "玉霄塵閉人長在，全鼎功成俗未知。", "他日飆輪謁茅許，願同雞犬去相隨。"]'),
('04e02701-4756-4b1f-a48c-606055d6ec56','題碧巖亭贈孫尊師','徐鉉','唐','唐诗','tang','','[]','絕境何人識，高亭萬象含。',96,'全唐诗/poet.tang.42000.json','["絕境何人識，高亭萬象含。", "凭軒臨樹杪，送目極天南。", "積靄生泉洞，歸雲鎖石龕。", "丹霞披翠巘，白鳥帶晴嵐。", "仙去留虛室，龍歸漲碧潭。", "幽巖君獨愛，玄味我曾耽。", "世上愁何限，人間事久諳。", "終須脫羈鞅，來此會空談。"]'),
('03a32e51-7918-4afc-9df7-ade594eece09','題白鶴廟','徐鉉','唐','唐诗','tang','','[]','平生心事向玄關，一入仙鄉似舊山。',64,'全唐诗/poet.tang.42000.json','["平生心事向玄關，一入仙鄉似舊山。", "白鶴淚空晴眇眇，丹沙流澗暮潺潺。", "嘗嗟多病嫌中藥，擬問真經乞小還。", "滿洞煙霞互陵亂，何峰臺榭是蕭閑。"]'),
('0f73cc22-385d-440f-97e6-117507a4313e','步虛詞五首 一','徐鉉','唐','唐诗','tang','','[]','氣爲還元正，心由抱一靈。',48,'全唐诗/poet.tang.42000.json','["氣爲還元正，心由抱一靈。", "凝神歸罔象，飛步入青冥。", "整服乘三素，旋綱躡九星。", "瓊章開後學，稽首奉真經。"]'),
('5a2a1af4-2dea-420b-bd1e-f67d7ffaa6f1','步虛詞五首 二','徐鉉','唐','唐诗','tang','','[]','天帝黃金闕，真人紫錦書。',48,'全唐诗/poet.tang.42000.json','["天帝黃金闕，真人紫錦書。", "霓裳紛蔽景，羽服迥凌虛。", "白鶴能爲使，班麟解駕車。", "靈符終願借，轉共世情疎。"]'),
('f650df59-7c25-47c7-a5b9-740660d8a8cb','步虛詞五首 三','徐鉉','唐','唐诗','tang','','[]','聖主過幽谷，虛皇在蘂宮。',48,'全唐诗/poet.tang.42000.json','["聖主過幽谷，虛皇在蘂宮。", "五千宗物母，七字祕神童。", "世上金壺遠，人間玉籥空。", "唯餘養身法，修此與天通。"]'),
('9a1e41a2-28af-4124-abf5-2a1863a84a69','步虛詞五首 四','徐鉉','唐','唐诗','tang','','[]','何處求玄解，人間有洞天。',48,'全唐诗/poet.tang.42000.json','["何處求玄解，人間有洞天。", "勤行皆是道，謫下尚爲仙。", "蔽景乘朱鳳，排虛駕紫煙。", "不嫌園吏傲，願在玉宸前。"]'),
('0fb969ca-d33e-4959-a258-1537421368a3','步虛詞五首 五','徐鉉','唐','唐诗','tang','','[]','三素霏霏遠，盟威凜凜寒。',48,'全唐诗/poet.tang.42000.json','["三素霏霏遠，盟威凜凜寒。", "火鈴空滅沒，星斗曉闌干。", "佩響流虛殿，爐煙在醮壇。", "蕭寥不可極，驂駕上雲端。"]'),
('15319d9e-68fd-4e8e-bfed-683c5898c1e1','留題仙觀','徐鉉','唐','唐诗','tang','','[]','瑤壇醮罷晚雲開，羽客分飛俗士迴。',32,'全唐诗/poet.tang.42000.json','["瑤壇醮罷晚雲開，羽客分飛俗士迴。", "爲報移文不須勒，未曾游處待重來。"]'),
('56249038-41cc-4204-b4da-beafc26a9010','和陳洗馬山莊新泉','徐鉉','唐','唐诗','tang','','[]','已開山館待抽簪，更要巖泉欲洗心。',64,'全唐诗/poet.tang.42000.json','["已開山館待抽簪，更要巖泉欲洗心。", "常被松聲迷細韻，忽流花片落高岑。", "便疏淺瀨穿莎徑，始有清光映竹林。", "何日煎茶醞香酒，沙邊同聽暝猨吟。"]'),
('2c196cad-4746-4204-8e01-9e73b9ed11e0','奉和七夕應令','徐鉉','唐','唐诗','tang','','[]','今宵星漢共晶光，應笑羅敷嫁侍郎。',64,'全唐诗/poet.tang.42000.json','["今宵星漢共晶光，應笑羅敷嫁侍郎。", "斗柄易傾離恨促，河流不盡後期長。", "靜聞天籟疑鳴佩，醉折荷花想豔妝。", "誰見宣猷堂上宴，一篇清韻振金鐺。"]'),
('0473eff7-13cb-446a-a88c-efa71721c4d1','又和八日','徐鉉','唐','唐诗','tang','','[]','微雲疎雨淡新秋，曉夢依稀十二樓。',64,'全唐诗/poet.tang.42000.json','["微雲疎雨淡新秋，曉夢依稀十二樓。", "故作別離應有以，擬延更漏共無由。", "那教人世長多恨，未必天仙不解愁。", "博望苑中殘酒醒，香風佳氣獨遲留。"]'),
('49bbcbdc-447f-46d3-a949-1cf5fb0491ab','和印先輩及第後獻座主朱舍人郊居之作','徐鉉','唐','唐诗','tang','','[]','成名郊外掩柴扉，樹影蟬聲共息機。',67,'全唐诗/poet.tang.42000.json','["成名郊外掩柴扉，樹影蟬聲共息機。", "積雨暗封青蘚徑，好風輕透白{糹朿}衣。", "嘉魚始賦人爭誦，荆玉頻收國自肥。", "獨坐公廳正煩暑，喜吟新詠見玄微。"]'),
('917cea25-0fcd-4642-aa95-efb0627c6636','和致仕張尚書新創道院','徐鉉','唐','唐诗','tang','','[]','梓澤成新致，金丹有舊情。',48,'全唐诗/poet.tang.42000.json','["梓澤成新致，金丹有舊情。", "挂冠朝睡足，隱几暮江清。", "藥圃分輕綠，松窗起細聲。", "養高寧厭病，默坐對諸生。"]'),
('3949a1fe-943b-4534-8388-18e594f57c80','和尉遲贊善秋暮僻居','徐鉉','唐','唐诗','tang','','[]','登高節物最堪憐，小嶺疎林對檻前。',64,'全唐诗/poet.tang.42000.json','["登高節物最堪憐，小嶺疎林對檻前。", "輕吹斷時雲縹緲，夕陽明處水澄鮮。", "江城秋早催寒事，望苑朝稀足晏眠。", "庭有菊花尊有酒，若方陶令媿前賢。"]'),
('ebe7a94b-449b-442b-b180-65268641ba3b','和陳贊善致仕還京口','徐鉉','唐','唐诗','tang','','[]','海門山下一漁舟，中有高人未白頭。',64,'全唐诗/poet.tang.42000.json','["海門山下一漁舟，中有高人未白頭。", "已駕安車歸故里，尚通閨籍在龍樓。", "泉聲漱玉窗前落，江色和煙檻外流。", "今日君臣厚終始，不須辛苦畫雙牛。"]'),
('28f23d8f-40ca-46ad-b09e-fde005322898','京使迴自臨川得從兄書寄詩依韻和','徐鉉','唐','唐诗','tang','','[]','珍重還京使，殷勤話故人。',48,'全唐诗/poet.tang.42000.json','["珍重還京使，殷勤話故人。", "別離長挂夢，寵祿不關身。", "趣向今成道，聲華舊絕塵。", "莫嗟客鬢老，詩句逐時新。"]'),
('bfd40774-c6d4-4068-823c-7ae5546f7694','陪鄭王相公賦筵前垂冰應教依韻','徐鉉','唐','唐诗','tang','','[]','窗外虛明雪乍晴，簷前垂霤盡成冰。',64,'全唐诗/poet.tang.42000.json','["窗外虛明雪乍晴，簷前垂霤盡成冰。", "長廊瓦疊行行密，晚院風高寸寸增。", "玉指乍拈簪尚媿，金階時墜磬難勝。", "晨餐堪醒曹參酒，自恨空腸病不能。"]'),
('17e63a26-31d8-4b39-9211-8962b8e463de','送禮部潘尚書致仕還建安','徐鉉','唐','唐诗','tang','','[]','名遂功成累復輕，鱸魚因起舊鄉情。',64,'全唐诗/poet.tang.42000.json','["名遂功成累復輕，鱸魚因起舊鄉情。", "履聲初下金華省，帆影看離石首城。", "化劒津頭尋故老，同亭會上問仙卿。", "冥鴻高舉真難事，相送何須淚滿纓。"]'),
('3cb8c0e9-4917-48ee-829e-6a39c4cf838f','和尉遲贊善病中見寄','徐鉉','唐','唐诗','tang','','[]','仙郎移病暑天過，却似冥鴻避罻羅。',64,'全唐诗/poet.tang.42000.json','["仙郎移病暑天過，却似冥鴻避罻羅。", "晝夢乍驚風動竹，夜吟時覺露霑莎。", "情親稍喜貧居近，性嬾猶嫌上直多。", "望苑恩深期勿藥，青雲岐路未蹉跎。"]'),
('da6b1336-d7a6-462b-be11-97ba89365cde','池州陳使君見示游齊山詩因寄','徐鉉','唐','唐诗','tang','','[]','往歲曾游弄水亭，齊峰濃翠暮軒橫。',64,'全唐诗/poet.tang.42000.json','["往歲曾游弄水亭，齊峰濃翠暮軒橫。", "哀猨出檻心雖喜，傷鳥聞弦勢易驚。", "病後簪纓殊寡興，老來泉石倍關情。", "今朝池口風波靜，遙賀山前有頌聲。"]'),
('d713cdb5-e584-49c5-a66c-c879cb8ea192','再領制誥和王明府見賀','徐鉉','唐','唐诗','tang','','[]','蹇步還依列宿邊，拱辰重認舊雲天。',64,'全唐诗/poet.tang.42000.json','["蹇步還依列宿邊，拱辰重認舊雲天。", "自嗟多難飄零困，不似當年膽氣全。", "雞樹晚花疎向日，龍池輕浪細含煙。", "從來不解爲身計，一葉悠悠任大川。"]'),
('36ec9510-4972-452b-9b4e-4735f0004400','送高舍人使嶺南','徐鉉','唐','唐诗','tang','','[]','西掖官曹近，南溟道路遙。',72,'全唐诗/poet.tang.42000.json','["西掖官曹近，南溟道路遙。", "使星將渡漢，仙櫂乍乘潮。", "柳映靈和折，梅依大庾飄。", "江帆風淅淅，山館雨蕭蕭。", "陸賈真迂闊，終童久寂寥。", "送君何限意，把酒一長謠。"]'),
('fa136d3a-d5ec-46ca-9811-4c6e8122141d','和王明府見寄','徐鉉','唐','唐诗','tang','','[]','時情世難消吾道，薄宦流年危此身。',64,'全唐诗/poet.tang.42000.json','["時情世難消吾道，薄宦流年危此身。", "莫歎京華同寂寞，曾經兵革共漂淪。", "對山開戶唯求靜，貰酒留賓不道貧。", "善政空多尚淹屈，不知誰是解憂民。"]'),
('e6e122c0-60da-4c74-ac6d-0e70eb314b25','和方泰州見寄','徐鉉','唐','唐诗','tang','','[]','逐客悽悽重入京，舊愁新恨兩難勝。',64,'全唐诗/poet.tang.42000.json','["逐客悽悽重入京，舊愁新恨兩難勝。", "雲收楚塞千山雪，風結秦淮一尺冰。", "置醴筵空情豈盡，投湘文就思如凝。", "更殘月落知孤坐，遙望船窗一點星。"]'),
('69cca25d-18d1-4793-a06e-604880a23be0','文獻太子挽歌詞五首 一','徐鉉','唐','唐诗','tang','','[]','國有承祧重，人知秉哲尊。',48,'全唐诗/poet.tang.42000.json','["國有承祧重，人知秉哲尊。", "清風來望苑，遺烈在東藩。", "此日升緱嶺，何因到寢門。", "天高不可問，煙靄共昏昏。"]'),
('89777efb-ae9d-4ee3-9176-90d396a8b660','文獻太子挽歌詞五首 二','徐鉉','唐','唐诗','tang','','[]','夏啓吾君子，周儲上帝賓。',48,'全唐诗/poet.tang.42000.json','["夏啓吾君子，周儲上帝賓。", "音容一飄忽，功業自紛綸。", "露泣承華月，風驚麗正塵。", "空餘商嶺客，行淚下宜春。"]'),
('7d90f7b1-7943-4e36-9d37-88856a2180f9','文獻太子挽歌詞五首 三','徐鉉','唐','唐诗','tang','','[]','出處成交讓，經綸有大功。',48,'全唐诗/poet.tang.42000.json','["出處成交讓，經綸有大功。", "淚碑瓜步北，棠樹蒜山東。", "百揆方時敘，重離遂不融。", "故臣偏感咽，曾是歎三窮。"]'),
('c18f4071-2e78-42f5-946f-bf23d73457cb','文獻太子挽歌詞五首 四','徐鉉','唐','唐诗','tang','','[]','甲觀光陰促，園陵天地長。',48,'全唐诗/poet.tang.42000.json','["甲觀光陰促，園陵天地長。", "簫笳咽無韻，賓御哭相將。", "盛烈傳彝鼎，遺文被樂章。", "君臣知己分，零淚亂無行。"]'),
('e6360316-739d-4a9f-b76b-d9864105845e','文獻太子挽歌詞五首 五','徐鉉','唐','唐诗','tang','','[]','綵仗清晨出，非同齒胄時。',48,'全唐诗/poet.tang.42000.json','["綵仗清晨出，非同齒胄時。", "愁煙鎖平甸，朔吹繞寒枝。", "楚客來何補，緱山去莫追。", "迴瞻飛蓋處，掩袂不勝悲。"]'),
('19a16376-720f-4dc6-ab80-6011988e368d','送王員外宰德安','徐鉉','唐','唐诗','tang','','[]','家世朱門貴，官資粉署優。',48,'全唐诗/poet.tang.42000.json','["家世朱門貴，官資粉署優。", "今爲百里長，應好五峰游。", "柳影連彭澤，湖光接庾樓。", "承明須再入，官滿莫淹留。"]'),
('2f58a1b4-3e9d-49ba-9a4c-045ad3dde435','以端谿硯酬張員外水精珠兼和來篇','徐鉉','唐','唐诗','tang','','[]','請以端谿潤，酬君水玉明。',48,'全唐诗/poet.tang.42000.json','["請以端谿潤，酬君水玉明。", "方圓雖異器，功用信俱呈。", "自得山川秀，能分日月精。", "巾箱各珍重，所貴在交情。"]'),
('c90ba907-6132-4cad-a81d-37b2a7413e87','奉使九華山中途遇青陽薛郎中','徐鉉','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','故人相別動相思，此地相逢豈素期。',64,'全唐诗/poet.tang.42000.json','["故人相別動相思，此地相逢豈素期。", "九子峰前閑未得，五谿橋上坐多時。", "甘泉從幸余知忝，宣室徵還子未遲。", "且飲一盃消別恨，野花風起漸離披。"]'),
('de6f64dd-f04e-4620-a646-f68c7bdb9778','奉命南使經彭澤','徐鉉','唐','唐诗','tang','','[]','遠使程途未一分，離心常要醉醺醺。',32,'全唐诗/poet.tang.42000.json','["遠使程途未一分，離心常要醉醺醺。", "那堪彭澤門前立，黃菊蕭疎不見君。"]'),
('adee5df9-b6e2-4040-bd7e-795018a65293','南都遇前嘉魚劉令言游閩嶺作此與之','徐鉉','唐','唐诗','tang','','[]','我持使節經韶石，君作閑游過武夷。',64,'全唐诗/poet.tang.42000.json','["我持使節經韶石，君作閑游過武夷。", "兩地山光成獨賞，隔年鄉思暗相知。", "洪厓壇上長岑寂，孺子亭前自別離。", "珍重分岐一盃酒，強加餐飯數吟詩。"]'),
('b6d0c77b-5307-45b7-b11f-707de7db4eb8','閣皁山','徐鉉','唐','唐诗','tang','','[]','殿影高低雲掩映，松陰繚繞步徘徊。',32,'全唐诗/poet.tang.42000.json','["殿影高低雲掩映，松陰繚繞步徘徊。", "從今莫厭簪裾累，不是乘軺不得來。"]'),
('efca8adc-8a81-4453-88ac-be385d18d83f','玉笥山留題','徐鉉','唐','唐诗','tang','','[]','仙鄉會應遠，王事知何極。',72,'全唐诗/poet.tang.42000.json','["仙鄉會應遠，王事知何極。", "征傳莫辭勞，玉峰聊一息。", "形骸已銷散，心想都凝寂。", "真氣自清虛，非關好松石。", "九仙皆積學，洞壑多遺跡。", "游子歸去來，胡爲但征役。"]'),
('6d46d156-ae59-41e3-9953-3e6469ac8b1b','廬陵別朱觀先輩','徐鉉','唐','唐诗','tang','','[]','桂籍知名有幾人，翻飛相續上青雲。',64,'全唐诗/poet.tang.42000.json','["桂籍知名有幾人，翻飛相續上青雲。", "解憐才子寧唯我，遠作卑官尚見君。", "嶺外獨持嚴助節，宮中誰薦長卿文。", "新詩試爲重高詠，朝漢臺前不可聞。"]'),
('eec11621-65b0-4bc9-b09a-727d8402979a','文彧少卿文山郎中交好深至二紀已餘暌別數年二子長逝奉使嶺表途次南康弔孫氏之孤於其家覩文彧手書於僧室慷慨悲歎留題此詩','徐鉉','唐','唐诗','tang','','[]','孫家虛坐弔諸孤，張叟僧房見手書。',64,'全唐诗/poet.tang.42000.json','["孫家虛坐弔諸孤，張叟僧房見手書。", "二紀歡游今若此，滿衣零淚欲何如。", "腰間金印從如斗，鏡裏霜華已滿梳。", "珍重遠公應笑我，塵心唯此未能除。"]'),
('b6f800a0-9799-4101-8879-aefeedae2fb4','朱處士相與有山水之願見送至南康作此以別之','徐鉉','唐','唐诗','tang','','[]','憐君送我至南康，更憶梅花庾嶺芳。',32,'全唐诗/poet.tang.42000.json','["憐君送我至南康，更憶梅花庾嶺芳。", "多少仙山共遊在，願君百歲尚康強。"]'),
('0a27233e-bddd-458e-9307-3bfd0ee29a26','清明日清遠峽作','徐鉉','唐','唐诗','tang','','[]','嶺外春過半，途中火又新。',24,'全唐诗/poet.tang.42000.json','["嶺外春過半，途中火又新。", "殷勤清遠峽，留戀北歸人。"]'),
('5b66c765-3223-4567-afeb-453e0c543da8','迴至南康題紫極宮裏道士房','徐鉉','唐','唐诗','tang','','[]','王事信靡盬，飲冰安足辭。',84,'全唐诗/poet.tang.42000.json','["王事信靡盬，飲冰安足辭。", "胡爲擁征傳，乃至天南陲。", "天南非我鄉，留滯忽踰時。", "還經羽人家，豁若雲霧披。", "何以寬吾懷，老莊有微詞。", "達士無不可，至人豈偏爲。", "客愁勿復道，爲君吟此詩。"]'),
('57e77fa9-6785-44a8-a469-a9899489e2ba','和歙州陳使君見寄','徐鉉','唐','唐诗','tang','','[]','新安風景好，時令肅轅門。',120,'全唐诗/poet.tang.42000.json','["新安風景好，時令肅轅門。", "身貴心彌下，功多口不言。", "韜鈐家法在，儒雅素風存。", "簪履陪游盛，鄉閭俗化敦。", "臨窗山色秀，繞郭水聲喧。", "織絡文章麗，矜嚴道義尊。", "樓臺秋月靜，京庾晚雲屯。", "曉吹傳衙鼓，晴陽展信旛。", "一篇貽友好，千里倍心論。", "未見歸驂動，空能役夢魂。"]'),
('41fb0aed-7aca-41f5-bc55-02de8afb4197','和賈員外戩見贈玉蘂花栽','徐鉉','唐','唐诗','tang','','[]','瓊瑤一簇帶花來，便斸蒼苔手自栽。',32,'全唐诗/poet.tang.42000.json','["瓊瑤一簇帶花來，便斸蒼苔手自栽。", "喜見唐昌舊顏色，爲君判病酌金罍。"]'),
('938e761f-ef00-4b60-a759-987977885f08','光穆皇后挽歌三首 一','徐鉉','唐','唐诗','tang','','[]','仙馭期難改，坤儀道自光。',48,'全唐诗/poet.tang.42000.json','["仙馭期難改，坤儀道自光。", "閟宮新表德，沙麓舊膺祥。", "素帟堯門掩，凝笳畢陌長。", "東風慘陵樹，無復見親桑。"]'),
('9bde1bb7-e04d-4817-91f2-9d7d61486fb9','光穆皇后挽歌三首 二','徐鉉','唐','唐诗','tang','','[]','永樂留虛位，長陵啓夕扉。',48,'全唐诗/poet.tang.42000.json','["永樂留虛位，長陵啓夕扉。", "返虞嚴吉杖，復土掩空衣。", "功業投三母，光靈極四妃。", "唯應彤史在，不與露花晞。"]'),
('62d40532-d242-4a6a-9d50-6b3579da4041','光穆皇后挽歌三首 三','徐鉉','唐','唐诗','tang','','[]','隱隱閶門路，煙雲曉更愁。',48,'全唐诗/poet.tang.42000.json','["隱隱閶門路，煙雲曉更愁。", "空瞻金輅出，非是濯龍游。", "德感人倫正，風行內職修。", "還隨偶物化，同此思軒丘。"]'),
('edef0aad-d0b9-4a38-a9d6-bdeb2864d8e4','嚴相公宅牡丹','徐鉉','唐','唐诗','tang','','[]','但是豪家重牡丹，爭如丞相閣前看。',64,'全唐诗/poet.tang.42000.json','["但是豪家重牡丹，爭如丞相閣前看。", "鳳樓日暖開偏早，雞樹陰濃謝更難。", "數朵已應迷國豔，一枝何幸上塵冠。", "不知更許憑欄否，爛熳春光未肯殘。"]'),
('86316174-9edc-45f1-9611-779d507942da','侍宴賦得歸鴈','徐鉉','唐','唐诗','tang','','[]','夜靜羣動息，翩翩一鴈歸。',48,'全唐诗/poet.tang.42000.json','["夜靜羣動息，翩翩一鴈歸。", "清音天際遠，寒影月中微。", "何處雲同宿，長空雪共飛。", "陽和常借便，免與素心違。"]'),
('fd96a47b-4060-405d-8565-efab7d72de94','又賦早春書事','徐鉉','唐','唐诗','tang','','[]','苑裏芳華早，皇家勝事多。',48,'全唐诗/poet.tang.42000.json','["苑裏芳華早，皇家勝事多。", "弓聲達春氣，弈思養天和。", "煖酒紅爐火，浮舟綠水波。", "雪晴農事起，擊壤聽賡歌。"]'),
('b1b8d31e-3825-4e36-aa15-e29dc9fc381b','依韻和令公大王薔薇詩','徐鉉','唐','唐诗','tang','','[]','綠樹成陰後，羣芳稍歇時。',216,'全唐诗/poet.tang.42000.json','["綠樹成陰後，羣芳稍歇時。", "誰將新濯錦，挂向最長枝。", "卷箔香先入，憑欄影任移。", "賞頻嫌酒渴，吟苦怕霜髭。", "架迥籠雲幄，庭虛展繡帷。", "有情縈舞袖，無力罥遊絲。", "嫩蘂鶯偷采，柔條柳伴垂。", "荀池波自照，梁苑客嘗窺。", "玉李尋皆謝，金桃亦暗衰。", "花中應獨貴，庭下故開遲。", "委豔妝苔砌，分華借槿籬。", "低昂勻灼爍，濃淡疊參差。", "幸植王宮裏，仍逢宰府知。", "芳心向誰許，醉態不能支。", "芍藥天教避，玫瑰衆共嗤。", "光明烘晝景，潤膩裛輕𩅰。", "麗似期神女，珍如重衛姬。", "君王偏屬詠，七子盡搜奇。"]'),
('2c7e2906-dd7f-40f8-9ac7-b5487984292e','和門下殷侍郎新茶二十韻','徐鉉','唐','唐诗','tang','','[]','暖吹入春園，新芽競粲然。',240,'全唐诗/poet.tang.42000.json','["暖吹入春園，新芽競粲然。", "才教鷹觜拆，未放雪花妍。", "荷杖青林下，攜筐旭景前。", "孕靈資雨露，鍾秀自山川。", "碾後香彌遠，烹來色更香。", "名隨土地貴，味逐水泉遷。", "力藉流黃暖，形模紫筍圓。", "正當鑽柳火，遙想湧金泉。", "任道時新物，須依古法煎。", "輕甌浮綠乳，孤竈散餘煙。", "甘薺非予匹，宮槐讓我先。", "竹孤空冉冉，荷弱謾田田。", "解渴消殘酒，清神感夜眠。", "十漿何足饋，百榼盡堪捐。", "采擷唯憂晚，營求不計錢。", "任公因焙顯，陸氏有經傳。", "愛甚真成癖，嘗多合得仙。", "亭臺虛靜處，風月豔陽天。", "自可臨泉石，何妨雜管弦。", "東山似蒙頂，願得從諸賢。"]'),
('0f02f360-38cf-497e-bc77-4e1650197f29','春雪應制','徐鉉','唐','唐诗','tang','','[]','繁陰連曙景，瑞雪灑芳辰。',48,'全唐诗/poet.tang.42000.json','["繁陰連曙景，瑞雪灑芳辰。", "勢密猶疑臘，風和始覺春。", "縈林開玉蘂，飄座裛香塵。", "欲識宸心悅，雲謠慰兆人。"]'),
('139b8a53-0975-494d-ba27-7c52e75ba740','進雪詩','徐鉉','唐','唐诗','tang','','[]','欲使新正識有年，故飄輕絮伴春還。',64,'全唐诗/poet.tang.42000.json','["欲使新正識有年，故飄輕絮伴春還。", "近看瓊樹籠銀闕，遠想瑤池帶玉關。", "潤逐麳麰鋪綠野，暖隨杯酒上朱顏。", "朝來花萼樓中宴，數曲賡歌雅頌間。"]'),
('0c4afd70-dc6a-4a44-ab68-8fc93d6911fb','自題山亭三首 一','徐鉉','唐','唐诗','tang','','[]','簪組非無累，園林未是歸。',24,'全唐诗/poet.tang.42000.json','["簪組非無累，園林未是歸。", "世喧長不到，何必故山薇。"]'),
('ba134a53-5d3f-42d6-9e0e-1ef27f6edb76','自題山亭三首 二','徐鉉','唐','唐诗','tang','','[]','小舫行乘月，高齋臥看山。',24,'全唐诗/poet.tang.42000.json','["小舫行乘月，高齋臥看山。", "退公聊自足，爭敢望長閑。"]'),
('c05fbb51-61be-4637-8bcc-9b982c863dda','自題山亭三首 三','徐鉉','唐','唐诗','tang','','[]','跂石仍臨水，披襟復挂冠。',24,'全唐诗/poet.tang.42000.json','["跂石仍臨水，披襟復挂冠。", "機心忘未得，棊局與魚竿。"]'),
('c753550f-debc-4e5d-9af4-ea5c8c99aa9c','和陳表用員外求酒','徐鉉','唐','唐诗','tang','','[]','暑天頻雨亦頻晴，簾外閑雲重復輕。',32,'全唐诗/poet.tang.42000.json','["暑天頻雨亦頻晴，簾外閑雲重復輕。", "珍重一壺酬絕唱，向風遙想醉吟聲。"]'),
('9a42fee4-161a-4046-83a4-b98f8df54b00','奉和右省僕射西亭高臥作','徐鉉','唐','唐诗','tang','','[]','院靜蒼苔積，庭幽怪石欹。',96,'全唐诗/poet.tang.42000.json','["院靜蒼苔積，庭幽怪石欹。", "蟬聲當檻急，虹影向簷垂。", "晝漏猶憐永，叢蘭未覺衰。", "疎篁巢翡翠，折葦覆鸕鷀。", "對酒襟懷曠，圍棊旨趣遲。", "景皆隨所尚，物各遂其宜。", "道與時相會，才非世所羇。", "賦詩貽座客，秋事爾何悲。"]'),
('cf82ef7c-37ae-4d97-8300-108550244b2d','憶新淦觴池寄孟賓于員外','徐鉉','唐','唐诗','tang','','[]','往年淦水駐行軒，引得清流似月圓。',64,'全唐诗/poet.tang.42000.json','["往年淦水駐行軒，引得清流似月圓。", "自有谿光還碧甃，不勞人力遞金船。", "潤滋苔蘚欺茵席，聲入杉松當管弦。", "珍重詩人頻管領，莫教塵土咽潺潺。"]'),
('1837feb2-a799-41ef-a114-0bf26f63af79','右省僕射後湖亭閑宴鉉以宿直先歸賦詩留獻','徐鉉','唐','唐诗','tang','','[]','湖上一陽生，虛亭啓高宴。',48,'全唐诗/poet.tang.42000.json','["湖上一陽生，虛亭啓高宴。", "楓林煙際出，白鳥波心見。", "主人忘貴達，座客容疵賤。", "獨慙殘照催，歸宿明光殿。"]'),
('e9b13d28-ffca-4a64-97db-9ccf725d1972','送孟賓于員外還新淦','徐鉉','唐','唐诗','tang','','[]','暫來城闕不從容，却佩銀魚隱玉峰。',64,'全唐诗/poet.tang.42000.json','["暫來城闕不從容，却佩銀魚隱玉峰。", "雙澗水邊欹醉石，九仙臺下聽風松。", "題詩翠壁稱逋客，采藥春畦狎老農。", "野鶴乘軒雲出岫，不知何日再相逢。"]'),
('154091f0-621d-4f23-9e89-1556d972a9b0','孟君別後相續寄書作此酬之','徐鉉','唐','唐诗','tang','','[]','多病怯煩暑，短才憂近職。',48,'全唐诗/poet.tang.42000.json','["多病怯煩暑，短才憂近職。", "跂足北窗風，遙懷浩無極。", "故人易成別，詩句空相憶。", "尺素寄天涯，淦江秋水色。"]'),
('4a8a5937-9527-4995-a740-ef9d611ba5e9','納后夕侍宴','徐鉉','唐','唐诗','tang','','[]','天上軒星正，雲間湛露垂。',72,'全唐诗/poet.tang.42000.json','["天上軒星正，雲間湛露垂。", "禮容過渭水，宴喜勝瑤池。", "彩霧籠花燭，升龍肅羽儀。", "君臣歡樂日，文物盛明時。", "簾捲銀河轉，香凝玉漏遲。", "華封傾祝意，觴酒與聲詩。"]'),
('18cc1c05-3eff-4c21-895c-e09e1827ee81','又三絕 一','徐鉉','唐','唐诗','tang','','[]','時平物茂歲功成，重翟排雲到玉京。',32,'全唐诗/poet.tang.42000.json','["時平物茂歲功成，重翟排雲到玉京。", "四海未知春色至，今宵先入九重城。"]'),
('8c67fbee-952d-4044-9722-0f92c0393634','又三絕 二','徐鉉','唐','唐诗','tang','','[]','銀燭金爐禁漏移，月輪初照萬年枝。',32,'全唐诗/poet.tang.42000.json','["銀燭金爐禁漏移，月輪初照萬年枝。", "造舟已似文王事，卜世應同八百期。"]'),
('25b64840-c9db-4f79-bb31-d489da132f98','又三絕 三','徐鉉','唐','唐诗','tang','','[]','漢主承乾帝道光，天家花燭宴昭陽。',32,'全唐诗/poet.tang.42000.json','["漢主承乾帝道光，天家花燭宴昭陽。", "六衣盛禮如金屋，彩筆分題似柏梁。"]'),
('921582a6-e4ba-4c72-9f59-e218c05eda5e','北苑侍宴雜詠詩 竹','徐鉉','唐','唐诗','tang','','[]','勁節生宮苑，虛心奉豫遊。',24,'全唐诗/poet.tang.42000.json','["勁節生宮苑，虛心奉豫遊。", "自然名價重，不羨渭川侯。"]'),
('58629206-d491-451b-a17d-9a9fbe11eb62','北苑侍宴雜詠詩 松','徐鉉','唐','唐诗','tang','','[]','細韻風中遠，寒青雪後濃。',24,'全唐诗/poet.tang.42000.json','["細韻風中遠，寒青雪後濃。", "繁陰堪避雨，効用待東封。"]'),
('a11faf7a-a60f-42f9-91b4-d109d7d4816c','北苑侍宴雜詠詩 水','徐鉉','唐','唐诗','tang','','[]','碧草垂低岸，東風起細波。',24,'全唐诗/poet.tang.42000.json','["碧草垂低岸，東風起細波。", "橫汾從遊宴，何謝到天河。"]'),
('70a22830-405f-4181-8a42-d56f6d3420f1','北苑侍宴雜詠詩 風','徐鉉','唐','唐诗','tang','','[]','昨朝纔解凍，今日又開花。',24,'全唐诗/poet.tang.42000.json','["昨朝纔解凍，今日又開花。", "帝力無人識，誰知玩物華。"]'),
('5dc8dcfa-125d-49c5-aaed-4183d6a45f46','北苑侍宴雜詠詩 菊','徐鉉','唐','唐诗','tang','','[]','細麗披金彩，氛氳散遠馨。',24,'全唐诗/poet.tang.42000.json','["細麗披金彩，氛氳散遠馨。", "汎杯頻奉賜，緣解制頹齡。"]'),
('bf18512a-9624-4d72-b460-700834b9d5e0','柳枝詞十首 一','徐鉉','唐','唐诗','tang','','[]','金馬辭臣賦小詩，梨園弟子唱新詞。',32,'全唐诗/poet.tang.42000.json','["金馬辭臣賦小詩，梨園弟子唱新詞。", "君恩還似東風意，先入靈和蜀柳枝。"]'),
('d231dbb4-bb96-44fa-b945-7e721226b964','柳枝詞十首 二','徐鉉','唐','唐诗','tang','','[]','百草千花共待春，綠楊顏色最驚人。',32,'全唐诗/poet.tang.42000.json','["百草千花共待春，綠楊顏色最驚人。", "天邊雨露年年在，上苑芳華歲歲新。"]'),
('5c2702f5-2433-4479-8e9e-4d81ca038169','柳枝詞十首 三','徐鉉','唐','唐诗','tang','','[]','長愛龍池二月時，𣯶𣯶金線弄春姿。',32,'全唐诗/poet.tang.42000.json','["長愛龍池二月時，𣯶𣯶金線弄春姿。", "假饒葉落枝空後，更有梨園笛裏吹。"]'),
('04b32110-3d0d-489a-8894-04b939b281b6','柳枝詞十首 四','徐鉉','唐','唐诗','tang','','[]','綠水成文柳帶搖，東風初到不鳴條。',32,'全唐诗/poet.tang.42000.json','["綠水成文柳帶搖，東風初到不鳴條。", "龍舟欲過偏留戀，萬縷輕絲拂御橋。"]'),
('e5c1b256-5df0-4351-bbe6-8b16c719571a','柳枝詞十首 五','徐鉉','唐','唐诗','tang','','[]','百尺長條婉麴塵，詩題不盡畫難真。',32,'全唐诗/poet.tang.42000.json','["百尺長條婉麴塵，詩題不盡畫難真。", "憑君折向人間種，還似君恩處處春。"]'),
('f402b09f-8792-465b-9283-346c2d97301a','柳枝詞十首 六','徐鉉','唐','唐诗','tang','','[]','風暖雲開晚照明，翠條深映鳳皇城。',32,'全唐诗/poet.tang.42000.json','["風暖雲開晚照明，翠條深映鳳皇城。", "人間欲識靈和態，聽取新詞玉管聲。"]'),
('ac704b30-e0c6-4ca0-9dac-6b378709a5d2','柳枝詞十首 七','徐鉉','唐','唐诗','tang','','[]','醉折垂楊唱柳枝，金城三月走金羈。',32,'全唐诗/poet.tang.42000.json','["醉折垂楊唱柳枝，金城三月走金羈。", "年年爲愛新條好，不覺蒼華也似絲。"]'),
('cbdcc25d-8f96-4698-bd5f-7c27b141a2ed','柳枝詞十首 八','徐鉉','唐','唐诗','tang','','[]','新春花柳競芳姿，偏愛垂楊拂地枝。',32,'全唐诗/poet.tang.42000.json','["新春花柳競芳姿，偏愛垂楊拂地枝。", "天子徧教詞客賦，宮中要唱洞簫詞。"]'),
('072151e9-bc50-4577-98b3-ac44208600aa','柳枝詞十首 九','徐鉉','唐','唐诗','tang','','[]','凝碧池頭蘸翠漣，鳳皇樓畔簇晴煙。',32,'全唐诗/poet.tang.42000.json','["凝碧池頭蘸翠漣，鳳皇樓畔簇晴煙。", "新詞欲詠知難詠，說與雙成入管弦。"]'),
('d21708e8-11f8-4505-b346-896c8c940613','柳枝詞十首 十','徐鉉','唐','唐诗','tang','','[]','侍從甘泉與未央，移舟偏要近垂楊。',32,'全唐诗/poet.tang.42000.json','["侍從甘泉與未央，移舟偏要近垂楊。", "櫻桃未綻梅花老，折得柔條百尺長。"]'),
('5919bfe9-7f9c-4115-a56a-47efeba1154c','奉和宮傅相公懷舊見寄四十韻','徐鉉','唐','唐诗','tang','','[]','謝傅功成德望全，鸞臺初下正蕭然。',384,'全唐诗/poet.tang.42000.json','["謝傅功成德望全，鸞臺初下正蕭然。", "摶風乍息三千里，感舊重懷四十年。", "西掖新官同賈馬，南朝興運似開天。", "文辭職業分工拙，流輩班資讓後先。", "每愧陋容勞刻畫，長慙頑石費彫鐫。", "晨趨綸掖吟春永，夕會精廬待月圓。", "立馬有時同草昭，聯鑣幾處共成篇。", "閑歌柳葉翻新曲，醉詠桃花促綺筵。", "少壯況逢時世好，經過寧慮歲華遷。", "雲龍得路須騰躍，社櫟非材合棄捐。", "再謁湘江猶是幸，兩還宣室竟何緣。", "已知瑕玷勞磨瑩，又有官司重接連。", "聽漏分宵趨建禮，從遊同召赴甘泉。", "雲開閶闔分臺殿，風過華林度管弦。", "行止不離宮仗影，衣裾嘗惹御爐煙。", "師資稷契論中禮，依止山公典小銓。", "多謝天波垂赤管，敢教晨景過華塼。", "翾飛附驥方經遠，巨楫垂風遂濟川。", "玉燭調時鈞軸正，台階平處德星懸。", "巖廊禮絕威容肅，布素情深友好偏。", "長擬營巢安大廈，忽驚操鉞領中權。", "吳門日麗龍銜節，京口沙晴鷁畫船。", "蓋代名高方赫赫，戀恩心切更乾乾。", "袁安辭氣忠仍懇，吳漢精誠直且專。"]'),
('096e5a2b-25a4-40f5-8c4c-c59de8d5a571','右省僕射相公垂覽和詩復貽長句輙次來韻','徐鉉','唐','唐诗','tang','','[]','西院春歸道思深，披衣閑聽暝猨吟。',64,'全唐诗/poet.tang.42000.json','["西院春歸道思深，披衣閑聽暝猨吟。", "鋪陳政事留黃閣，偃息神機在素琴。", "玉柄暫時疎末座，瑤華頻復惠清音。", "開晴便作東山約，共賞煙霞放曠心。"]'),
('4ee2fbbd-30af-42fa-b169-a15f55098b49','九日落星山登高','徐鉉','唐','唐诗','tang','','[]','秋暮天高稻穟成，落星山上會諸賓。',64,'全唐诗/poet.tang.42000.json','["秋暮天高稻穟成，落星山上會諸賓。", "黃花汎酒依流俗，白髮滿頭思古人。", "巖影晚看雲出岫，湖光遙見客垂綸。", "風煙不改年長度，終待林泉老此身。"]'),
('a817b037-7723-498e-aeea-5a47dccab5e8','十日和張少監','徐鉉','唐','唐诗','tang','','[]','重陽高會古平臺，吟徧秋光始下來。',64,'全唐诗/poet.tang.42000.json','["重陽高會古平臺，吟徧秋光始下來。", "黃菊後期香未減，新詩捧得眼還開。", "每因佳節知身老，却憶前歡似夢迴。", "且喜清時屢行樂，是非名利盡悠哉。"]'),
('bebcfa42-b2e1-45e1-97c4-1794e8ec2709','御筵送鄧王','徐鉉','唐','唐诗','tang','','[]','禁裏秋光似水清，林煙池影共離情。',64,'全唐诗/poet.tang.42000.json','["禁裏秋光似水清，林煙池影共離情。", "暫移黃閣只三載，却望紫垣都數程。", "滿座清風天子送，隨車甘雨郡人迎。", "綺霞閣上詩題在，從此還應有頌聲。"]'),
('1675125f-a6e8-40d1-976a-f26cadf15f62','和張少監晚菊','徐鉉','唐','唐诗','tang','','[]','憶共庭蘭倚砌裁，柔條輕吹獨依隈。',64,'全唐诗/poet.tang.42000.json','["憶共庭蘭倚砌裁，柔條輕吹獨依隈。", "自知佳節終堪賞，爲惜流光未忍開。", "采擷也須盈掌握，馨香還解滿尊罍。", "今朝旬假猶無事，更好登臨汎一盃。"]'),
('2e50d9d9-2809-4650-ab6e-71a253a60beb','送馮侍郎','徐鉉','唐','唐诗','tang','','[]','聞君竹馬戲毘陵，誰道觀風自六卿。',64,'全唐诗/poet.tang.42000.json','["聞君竹馬戲毘陵，誰道觀風自六卿。", "今日聲明光舊物，共看旌斾擁書生。", "斬蛟橋下谿煙碧，射虎亭邊草路清。", "應念筵中倍離恨，老來偏重十年兄。"]'),
('cf2140b9-df12-4522-adef-86708ec89f93','又絕句寄題毘陵驛','徐鉉','唐','唐诗','tang','','[]','曾持使節駐毘陵，長與州人有舊情。',32,'全唐诗/poet.tang.42000.json','["曾持使節駐毘陵，長與州人有舊情。", "爲向驛橋風月道，舍人髭鬢白千莖。"]'),
('d944d802-48d3-4c6f-b997-1f198d250c51','陳侍郎宅觀花燭','徐鉉','唐','唐诗','tang','','[]','今夜銀河萬里秋，人言織女嫁牽牛。',64,'全唐诗/poet.tang.42000.json','["今夜銀河萬里秋，人言織女嫁牽牛。", "佩聲寥亮和金奏，燭影熒煌映玉鉤。", "座客亦從天子賜，更籌須爲主人留。", "世間盛事君知否，朝下鸞臺夕鳳樓。"]'),
('d48d8a8d-54a1-4ef1-bc99-fe161cbbcf74','送蕭尚書致仕歸廬陵','徐鉉','唐','唐诗','tang','','[]','江海分飛二十春，重論前事不堪聞。',64,'全唐诗/poet.tang.42000.json','["江海分飛二十春，重論前事不堪聞。", "主憂臣辱誰非我，曲突徙薪唯有君。", "金紫滿身皆外物，雪霜垂領便離羣。", "鶴歸華表望不盡，玉笥山頭多白雲。"]'),
('ec431828-346d-41f1-a957-60e6ed4cec62','賦得秋江晚照','徐鉉','唐','唐诗','tang','','[]','落日照平流，晴空萬里秋。',48,'全唐诗/poet.tang.42000.json','["落日照平流，晴空萬里秋。", "輕明動楓葉，點的亂沙鷗。", "罾網魚梁靜，籉簦稻穗收。", "不教行樂倦，冉冉下城樓。"]'),
('3448ac9a-c1fd-47cf-a54d-cda9525c084e','奉和子龍大監與舍弟贈答之什','徐鉉','唐','唐诗','tang','','[]','石渠東觀兩優賢，明主知臣豈偶然。',64,'全唐诗/poet.tang.42000.json','["石渠東觀兩優賢，明主知臣豈偶然。", "鴛鷺分行皆接武，金蘭同好共忘年。", "懷恩未遂林泉約，竊位空慙組綬懸。", "多少深情知不盡，好音相慰強成篇。"]'),
('3bb18d8e-45e3-4b05-8c2f-6c13deec02b9','史館庭梅見其毫末歷載三十今已半枯嘗僚諸公唯相公與鉉在耳覩物興感率成短篇謹書獻上伏惟垂覽','徐鉉','唐','唐诗','tang','','[]','東觀婆娑樹，曾憐甲坼時。',48,'全唐诗/poet.tang.42000.json','["東觀婆娑樹，曾憐甲坼時。", "繁英共攀折，芳歲幾推移。", "往事皆陳迹，清香亦暗衰。", "相看宜自喜，雙鬢合垂絲。"]'),
('1a3e574c-5d1b-4f89-8a38-2f5f91583d01','太傅相公深感庭梅再成絕唱曲垂借示倍認知憐謹用舊韻攀和','徐鉉','唐','唐诗','tang','','[]','禁省繁華地，含芳自一時。',48,'全唐诗/poet.tang.42000.json','["禁省繁華地，含芳自一時。", "雪英開復落，紅藥植還移。", "靜想分今昔，頻吟歎盛衰。", "多情共如此，爭免鬢成絲。"]'),
('f6fb39cd-311b-4076-910f-fdaeae3cef03','太傅相公以庭梅二篇許舍弟同賦再迂藻思曲有虛稱謹依韻奉和庶申感謝','徐鉉','唐','唐诗','tang','','[]','舊眷終無替，流光自足悲。',48,'全唐诗/poet.tang.42000.json','["舊眷終無替，流光自足悲。", "攀條感花萼，和曲許塤篪。", "前會成春夢，和人更己知。", "緣情聊借喻，爭取道言詩。"]'),
('6ae8e60e-ccc7-4ec4-ad49-17f265adc2d3','和鍾大監汎舟同游見示','徐鉉','唐','唐诗','tang','','[]','潮溝橫趣北山阿，一月三游未是多。',64,'全唐诗/poet.tang.42000.json','["潮溝橫趣北山阿，一月三游未是多。", "老去交親難暫捨，閑中滋味更無過。", "谿橋樹映行人渡，村徑風飄牧豎歌。", "孤櫂亂流偏有興，滿川晴日弄微波。"]'),
('3426813e-83aa-4d25-8851-785c456de00c','又和游光睦院','徐鉉','唐','唐诗','tang','','[]','寺門山水際，清淺照孱顏。',48,'全唐诗/poet.tang.42000.json','["寺門山水際，清淺照孱顏。", "客櫂晚維岸，僧房猶掩關。", "日華穿竹靜，雲影過堦閑。", "箕踞一長嘯，忘懷物我間。"]'),
('c5a84d32-ef18-4ac9-8270-457e2b18d47f','和張少監舟中望蔣山','徐鉉','唐','唐诗','tang','','[]','谿路向還背，前山高復重。',48,'全唐诗/poet.tang.42000.json','["谿路向還背，前山高復重。", "紛披紅葉樹，間斷白雲峰。", "盡日慵移櫂，何年醉倚松。", "自知閑未得，不敢笑周顒。"]'),
('c1cbc223-a4fb-4faf-9774-9f4a15def66a','茱萸詩','徐鉉','唐','唐诗','tang','','[]','萬物慶西成，茱萸獨擅名。',48,'全唐诗/poet.tang.42000.json','["萬物慶西成，茱萸獨擅名。", "芳排紅結小，香透夾衣輕。", "宿露霑猶重，朝陽照更明。", "長和菊花酒，高宴奉西清。"]'),
('58463373-cbd8-476b-a00e-68dc942965fe','奉和御製茱萸','徐鉉','唐','唐诗','tang','','[]','臺畔西風御果新，芳香精彩麗蕭辰。',64,'全唐诗/poet.tang.42000.json','["臺畔西風御果新，芳香精彩麗蕭辰。", "柔條細葉妝治好，紫蔕紅芳點綴勻。", "幾朵得陪天上宴，千株長作洞中春。", "今朝聖藻偏流詠，黃菊無由更敢鄰。"]'),
('438d4a8b-b0e9-45f0-905a-5c4b8a0df19d','蒙恩賜酒旨令醉進詩以謝','徐鉉','唐','唐诗','tang','','[]','明光殿裏夜迢迢，多病逢秋自寂寥。',64,'全唐诗/poet.tang.42000.json','["明光殿裏夜迢迢，多病逢秋自寂寥。", "蠟炬乍傳丹鳳詔，御題初認白雲謠。", "今宵幸識衢尊味，明日知停入閤朝。", "爲感君恩判一醉，不煩辛苦解金貂。"]'),
('b407b9d8-6d1e-4a43-ac33-a9c6819a2372','秋日汎舟賦蘋花','徐鉉','唐','唐诗','tang','','[]','素豔擁行舟，清香覆碧流。',48,'全唐诗/poet.tang.42000.json','["素豔擁行舟，清香覆碧流。", "遠煙分的的，輕浪汎悠悠。", "雨歇平湖滿，風涼運瀆秋。", "今朝流詠處，即是白蘋洲。"]'),
('31bd2318-729d-45dc-b979-84f0e462deb6','題梁王舊園','徐鉉','唐','唐诗','tang','','[]','梁王舊館枕潮溝，共引垂藤繫小舟。',66,'全唐诗/poet.tang.42000.json','["梁王舊館枕潮溝，共引垂藤繫小舟。", "樹倚荒臺風淅淅，草埋欹石[雨]修修。", "門前不見鄒枚醉，池上時聞鴈鶩愁。", "節士逢秋多感激，不須頻向此中游。"]'),
('257162d3-d669-44a7-a8dd-66f54bca50b4','奉酬度支陳員外','徐鉉','唐','唐诗','tang','','[]','古來賢達士，馳鶩唯羣書。',72,'全唐诗/poet.tang.42000.json','["古來賢達士，馳鶩唯羣書。", "非禮誓弗習，違道無與居。", "儒家若迂闊，遂將世情疎。", "吾友嗣世德，古風藹有餘。", "幸遇漢文皇，握蘭佩金魚。", "俯視長沙賦，悽悽將焉如。"]'),
('7a1b7b4e-27e9-44b8-af51-491d3f6f40c5','明道人歸西林求題院額作此送之','徐鉉','唐','唐诗','tang','','[]','昔從岐陽狩，簪纓滿翠微。',48,'全唐诗/poet.tang.42000.json','["昔從岐陽狩，簪纓滿翠微。", "十年勞我夢，今日送師歸。", "曳尾龜應樂，乘軒鶴謾肥。", "含情題小篆，將去挂巖扉。"]'),
('8ba95940-f556-48af-8cdc-1a12bef149cf','送宣州丘判官','徐鉉','唐','唐诗','tang','','[]','憲署游從阻，平臺道路賒。',48,'全唐诗/poet.tang.42000.json','["憲署游從阻，平臺道路賒。", "喜君馳後乘，於此會仙槎。", "緩酌遲飛蓋，微吟望綺霞。", "相迎在春渚，暫別莫咨嗟。"]'),
('b96f294d-3da1-463d-80b6-9ca3734f9b79','北使還襄邑道中作','徐鉉','唐','唐诗','tang','','[]','九月三十日，獨行梁宋道。',48,'全唐诗/poet.tang.42000.json','["九月三十日，獨行梁宋道。", "河流激似飛，林葉翻如掃。", "程遙苦晝短，野逈知寒早。", "還家亦不閑，要且還家了。"]'),
('51d1077c-926f-4def-ab5e-1dc1c7029e09','禁中新月','徐鉉','唐','唐诗','tang','','[]','今夕拜新月，沈沈禁署中。',48,'全唐诗/poet.tang.42000.json','["今夕拜新月，沈沈禁署中。", "玉繩疎間彩，金掌靜無風。", "節換知身老，時平見歲功。", "吟看北墀暝，蘭燼墜微紅。"]'),
('d93af8ae-752e-432c-b230-479984b15e73','觀吉王從謙花燭','徐鉉','唐','唐诗','tang','','[]','王門嘉禮萬人觀，況是新承置醴歡。',64,'全唐诗/poet.tang.42000.json','["王門嘉禮萬人觀，況是新承置醴歡。", "花燭喧闐丞相府，星辰搖動遠遊冠。", "歌聲暫闋聞宮漏，雲影初開見露盤。", "帝里佳期頻賦頌，長留故事在金鑾。"]'),
('fb68fe81-b62c-4f80-8adc-f3e30cd071cf','棊賭賦詩輸劉起居','徐鉉','唐','唐诗','tang','','[]','刻燭知無取，爭先素未精。',48,'全唐诗/poet.tang.42000.json','["刻燭知無取，爭先素未精。", "本圖忘物我，何必計輸贏。", "賭墅終規利，焚囊亦近名。", "不如相視笑，高詠兩三聲。"]'),
('73322167-4096-4faa-b3de-7ba30a9f0dc7','春盡日游後湖贈劉起居','徐鉉','唐','唐诗','tang','','[]','今朝湖上送春歸，萬頃澄波照白髭。',16,'全唐诗/poet.tang.42000.json','["今朝湖上送春歸，萬頃澄波照白髭。"]'),
('bed660c3-f848-441b-8d9b-00388a16360e','送察院李侍御使廬陵因寄孟員外','徐鉉','唐','唐诗','tang','','[]','繡衣乘驛急如星，山水何妨寄野情。',32,'全唐诗/poet.tang.42000.json','["繡衣乘驛急如星，山水何妨寄野情。", "肯向九仙臺下歇，閑聽孟叟醉吟聲。"]'),
('bd54c32e-5332-44c9-9bb0-b7ef21ca609b','後湖訪古各賦一題得西邸','徐鉉','唐','唐诗','tang','','[]','南朝藩閫地，八友舊招尋。',48,'全唐诗/poet.tang.42000.json','["南朝藩閫地，八友舊招尋。", "事往山光在，春晴草色深。", "曲池魚自樂，叢桂鳥頻吟。", "今日中興運，猶懷翰墨林。"]'),
('708eb6d6-bb17-43b0-9f6a-ff632c968fcf','送德邁道人之豫章','徐鉉','唐','唐诗','tang','','[]','禪靈橋畔落殘花，橋上離情對日斜。',64,'全唐诗/poet.tang.42000.json','["禪靈橋畔落殘花，橋上離情對日斜。", "顧我乘軒慙組綬，羨師飛錫指煙霞。", "樓中西嶺真君宅，門外南州處士家。", "莫道空談便無事，碧雲詩思更無涯。"]'),
('85d88083-5e91-4ea9-b2d6-747242b8046b','送陳祕監歸泉州','徐鉉','唐','唐诗','tang','','[]','風滿潮溝木葉飛，水邊行客駐驂騑。',64,'全唐诗/poet.tang.42000.json','["風滿潮溝木葉飛，水邊行客駐驂騑。", "三朝恩澤馮唐老，萬里鄉關賀監歸。", "世路窮通前事遠，半生談笑此心違。", "離歌不識高堂慶，特地令人淚滿衣。"]'),
('0814f079-0743-44c5-ab9e-632d711f4787','又聽霓裳羽衣曲送陳君','徐鉉','唐','唐诗','tang','','[]','清商一曲遠人行，桃葉津頭月正明。',32,'全唐诗/poet.tang.42000.json','["清商一曲遠人行，桃葉津頭月正明。", "此是開元太平曲，莫教偏作別離聲。"]'),
('9dbdcd37-8aea-473d-9a10-7d16a666babf','又題白鷺洲江鷗送陳君','徐鉉','唐','唐诗','tang','','[]','白鷺洲邊江路斜，輕鷗按翼滿平沙。',128,'全唐诗/poet.tang.42000.json','["白鷺洲邊江路斜，輕鷗按翼滿平沙。", "吾徒來送遠行客，停舟爲爾長歎息。", "酒旗魚艇兩無猜，月影蘆花鎮相得。", "離筵一曲怨復清，滿座銷魂鳥不驚。", "人生不及水禽樂，安用虛名上麟閣。", "同心攜手今如此，金鼎丹砂何寂寞。", "天涯後會眇難期，從此又應添白髭。", "願君不忘分飛處，長保翩翩潔白姿。"]'),
('ed5a4082-d507-4d8a-a9a5-d6679d8d766c','哭刑部侍郎喬公詩','徐鉉','唐','唐诗','tang','','[]','舉世重文雅，夫君更質真。',120,'全唐诗/poet.tang.42000.json','["舉世重文雅，夫君更質真。", "曾嗟混雞鶴，終日異淄磷。", "詞賦離騷客，封章諫諍臣。", "襟懷道家侶，標格古時人。", "逸老誠云福，遺形未免貧。", "求文空得草，埋玉遂爲塵。", "靜想忘年契，冥思按武晨。", "連宵洽杯酒，分日掌絲綸。", "蠹簡書陳事，遺孤託世親。", "前賢同此歎，非我獨霑巾。"]'),
('4eff3617-229a-4315-94c4-980093a0d504','送程德琳郎中學士','徐鍇','唐','唐诗','tang','','[]','瓜步妖氛滅，崑岡草樹青。',48,'全唐诗/poet.tang.42000.json','["瓜步妖氛滅，崑岡草樹青。", "終朝空望極，今日送君行。", "報政秋雲靜，微吟曉月生。", "樓中長可見，特用滅離情。"]'),
('b9dbd321-84eb-4dc1-baf4-1daa7a4321fe','太傅相公以東觀庭梅西垣舊植昔陪盛賞今獨家兄唱和之餘俾令攀和輙依本韻伏愧斐然','徐鍇','唐','唐诗','tang','','[]','靜對含章樹，閑思共有時。',50,'全唐诗/poet.tang.42000.json','["靜對含章樹，閑思共有時。", "香隨荀令在，根異武昌移。", "物性雖搖落，人心豈變衰。", "唱酬勝笛曲，來往韻朱[絲]。"]'),
('66ae3878-36e2-44f7-ae6f-d24d5976a7ac','太傅相公與家兄梅花詶唱許綴末篇再賜新詩俯光拙句謹奉清韻用感鈞私伏惟采覽','徐鍇','唐','唐诗','tang','','[]','重歎梅花落，非關塞笛悲。',48,'全唐诗/poet.tang.42000.json','["重歎梅花落，非關塞笛悲。", "論文叨接萼，末曲愧吹篪。", "枝逐清風動，香因白雪知。", "陶鈞敷左悌，更賦邵公詩。"]'),
('c342681c-c0e4-4c44-90f7-d247d228fd0e','同家兄哭喬侍郎','徐鍇','唐','唐诗','tang','','[]','諸公長者鄭當時，事事無心性坦夷。',64,'全唐诗/poet.tang.42000.json','["諸公長者鄭當時，事事無心性坦夷。", "但是登臨皆有作，未嘗相見不伸眉。", "生前適意無過酒，身後遺言只要詩。", "三日笑談成理命，一篇投弔尚應知。"]'),
('62a59127-ec42-4ead-a8dc-9a7eaf5b6e12','秋詞','徐鍇','唐','唐诗','tang','','[]','井梧紛墮砌，寒雁遠橫空。',26,'全唐诗/poet.tang.42000.json','["井梧紛墮砌，寒雁遠橫空。", "雨久[莓]苔紫，霜濃薜荔紅。"]'),
('749502c2-a0f7-4be8-a7e9-8a19f30596b2','和徐鼎臣見寄','包頴','唐','唐诗','tang','','[]','平生中表最情親，浮世那堪聚散頻。',64,'全唐诗/poet.tang.42000.json','["平生中表最情親，浮世那堪聚散頻。", "謝朓去吟歸省閣，劉楨猶自臥漳濱。", "舊游半似前生事，要路多逢後進人。", "且喜新吟報強健，明年相望杏園春。"]'),
('9afc707f-0640-4b4a-b740-769420d099c2','貽耀州將','鍾謨','唐','唐诗','tang','','[]','翩翩歸盡塞垣鴻，隱隱驚開蟄戶蟲。',64,'全唐诗/poet.tang.42000.json','["翩翩歸盡塞垣鴻，隱隱驚開蟄戶蟲。", "渭北離愁春色裏，江南家事戰塵中。", "還同逐客紉蘭佩，誰聽縲囚奏土風。", "多謝賢侯振吾道，免令搔首泣途窮。"]'),
('e3972438-28fb-4d53-ba32-319a79fa0319','獻周世宗','鍾謨','唐','唐诗','tang','','[]','三年耀武羣雄服，一日回鑾萬國春。',32,'全唐诗/poet.tang.42000.json','["三年耀武羣雄服，一日回鑾萬國春。", "南北通歡永無事，謝恩歸去老陪臣。"]'),
('8db7eb16-3521-47c6-b489-d6844aa1c81a','代京妓越賓荅徐鉉','鍾謨','唐','唐诗','tang','','[]','一幅輕綃寄海濱，越姑長感昔時恩。',32,'全唐诗/poet.tang.42000.json','["一幅輕綃寄海濱，越姑長感昔時恩。", "欲知別後情多少，點點憑君看淚痕。"]'),
('10690ae2-a50f-407b-aa9e-4f3b3b9e9f8c','寄麻姑仙壇道士','查文徽','唐','唐诗','tang','','[]','別後相思鶴信稀，郡樓南望遠峰迷。',64,'全唐诗/poet.tang.42000.json','["別後相思鶴信稀，郡樓南望遠峰迷。", "人歸仙洞雲連地，花落春林水滿溪。", "白髮只應悲鏡鑷，丹砂猶待寄刀圭。", "方平車駕今何在，常苦塵中日易西。"]'),
('6084b90d-8dd5-4cde-92de-f0b7b59e7959','贈韓定辭','馬彧','唐','唐诗','tang','','[]','燧林芳草綿綿思，盡日相攜陟麗譙。',32,'全唐诗/poet.tang.42000.json','["燧林芳草綿綿思，盡日相攜陟麗譙。", "別後巏嵍山上望，羨君時復見王喬。"]'),
('e7b374ca-5c3a-4568-9060-0cd9721accfe','答馬彧','韓定辭','唐','唐诗','tang','','[]','崇霞臺上神仙客，學辨癡龍藝最多。',32,'全唐诗/poet.tang.42000.json','["崇霞臺上神仙客，學辨癡龍藝最多。", "盛德好將銀管述，麗詞堪與雪兒歌。"]'),
('db652f85-1276-487d-814e-796920f26d98','題楊克儉池館','何昌齡','唐','唐诗','tang','','[]','經旬因雨不重來，門有蛛絲徑有苔。',32,'全唐诗/poet.tang.42000.json','["經旬因雨不重來，門有蛛絲徑有苔。", "再向白蓮亭上望，不知花木爲誰開。"]'),
('4798acb6-7d38-4d65-8696-033fadc34f56','獻江淮郡守盧公','李羽','唐','唐诗','tang','','[]','塞詔東來淝水濱，時情惟望秉陶鈞。',32,'全唐诗/poet.tang.42000.json','["塞詔東來淝水濱，時情惟望秉陶鈞。", "將軍一陣爲功業，忍見沙塲百戰人。"]'),
('b005625f-2fa7-457f-97f0-6c8fc22ba6b4','南山池','梁藻','唐','唐诗','tang','','[]','翡翠戲翻荷葉雨，鷺鷥飛破竹林煙。',32,'全唐诗/poet.tang.42000.json','["翡翠戲翻荷葉雨，鷺鷥飛破竹林煙。", "時沽村酒臨軒酌，擬摘新茶靠石煎。"]'),
('e0e441fe-8fac-4ae5-b493-f54e7fbfaa04','嘲廬山道士','陳沆','唐','唐诗','tang','','["\u5e90\u5c71"]','啖肉先生欲上昇，黃雲踏破紫雲崩。',32,'全唐诗/poet.tang.42000.json','["啖肉先生欲上昇，黃雲踏破紫雲崩。", "龍腰鶴背無多力，傳與麻姑借大鵬。"]'),
('f8845da3-c254-498d-8481-8d5bd05c2c95','句','陳沆','唐','唐诗','tang','','[]','罷却兒女戲，放他花木生。',40,'全唐诗/poet.tang.42000.json','["罷却兒女戲，放他花木生。", "掃地雲黏箒，耕山鳥怕牛。", "點入旱雲千國仰，力浮塵世一毫輕。"]'),
('dd30d356-9c60-4689-afe6-df65886a2c68','贈織錦人','李詢','唐','唐诗','tang','','[]','札札機聲曉復晡，眼穿力盡竟何如。',32,'全唐诗/poet.tang.42000.json','["札札機聲曉復晡，眼穿力盡竟何如。", "美人一曲成千賜，心裏猶嫌花樣疎。"]'),
('d80bf62a-7a94-4009-ab3e-b61adc86797d','題金山','韓垂','唐','唐诗','tang','','[]','靈山一峰秀，岌然殊衆山。',48,'全唐诗/poet.tang.42000.json','["靈山一峰秀，岌然殊衆山。", "盤根大江底，插影浮雲間。", "雷霆常間作，風雨時往還。", "象外懸清影，千載長躋攀。"]'),
('551d99e1-9262-4c84-bd8a-f77183a44c93','後湖','朱存','唐','唐诗','tang','','[]','雷轟疊鼓火翻旗，三異翩翩試水師。',32,'全唐诗/poet.tang.42000.json','["雷轟疊鼓火翻旗，三異翩翩試水師。", "驚起黑龍眠不得，狂風猛雨不多時。"]'),
('750b38aa-fea0-4378-89a1-81367990b222','和徐舍人九月十一日見寄','陳彥','唐','唐诗','tang','','[]','衡門寂寂逢迎少，不見仙郎向五旬。',32,'全唐诗/poet.tang.42000.json','["衡門寂寂逢迎少，不見仙郎向五旬。", "莫問龍山前日事，菊花開却爲閑人。"]'),
('58ef9510-fde1-41ce-adbf-9fe5fad72f81','登游齊山','許堅','唐','唐诗','tang','','[]','星使南馳入楚重，此山偏得駐行蹤。',32,'全唐诗/poet.tang.42000.json','["星使南馳入楚重，此山偏得駐行蹤。", "落花滿地月華冷，寂寞舊山三四峰。"]'),
('f9b773c4-38f6-45fa-a92a-22721e3b8b5a','遊溧陽下山寺','許堅','唐','唐诗','tang','','[]','地枕吳溪與越峰，前朝恩錫靈泉額。',64,'全唐诗/poet.tang.42000.json','["地枕吳溪與越峰，前朝恩錫靈泉額。", "竹林晴見雁塔高，石室曾棲幾禪伯。", "荒碑字沒秋苔深，古池香泛荷花白。", "客有經年說別林，落日啼猨情脈脈。"]'),
('9e1a5951-1619-41c7-9efe-91df3e38e555','題幽棲觀','許堅','唐','唐诗','tang','','[]','仙翁上昇去，丹井寄晴壑。',48,'全唐诗/poet.tang.42000.json','["仙翁上昇去，丹井寄晴壑。", "山色接天台，湖光照寥廓。", "玉洞絕無人，老檜猶棲鶴。", "我欲掣青蛇，他時沖碧落。"]'),
('61dadf1b-572e-49d4-8e33-893efc780576','上舍人徐鉉','許堅','唐','唐诗','tang','','[]','幾宵煙月鎖樓臺，欲寄侯門薦下才。',32,'全唐诗/poet.tang.42000.json','["幾宵煙月鎖樓臺，欲寄侯門薦下才。", "滿面塵埃人不識，謾隨流水出山來。"]'),
('da8d379c-6683-40c7-8bcd-5d26351ac27b','題茅山觀','許堅','唐','唐诗','tang','','[]','常恨清風千載鬱，洞天令得恣遊遨。',64,'全唐诗/poet.tang.42000.json','["常恨清風千載鬱，洞天令得恣遊遨。", "松楸古色玉壇靜，鸞鶴不來青漢高。", "茅氏井寒丹已化，玄宗碑斷夢仍勞。", "分明有箇長生路，休向紅塵嘆二毛。"]'),
('800c2286-cd08-4e5d-98dc-22d44e73bb4f','建州節帥更代筵上獻詩','王感化','唐','唐诗','tang','','[]','旌旗赴天臺，溪山曉色開。',24,'全唐诗/poet.tang.42000.json','["旌旗赴天臺，溪山曉色開。", "萬家悲更喜，迎佛送如來。"]'),
('4c7a8ac1-5430-4fc6-8bd4-ee614d350e95','奉元宗命詠苑中白野鵲','王感化','唐','唐诗','tang','','[]','碧岩深洞恣遊遨，天與蘆花作羽毛。',32,'全唐诗/poet.tang.42000.json','["碧岩深洞恣遊遨，天與蘆花作羽毛。", "要識此來棲宿處，上林瓊樹一枝高。"]'),
('f71327c2-8221-4a34-b813-45c0700e55d0','句','王感化','唐','唐诗','tang','','[]','草中誤認將軍虎，山上曾爲道士羊。',16,'全唐诗/poet.tang.42000.json','["草中誤認將軍虎，山上曾爲道士羊。"]'),
('7a65863f-894e-40a2-8082-e2196d82c77c','元宗釣魚無獲進詩','李家明','唐','唐诗','tang','','[]','玉甃垂鉤興正濃，碧池春暖水溶溶。',34,'全唐诗/poet.tang.42000.json','["玉甃垂鉤興正濃，碧池春暖水溶溶。", "凡鱗不敢吞香[餌]，知是君王合釣龍。"]'),
('e7c48e94-5c96-49b6-b07a-41440693a8e8','詠臥牛','李家明','唐','唐诗','tang','','[]','曾遭甯戚鞭敲角，又被田單火燎身。',32,'全唐诗/poet.tang.42000.json','["曾遭甯戚鞭敲角，又被田單火燎身。", "閑向斜陽嚼枯草，近來問喘爲無人。"]'),
('bfcb2873-5911-42b5-b375-357186a48928','題紙鳶止宋齊丘哭子','李家明','唐','唐诗','tang','','[]','安排唐祚革強吳，盡是先生作計謨。',35,'全唐诗/poet.tang.42000.json','["安排唐祚革強吳，盡是先生作計謨。", "一個孩兒{扌棄}不得，讓皇百口合何如。"]'),
('20a5cacf-2dd1-4d01-8e16-ef9de428f825','詠皖公山','李家明','唐','唐诗','tang','','[]','龍舟輕颭錦帆風，正值宸游望遠空。',32,'全唐诗/poet.tang.42000.json','["龍舟輕颭錦帆風，正值宸游望遠空。", "迴首皖公山色翠，影斜不到壽杯中。"]'),
('2e2d26a1-d095-4897-95da-315233ab853a','奉和聖制送鄧王牧宣城','湯悅','唐','唐诗','tang','','[]','千里陵陽同[陝]服，鑿門胙土寄親賢。',66,'全唐诗/poet.tang.42000.json','["千里陵陽同[陝]服，鑿門胙土寄親賢。", "曙煙已別黃金殿，晚照重登白玉筵。", "江上浮光宜雨後，郡中遠岫列窗前。", "天心待報期年政，留與工師播管弦。"]'),
('3d363820-7f8c-4bca-b922-cc0d6e25e1fd','早春寄華下同志','湯悅','唐','唐诗','tang','','[]','正是花時節，思君寢復興。',48,'全唐诗/poet.tang.42000.json','["正是花時節，思君寢復興。", "市沽終不醉，春夢亦無憑。", "嶽面懸清雨，河心走濁冰。", "東門一條路，離恨正相仍。"]'),
('ab9fc52c-8748-4653-8cd6-9aa1a1808a92','鼎臣學士侍郎以東館庭梅昔翰苑之毫末今復半枯向時同僚零落都盡素𩬇垂領茲唯二人感舊傷懷發於吟詠惠然好我不能無言輙次來韻攀和','湯悅','唐','唐诗','tang','','[]','憶見萌芽日，還憐合抱時。',48,'全唐诗/poet.tang.42000.json','["憶見萌芽日，還憐合抱時。", "舊歡如夢想，物態暗還移。", "素豔今無幾，朱顏亦自衰。", "樹將人共老，何暇更悲絲。"]'),
('fddd2f11-7ef7-4229-9a95-dcbfab35e2ea','再次前韻代梅荅','湯悅','唐','唐诗','tang','','[]','託植經多稔，頃筐向盛時。',48,'全唐诗/poet.tang.42000.json','["託植經多稔，頃筐向盛時。", "枝條雖已故，情分不曾移。", "莫向堦前老，還同鏡裏衰。", "更應憐墮葉，殘吹挂蟲絲。"]'),
('f746f91a-f0f9-4b89-bc69-f9f525fb9550','鼎臣學士侍郎楚金舍人學士以再傷庭梅詩同垂寵和清絕感歎情致俱深因成四十字陳謝','湯悅','唐','唐诗','tang','','[]','人物同遷謝，重成念舊悲。',50,'全唐诗/poet.tang.42000.json','["人物同遷謝，重成念舊悲。", "連華得瓊玖，合奏發塤篪。", "餘枿雖無取，殘芳尚獲知。", "問君何所似，珍重杜[秋]詩。"]'),
('e23f91ac-0f02-4281-8323-20aca4df7e10','送鍾員外','蕭彧','唐','唐诗','tang','','[]','麗漢金波滿，當筵玉斚傾。',48,'全唐诗/poet.tang.42000.json','["麗漢金波滿，當筵玉斚傾。", "因思頻聚散，幾復換虧盈。", "光徹離襟冷，聲符別管清。", "那堪還目此，兩地倚樓情。"]'),
('03134fb5-0a60-4b7c-86b4-67bd53ef0ff0','送德林郎中學士赴東府','蕭彧','唐','唐诗','tang','','[]','離情折楊柳，此別異春哉。',48,'全唐诗/poet.tang.42000.json','["離情折楊柳，此別異春哉。", "含露東籬豔，汎香南浦杯。", "惜持行次贈，留插醉中迴。", "暮齒如能制，玉山甘判頹。"]'),
('23347f25-c769-4d8e-b2f6-97a28433bfc3','送鍾員外','孫峴','唐','唐诗','tang','','[]','萬物中蕭灑，修篁獨逸羣。',48,'全唐诗/poet.tang.42000.json','["萬物中蕭灑，修篁獨逸羣。", "貞姿曾冒雪，高節欲凌雲。", "細韻風初發，濃煙日正曛。", "因題偏惜別，不可暫無君。"]'),
('ae996842-f73a-49d2-8b43-b6857c121f45','送鍾員外','謝仲宣','唐','唐诗','tang','','[]','送人多折柳，唯我獨吟松。',48,'全唐诗/poet.tang.42000.json','["送人多折柳，唯我獨吟松。", "若保歲寒在，何妨霜雪重。", "森梢逢靜境，廓落見孤峰。", "還似君高節，亭亭尠繼蹤。"]'),
('bcecfc1f-3f0a-4043-80f9-3e0b807cac2c','別諸同志','鍾蒨','唐','唐诗','tang','','["\u957f\u6c5f"]','隨陽來萬里，點點度遙空。',48,'全唐诗/poet.tang.42000.json','["隨陽來萬里，點點度遙空。", "影落長江水，聲悲半夜風。", "殘秋辭絕漠，無定似驚蓬。", "我有離羣恨，飄飄類此鴻。"]'),
('044bdca9-a368-4d15-a60b-68a1123bbce7','送德林郎中學士赴東府','喬舜','唐','唐诗','tang','','[]','摻袂向江頭，朝宗勢未休。',48,'全唐诗/poet.tang.42000.json','["摻袂向江頭，朝宗勢未休。", "何人乘桂楫，之子過揚州。", "颯颯翹沙鴈，漂漂逐浪鷗。", "欲知離別恨，半是淚和流。"]'),
('3ae9cded-664d-415c-b303-e8ffa24f9d74','送鍾員外','王沂','唐','唐诗','tang','','[]','靜追蘋末興，況復值蕭條。',48,'全唐诗/poet.tang.42000.json','["靜追蘋末興，況復值蕭條。", "猛勢資新鴈，寒聲伴暮潮。", "過山雲散亂，經樹葉飄颻。", "今日煙江上，征帆望望遙。"]'),
('273ea6f9-df47-4565-8c57-9cfba4c95046','送德林郎中學士赴東府','陳元裕','唐','唐诗','tang','','[]','上善湛然秋，恩波洽帝猷。',48,'全唐诗/poet.tang.42000.json','["上善湛然秋，恩波洽帝猷。", "謾言生險浪，豈爽見安流。", "汎去星槎遠，澄來月練浮。", "滔滔對離酌，入洛稱仙舟。"]'),
('623f0477-a29a-425f-831a-d4497e6e1c5a','宿山寺','孟貫','唐','唐诗','tang','','[]','溪山盡日行，方聽遠鐘聲。',48,'全唐诗/poet.tang.42000.json','["溪山盡日行，方聽遠鐘聲。", "入院逢僧定，登樓見月生。", "露垂群木潤，泉落一岩清。", "此景關吾事，通宵寐不成。"]'),
('c723c4e4-958e-47f7-843f-2920a4228413','贈棲隱洞譚先生','孟貫','唐','唐诗','tang','','[]','先生雙鬢華，深谷臥雲霞。',48,'全唐诗/poet.tang.42000.json','["先生雙鬢華，深谷臥雲霞。", "不伐有巢樹，多移無主花。", "石泉春釀酒，松火夜煎茶。", "因問山中事，如君有幾家。"]'),
('7d74e332-3dc0-4c1d-89b1-798d2b32cfd8','歸鴈','孟貫','唐','唐诗','tang','','[]','春至衡陽鴈，思歸塞路長。',48,'全唐诗/poet.tang.42000.json','["春至衡陽鴈，思歸塞路長。", "汀洲齊奮翼，霄漢共成行。", "雪盡翻風暖，寒收度月涼。", "直應到秋日，依舊返瀟湘。"]'),
('d9db58b5-7a49-416c-9d28-d881795a0c04','春江送人','孟貫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','春江多去情，相去枕長汀。',48,'全唐诗/poet.tang.42000.json','["春江多去情，相去枕長汀。", "數鴈別湓浦，片帆離洞庭。", "雨餘沙草綠，雲散岸峰青。", "誰共觀明月，漁歌夜好聽。"]'),
('1c4b724a-98fd-44df-a837-f48763f6cb40','過秦嶺','孟貫','唐','唐诗','tang','','[]','古今傳此嶺，高下勢崢嶸。',48,'全唐诗/poet.tang.42000.json','["古今傳此嶺，高下勢崢嶸。", "安得青山路，化爲平地行。", "蒼苔留虎跡，碧樹障溪聲。", "欲過一回首，踟躕無限情。"]'),
('6cc88451-6931-4e93-b669-0c2b7bf69b34','送吳夢誾歸閩','孟貫','唐','唐诗','tang','','[]','甌閩在天末，此去整行衣。',48,'全唐诗/poet.tang.42000.json','["甌閩在天末，此去整行衣。", "久客逢春盡，思家冒暑歸。", "海雲添晚景，山瘴滅晴暉。", "相憶吟偏苦，不堪書信稀。"]'),
('e11b22c6-a621-44a7-8f7d-fdd28cf9b0d6','山中夏日','孟貫','唐','唐诗','tang','','[]','深山宜避暑，門戶映嵐光。',48,'全唐诗/poet.tang.42000.json','["深山宜避暑，門戶映嵐光。", "夏木蔭溪路，晝雲埋石牀。", "心源澄道靜，衣葛蘸泉涼。", "算得紅塵裏，誰知此興長。"]'),
('d9b8f564-151c-49e1-be47-2b051da14307','宿故人江居','孟貫','唐','唐诗','tang','','[]','渡口樹冥冥，南山漸隱青。',48,'全唐诗/poet.tang.42000.json','["渡口樹冥冥，南山漸隱青。", "漁舟歸舊浦，鷗鳥宿前汀。", "靜榻懸燈坐，閑門對浪扃。", "相思頻到此，幾番醉還醒。"]'),
('04c539e6-5dfa-406a-848d-99f109cf578b','寄伍喬','孟貫','唐','唐诗','tang','','[]','蹉跎春又晚，天末信來遲。',48,'全唐诗/poet.tang.42000.json','["蹉跎春又晚，天末信來遲。", "長憶分攜日，正當搖落時。", "獨遊饒旅恨，多事失歸期。", "君看前溪樹，山禽巢幾枝。"]'),
('8f35e245-1e06-4b64-acbf-8b6848925da7','山中訪人不遇','孟貫','唐','唐诗','tang','','[]','負琴兼杖藜，特地過巖西。',48,'全唐诗/poet.tang.42000.json','["負琴兼杖藜，特地過巖西。", "已見竹軒閉，又聞山鳥啼。", "長松寒倚谷，細草暗連溪。", "久立無人事，煙霞歸路迷。"]'),
('ef6e2036-87e4-48b8-a530-989e1366a1a8','贈隱者','孟貫','唐','唐诗','tang','','[]','世路爭名利，深山獨結茅。',48,'全唐诗/poet.tang.42000.json','["世路爭名利，深山獨結茅。", "安情自得所，非道豈相交。", "百尺松當戶，千年鶴在巢。", "知君於此景，未欲等閑拋。"]'),
('20dc452e-c782-4507-bf4d-3e7f999d28b2','寄暹上人','孟貫','唐','唐诗','tang','','[]','聞罷城中講，來安頂上禪。',48,'全唐诗/poet.tang.42000.json','["聞罷城中講，來安頂上禪。", "夜燈明石室，清磐出巖泉。", "欲訪慙多事，相思恨隔年。", "終期息塵慮，接話虎溪邊。"]'),
('20e2c5f8-2d12-4251-8af4-0021dcb56cc7','江邊閑步','孟貫','唐','唐诗','tang','','[]','閑來南渡口，迤邐看江楓。',48,'全唐诗/poet.tang.42000.json','["閑來南渡口，迤邐看江楓。", "一路波濤畔，數家蘆葦中。", "遠汀排晚樹，深浦漾寒鴻。", "吟罷慵回首，此情誰與同。"]'),
('06c7d5bd-7e3e-4b48-b81b-f10192ec994e','過王逸人園林','孟貫','唐','唐诗','tang','','[]','谷口何時住，煙霞一徑深。',48,'全唐诗/poet.tang.42000.json','["谷口何時住，煙霞一徑深。", "水聲離遠洞，山色出疎林。", "雪彩從沾鬢，年光不計心。", "自言人少到，猶喜我來尋。"]'),
('7f08c487-bac5-4525-a8c5-3b433e3c6715','寄李處士','孟貫','唐','唐诗','tang','','[]','僧話磻溪叟，平生重赤松。',48,'全唐诗/poet.tang.42000.json','["僧話磻溪叟，平生重赤松。", "夜堂悲蟋蟀，秋水老芙蓉。", "吟坐倦垂釣，閑行多倚筇。", "聞名來已久，未得一相逢。"]'),
('f664c812-ecd9-4246-bdc0-36d9e8f910a4','夏日寄史處士','孟貫','唐','唐诗','tang','','[]','掩關苔滿地，終日坐騰騰。',48,'全唐诗/poet.tang.42000.json','["掩關苔滿地，終日坐騰騰。", "暑氣冷衣葛，暮雲催燭燈。", "寂寥知得趣，疎嬾似無能。", "還憶舊遊否，何年別杜陵。"]'),
('0a9b6a4b-ce02-4c02-91a7-6f2028438df2','夏日登瀑頂寺因寄諸知己','孟貫','唐','唐诗','tang','','[]','曾於塵裏望，此景在煙霄。',48,'全唐诗/poet.tang.42000.json','["曾於塵裏望，此景在煙霄。", "巖靜水聲近，山深暑氣遙。", "杖藜青石路，煮茗白雲樵。", "寄語爲郎者，誰能訪寂寥。"]'),
('a7cfba21-ad4c-4d1a-bac1-890660849074','懷果上人','孟貫','唐','唐诗','tang','','[]','擁錫南遊去，名香幾處焚。',48,'全唐诗/poet.tang.42000.json','["擁錫南遊去，名香幾處焚。", "別來無遠信，多恐在深雲。", "好月曾同步，幽香省共聞。", "相思不相見，林下葉紛紛。"]'),
('a8b1b4bf-7453-465e-944a-1fbafa8b8069','寄故園兄弟','孟貫','唐','唐诗','tang','','[]','久與鄉關阻，風塵損舊衣。',48,'全唐诗/poet.tang.42000.json','["久與鄉關阻，風塵損舊衣。", "水思和月泛，山憶共僧歸。", "林想添鄰舍，溪應改釣磯。", "弟兄無苦事，不用別庭闈。"]'),
('23db21d3-d86d-42e5-a0db-dc43301cc6bb','早秋吟眺','孟貫','唐','唐诗','tang','','[]','新秋初雨後，獨立對遙山。',48,'全唐诗/poet.tang.42000.json','["新秋初雨後，獨立對遙山。", "去鳥望中沒，好雲吟裏還。", "長年慙道薄，明代取身閑。", "從有西征思，園林嬾閉關。"]'),
('4056ef9a-8c23-47ee-868e-48596a7a3721','送江爲歸嶺南','孟貫','唐','唐诗','tang','','[]','舊山臨海色，歸路到天涯。',48,'全唐诗/poet.tang.42000.json','["舊山臨海色，歸路到天涯。", "此別各多事，重逢是幾時。", "江行晴望遠，嶺宿夜吟遲。", "珍重南方客，清風失所思。"]'),
('ae06ee63-7a6a-483c-9ef8-701a5a7ed15b','山中荅友人','孟貫','唐','唐诗','tang','','[]','偶愛春山在，因循值暑時。',48,'全唐诗/poet.tang.42000.json','["偶愛春山在，因循值暑時。", "風塵非所願，泉石本相宜。", "坐久松陰轉，吟餘蟬韻移。", "自慙疎野甚，多失故人期。"]'),
('e66e7b51-5572-434f-9dc0-e631f7838f73','山齋早秋雨中','孟貫','唐','唐诗','tang','','[]','深居少往還，卷箔早秋間。',48,'全唐诗/poet.tang.42000.json','["深居少往還，卷箔早秋間。", "雨灑吟蟬樹，雲藏嘯狖山。", "炎蒸如便退，衣葛亦堪閑。", "靜坐得無事，酒巵聊暢顏。"]'),
('b3d91d9e-6933-4ec4-a883-8560ac99d2f1','送人遊南越','孟貫','唐','唐诗','tang','','[]','孑然南越去，替爾畏前程。',48,'全唐诗/poet.tang.42000.json','["孑然南越去，替爾畏前程。", "見說路岐嶮，不通車馬行。", "瘴煙迷海色，嶺樹帶猨聲。", "獨向山家宿，多應鄉思生。"]'),
('08041cb7-e94d-49e2-8bd4-b9ea7e140e85','酬東溪史處士','孟貫','唐','唐诗','tang','','[]','咫尺東溪路，年來偶訪遲。',48,'全唐诗/poet.tang.42000.json','["咫尺東溪路，年來偶訪遲。", "泉聲迷夜雨，花片落空枝。", "石徑逢僧出，山牀見鶴移。", "貧齋有琴酒，曾許月圓期。"]'),
('a6906983-cde2-46ca-8bea-4acb667434cb','秋江送客','孟貫','唐','唐诗','tang','','[]','秋風楚江上，送子話遊遨。',48,'全唐诗/poet.tang.42000.json','["秋風楚江上，送子話遊遨。", "遠水宿何處，孤舟春夜濤。", "浦雲沈鴈影，山月照猨嗥。", "莫爲飢寒苦，便成名利勞。"]'),
('3131504c-7888-4f19-bdd2-af70edc51814','寄山中高逸人','孟貫','唐','唐诗','tang','','[]','煙霞多放曠，吟嘯是尋常。',48,'全唐诗/poet.tang.42000.json','["煙霞多放曠，吟嘯是尋常。", "猨共摘山果，僧鄰住石房。", "躡雲雙屐冷，採藥一身香。", "我憶相逢夜，松潭月色涼。"]'),
('c9494fca-97a0-4480-9605-cc6dad7cea80','懷友人','孟貫','唐','唐诗','tang','','[]','浮世況多事，飄流每歎君。',48,'全唐诗/poet.tang.42000.json','["浮世況多事，飄流每歎君。", "路岐何處去，消息幾時聞。", "吟裏落秋葉，望中生暮雲。", "孤懷誰慰我，夕鳥自成群。"]'),
('72a9c6b6-d314-4205-8c3e-365c9f2878eb','送人歸別業','孟貫','唐','唐诗','tang','','[]','別業五湖上，春殘去路賒。',48,'全唐诗/poet.tang.42000.json','["別業五湖上，春殘去路賒。", "還尋舊山水，重到故人家。", "門徑掩芳草，園林落異花。", "君知釣磯在，猶喜有生涯。"]'),
('f30fc2c2-f211-4207-b4fb-4aa7a97d8d04','冬日登江樓','孟貫','唐','唐诗','tang','','[]','高樓臨古岸，野步晚來登。',48,'全唐诗/poet.tang.42000.json','["高樓臨古岸，野步晚來登。", "江水因寒落，山雲爲雪凝。", "遠村雖入望，危檻不堪憑。", "親老未歸去，鄉愁徒自興。"]'),
('709fb6d7-36b2-42f6-925a-bbccf91965a1','寄張山人','孟貫','唐','唐诗','tang','','[]','草堂南澗邊，有客嘯雲煙。',48,'全唐诗/poet.tang.42000.json','["草堂南澗邊，有客嘯雲煙。", "掃葉林風後，拾薪山雨前。", "野橋通竹徑，流水入芝田。", "琴月相親夜，更深戀不眠。"]'),
('783b48e9-b456-4c72-a816-fb78ec2b4a1e','杜鵑花','成彥雄','唐','唐诗','tang','','[]','杜鵑花與鳥，怨豔兩何賒。',48,'全唐诗/poet.tang.42000.json','["杜鵑花與鳥，怨豔兩何賒。", "疑是口中血，滴成枝上花。", "一聲寒食夜，數朵野僧家。", "謝豹出不出，日遲遲又斜。"]'),
('768e3bac-d59d-4602-a470-80a34f966006','江上楓','成彥雄','唐','唐诗','tang','','[]','江楓自蓊鬱，不競松筠力。',24,'全唐诗/poet.tang.42000.json','["江楓自蓊鬱，不競松筠力。", "一葉落漁家，殘陽帶秋色。"]'),
('3bdd9246-d1c6-41b0-9350-0af8d67cb577','夜夜曲','成彥雄','唐','唐诗','tang','','[]','自從君去夜，錦幌孤蘭麝。',24,'全唐诗/poet.tang.42000.json','["自從君去夜，錦幌孤蘭麝。", "欹枕對銀缸，秦箏綠窗下。"]'),
('40604fe3-1589-4c10-a501-07aec34ce4fc','村行','成彥雄','唐','唐诗','tang','','[]','曖曖村煙暮，牧童出深塢。',24,'全唐诗/poet.tang.42000.json','["曖曖村煙暮，牧童出深塢。", "騎牛不顧人，吹笛尋山去。"]'),
('21877f45-1a57-4807-9421-b7d934d573ac','煎茶','成彥雄','唐','唐诗','tang','','[]','岳寺春深睡起時，虎跑泉畔思遲遲。',32,'全唐诗/poet.tang.42000.json','["岳寺春深睡起時，虎跑泉畔思遲遲。", "蜀茶倩箇雲僧碾，自拾枯松三四枝。"]'),
('5ae3e7d6-4525-4f7e-b1fb-f00b54dfb1f9','松','成彥雄','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u52b1\u5fd7"]','大夫名價古今聞，盤屈孤貞更出羣。',32,'全唐诗/poet.tang.42000.json','["大夫名價古今聞，盤屈孤貞更出羣。", "將謂嶺頭閑得了，夕陽猶挂數枝雲。"]'),
('7aa27ae8-0d08-440c-a0bb-f84aa1b6b3ed','新燕','成彥雄','唐','唐诗','tang','','[]','纔離海島宿江濱，應夢笙歌作近鄰。',32,'全唐诗/poet.tang.42000.json','["纔離海島宿江濱，應夢笙歌作近鄰。", "減省雕梁竝頭語，畫堂中有未歸人。"]'),
('b959da0b-41f2-4e71-96c7-1a673e3d13f8','會友不至','成彥雄','唐','唐诗','tang','','[]','王孫還是負佳期，玉馬追遊日漸西。',32,'全唐诗/poet.tang.42000.json','["王孫還是負佳期，玉馬追遊日漸西。", "獨上郊原人不見，鷓鴣飛過落花溪。"]'),
('0d745918-a733-4461-90c0-ba05f77f2b75','惜花','成彥雄','唐','唐诗','tang','','[]','忘餐爲戀滿枝紅，錦障頻移護晚風。',32,'全唐诗/poet.tang.42000.json','["忘餐爲戀滿枝紅，錦障頻移護晚風。", "客散酒酣歸未得，欄邊獨立月明中。"]'),
('974f2ad8-33b5-4b1a-8eca-b6bf03a1bad7','中秋月','成彥雄','唐','唐诗','tang','','[]','王母粧成鏡未收，倚欄人在水精樓。',32,'全唐诗/poet.tang.42000.json','["王母粧成鏡未收，倚欄人在水精樓。", "笙歌莫占清光盡，留與溪翁一釣舟。"]'),
('32947a7f-2073-4b93-8be4-b2d4349466fb','暮春日宴溪亭','成彥雄','唐','唐诗','tang','','[]','寒食尋芳遊不足，溪亭還醉綠楊煙。',32,'全唐诗/poet.tang.42000.json','["寒食尋芳遊不足，溪亭還醉綠楊煙。", "誰家花落臨流樹，數片殘紅到檻前。"]'),
('c63c156e-182d-4b65-9689-b5aa857e7e86','曉','成彥雄','唐','唐诗','tang','','[]','列宿回元朝北極，爽神晞露滴樓臺。',32,'全唐诗/poet.tang.42000.json','["列宿回元朝北極，爽神晞露滴樓臺。", "佳人卷箔臨階砌，笑指庭花昨夜開。"]'),
('980c8a82-9fda-43be-a276-7ab9e28cb5cc','夕','成彥雄','唐','唐诗','tang','','[]','臺榭沈沈禁漏初，麝煙紅蠟透蝦鬚。',32,'全唐诗/poet.tang.42000.json','["臺榭沈沈禁漏初，麝煙紅蠟透蝦鬚。", "雕籠鸚鵡將棲宿，不許鵶鬟轉轆轤。"]'),
('177fd90a-473f-4e98-8b2f-d8e9af8f72b7','露','成彥雄','唐','唐诗','tang','','[]','銀河昨夜降醍醐，灑遍坤維萬象蘇。',32,'全唐诗/poet.tang.42000.json','["銀河昨夜降醍醐，灑遍坤維萬象蘇。", "疑是鮫人曾泣處，滿池荷葉捧真珠。"]'),
('348a013e-552a-461d-a2d3-5499d4043881','遊紫陽宮','成彥雄','唐','唐诗','tang','','[]','古殿煙霞簇畫屏，直疑踪跡到蓬瀛。',32,'全唐诗/poet.tang.42000.json','["古殿煙霞簇畫屏，直疑踪跡到蓬瀛。", "碧桃滿地眠花鹿，深院松窗擣藥聲。"]'),
('adfdb8fb-548d-41c7-af61-0ca0aeb11e96','除夜','成彥雄','唐','唐诗','tang','','[]','銅龍看却送春來，莫惜顛狂酒百杯。',32,'全唐诗/poet.tang.42000.json','["銅龍看却送春來，莫惜顛狂酒百杯。", "吟鬢就中專擬白，那堪更被二更催。"]'),
('39b0f2b2-7e38-49ad-9273-fa6bdf685354','元日','成彥雄','唐','唐诗','tang','','[]','戴星先捧祝堯觴，鏡裏堪驚兩鬢霜。',32,'全唐诗/poet.tang.42000.json','["戴星先捧祝堯觴，鏡裏堪驚兩鬢霜。", "好是燈前偷失笑，屠蘇應不得先嘗。"]'),
('ae74b612-2fdf-4565-aa46-e385520b397d','寒夜吟','成彥雄','唐','唐诗','tang','','[]','洞房脉脉寒宵永，燭影香消金鳳冷。',32,'全唐诗/poet.tang.42000.json','["洞房脉脉寒宵永，燭影香消金鳳冷。", "猧兒睡魘喚不醒，滿窗撲落銀蟾影。"]'),
('cf0bd1a2-70c2-470a-8495-0c578fd77966','柳枝辭九首 一','成彥雄','唐','唐诗','tang','','[]','輕籠小徑近誰家，玉馬追風翠影斜。',32,'全唐诗/poet.tang.42000.json','["輕籠小徑近誰家，玉馬追風翠影斜。", "愛把長條惱公子，惹他頭上海棠花。"]'),
('51b73ef4-8018-424d-923c-c6fc4cbbf10b','柳枝辭九首 二','成彥雄','唐','唐诗','tang','','[]','鵝黃剪出小花鈿，綴上芳枝色轉鮮。',32,'全唐诗/poet.tang.42000.json','["鵝黃剪出小花鈿，綴上芳枝色轉鮮。", "飲散無人收拾得，月明階下伴鞦韆。"]'),
('0cd52503-19d8-4253-a57d-dec6cc70f21a','柳枝辭九首 三','成彥雄','唐','唐诗','tang','','[]','東君愛惜與先春，草澤無人處也新。',32,'全唐诗/poet.tang.42000.json','["東君愛惜與先春，草澤無人處也新。", "委囑露華幷細雨，莫教遲日惹風塵。"]'),
('24371f88-4e8c-4406-a28b-60e334804faf','柳枝辭九首 四','成彥雄','唐','唐诗','tang','','[]','句踐初迎西子年，琉璃爲箒掃溪煙。',32,'全唐诗/poet.tang.42000.json','["句踐初迎西子年，琉璃爲箒掃溪煙。", "至今不改當時色，留與王孫繫酒船。"]'),
('43a4bb3f-1ec9-4e63-9ca1-3cdd7b4c9c1d','柳枝辭九首 五','成彥雄','唐','唐诗','tang','','[]','綠楊移傍小亭栽，便擁穠煙撥不開。',32,'全唐诗/poet.tang.42000.json','["綠楊移傍小亭栽，便擁穠煙撥不開。", "誰把金刀爲刪掠，放教明月入窗來。"]'),
('15fa0df4-8fb4-4c1c-8e5d-6d18e10a023d','柳枝辭九首 六','成彥雄','唐','唐诗','tang','','[]','遠接關河高接雲，雨餘洗出半天津。',32,'全唐诗/poet.tang.42000.json','["遠接關河高接雲，雨餘洗出半天津。", "牡丹不用相輕薄，自有清陰覆得人。"]'),
('febb03a8-720d-4281-91ab-3e77b3df58aa','柳枝辭九首 七','成彥雄','唐','唐诗','tang','','[]','掩映鶯花媚有餘，風流才調比應無。',32,'全唐诗/poet.tang.42000.json','["掩映鶯花媚有餘，風流才調比應無。", "朝朝奉御臨池上，不羨青松拜大夫。"]'),
('3c6a7a0a-cb70-4294-96f1-a58b63457bec','柳枝辭九首 八','成彥雄','唐','唐诗','tang','','[]','王孫宴罷曲江池，折取春光伴醉歸。',32,'全唐诗/poet.tang.42000.json','["王孫宴罷曲江池，折取春光伴醉歸。", "怪得美人爭鬬乞，要他穠翠染羅衣。"]'),
('61a046a9-c67f-485c-9116-18784a13ab58','柳枝辭九首 九','成彥雄','唐','唐诗','tang','','[]','殘照林梢嫋數枝，能折醉客上金堤。',32,'全唐诗/poet.tang.42000.json','["殘照林梢嫋數枝，能折醉客上金堤。", "馬嬌如練纓如火，瑟瑟陰中步步嘶。"]'),
('e7969678-cc76-4951-8731-5c358195e3fc','句','成彥雄','唐','唐诗','tang','','[]','莎草放茵深護砌，海榴噴火巧橫牆。',32,'全唐诗/poet.tang.42000.json','["莎草放茵深護砌，海榴噴火巧橫牆。", "紋鱗引子跳銀海，紫燕呼雛語畫梁。"]'),
('37afad39-b55f-4f65-b73a-1f8b20f9e0ca','寄禪月大師','周庠','唐','唐诗','tang','','[]','昨日塵遊到幾家，就中偏省近宣麻。',64,'全唐诗/poet.tang.42000.json','["昨日塵遊到幾家，就中偏省近宣麻。", "水田鋪座時移畫，金地譚空說盡沙。", "傍竹欲添犀浦石，栽松更碾味江茶。", "有時捻得休公卷，倚柱閑吟見落霞。"]'),
('f289049e-cc32-4ff4-b79f-9912fe77226e','寄禪月大師','張格','唐','唐诗','tang','','[]','龍華咫尺斷來音，日夕空馳詠德心。',64,'全唐诗/poet.tang.42000.json','["龍華咫尺斷來音，日夕空馳詠德心。", "禪月字清師號別，壽春詩古帝恩深。", "畫成羅漢驚三界，書似張顛直萬金。", "莫倚名高忘故舊，曉晴閑步一相尋。"]'),
('0276959f-001e-46ce-9c3b-cb2a7e39685d','贈禪月大師','王鍇','唐','唐诗','tang','','[]','長愛吾師性自然，天心白月水中蓮。',64,'全唐诗/poet.tang.42000.json','["長愛吾師性自然，天心白月水中蓮。", "神通力遍恆沙外，詩句名高八米前。", "尋訪不聞朝振錫，修行唯說夜安禪。", "太平時節俱無事，莫惜時來話草玄。"]'),
('58642f5b-b16f-41a3-8f17-f9eb91804e38','奉詔賦蜀主降唐','牛希濟','唐','唐诗','tang','','[]','滿城文武欲朝天，不覺鄰師犯塞煙。',64,'全唐诗/poet.tang.42000.json','["滿城文武欲朝天，不覺鄰師犯塞煙。", "唐主再懸新日月，蜀王難保舊山川。", "非干將相扶持拙，自是君臣數盡年。", "古往今來亦如此，幾曾歡笑幾潸然。"]'),
('c9db58a2-7f2b-47e3-9041-6d3bb59cdcff','蜀獁引 一','馮涓','唐','唐诗','tang','','[]','昂藏大步蠶叢國，曲頸微伸高九尺。',32,'全唐诗/poet.tang.42000.json','["昂藏大步蠶叢國，曲頸微伸高九尺。", "卓女窺窗莫我知，嚴仙據案何曾識。"]'),
('662b7275-3149-4c2a-9f37-8cfa298f08da','蜀獁引 二','馮涓','唐','唐诗','tang','','[]','自古皆傳蜀道難，爾何能過拔蛇山。',32,'全唐诗/poet.tang.42000.json','["自古皆傳蜀道難，爾何能過拔蛇山。", "忽驚登得雞翁磧，又恐礙著鹿頭關。"]'),
('3b1db042-e9eb-4ebd-b4eb-e533898d02a7','句','馮涓','唐','唐诗','tang','','[]','不隨俗物皆成土，只待良時却補天。',32,'全唐诗/poet.tang.42000.json','["不隨俗物皆成土，只待良時却補天。", "釜魚化作池中物，木履浮爲天際船。"]'),
('013e7216-af7e-4d3d-a18f-1fe50fdf1e7d','從幸秦川賦鷙獸詩','李浩弼','唐','唐诗','tang','','[]','巖下年年自寢訛，生靈餐盡意如何。',64,'全唐诗/poet.tang.42000.json','["巖下年年自寢訛，生靈餐盡意如何。", "爪牙衆後民隨減，溪壑深來骨已多。", "天子紀綱猶被弄，客人窮獨固難過。", "長途莫怪無人跡，盡被山王稜殺他。"]'),
('005869f9-aced-4ae8-8092-8556958c7ad4','批子弟理舊居狀','楊玢','唐','唐诗','tang','','[]','四鄰侵我我從伊，畢竟須思未有時。',32,'全唐诗/poet.tang.42000.json','["四鄰侵我我從伊，畢竟須思未有時。", "試上含元殿基望，秋風秋草正離離。"]'),
('4e6adcf7-546f-4f00-8077-501bc252f581','登慈恩寺塔','楊玢','唐','唐诗','tang','','[]','紫雲樓下曲江平，鴉噪殘陽麥隴青。',32,'全唐诗/poet.tang.42000.json','["紫雲樓下曲江平，鴉噪殘陽麥隴青。", "莫上慈恩最高處，不堪看又不堪聽。"]'),
('0ddec308-c20f-4d2b-9fc9-62d8bac74227','遣歌妓','楊玢','唐','唐诗','tang','','[]','垂老無端用意乖，誰知道侶厭清齋。',32,'全唐诗/poet.tang.42000.json','["垂老無端用意乖，誰知道侶厭清齋。", "如今又采蘼蕪去，辜負張君繡靸鞋。"]'),
('5841457a-17e1-450d-9959-ec318bbf2355','和題劒門','韓昭','唐','唐诗','tang','','[]','閉關防老寇，孰敢振威稜。',48,'全唐诗/poet.tang.42000.json','["閉關防老寇，孰敢振威稜。", "險固疑天設，山河自古憑。", "三川奚所賴，雙劒最堪矜。", "鳥道微通處，煙霞鎖百層。"]'),
('ab1665bd-e8ec-4933-96fd-9c1b7e4e91c6','從幸秦川過白衛獻詩','韓昭','唐','唐诗','tang','','[]','吾王巡狩爲安邊，此去秦亭尚數千。',64,'全唐诗/poet.tang.42000.json','["吾王巡狩爲安邊，此去秦亭尚數千。", "夜照路岐山店火，曉通消息戍瓶煙。", "爲雲巫峽雖神女，跨鳳秦樓是謫仙。", "八駿似龍人似虎，何愁飛過大漫天。"]'),
('edc71f03-8d6f-452b-843f-20c4251e6f4d','記皂江墮水事','楊鼎夫','唐','唐诗','tang','','[]','青城山峭皂江寒，欲度當時作等閑。',64,'全唐诗/poet.tang.42000.json','["青城山峭皂江寒，欲度當時作等閑。", "櫂逆狂風趨近岸，舟逢怪石碎前灣。", "手攜弱杖倉皇處，命出洪濤頃刻間。", "今日深恩無以報，令人羞記雀銜環。"]'),
('1be8469b-9c1e-449b-a913-89e4b68f5e6b','題張道隱太山祠畫龍','蔣貽恭','唐','唐诗','tang','','[]','世人空解競丹青，惟子通玄得墨靈。',64,'全唐诗/poet.tang.42000.json','["世人空解競丹青，惟子通玄得墨靈。", "應有鬼神看下筆，豈無風雨助成形。", "威疑噴浪歸滄海，勢欲拏雲上杳冥。", "靜閉綠堂深夜後，曉來簾幕似聞腥。"]'),
('e9be50be-37eb-46ca-8272-a3fdc13664a6','詠蠶','蔣貽恭','唐','唐诗','tang','','["\u6292\u60c5"]','辛勤得繭不盈筐，燈下繅絲恨更長。',32,'全唐诗/poet.tang.42000.json','["辛勤得繭不盈筐，燈下繅絲恨更長。", "著處不知來處苦，但貪衣上繡鴛鴦。"]'),
('6e2b0a66-6ed7-438a-a139-d56c413bac46','漁父歌三首 一','李珣','唐','唐诗','tang','','[]','水接衡門十里餘，信船歸去臥看書。',32,'全唐诗/poet.tang.42000.json','["水接衡門十里餘，信船歸去臥看書。", "輕爵祿，慕玄虛，莫道漁人只爲魚。"]'),
('a1b29dc9-0529-427d-af4a-0081e8abdf46','漁父歌三首 二','李珣','唐','唐诗','tang','','[]','避世垂綸不記年，官高爭得似君閑。',32,'全唐诗/poet.tang.42000.json','["避世垂綸不記年，官高爭得似君閑。", "傾白酒，對青山，笑指柴門待月還。"]'),
('b428affa-cdce-4c01-a7f9-d82068e72d6c','漁父歌三首 三','李珣','唐','唐诗','tang','','[]','棹警鷗飛水濺袍，影侵潭面柳垂條。',32,'全唐诗/poet.tang.42000.json','["棹警鷗飛水濺袍，影侵潭面柳垂條。", "終日醉，絕塵勞，曾見錢塘八月濤。"]'),
('6ee3768c-ee3a-4e4b-b880-579f6b714a3f','感禿鶖潛吟','顧敻','唐','唐诗','tang','','[]','昔日曾看瑞應圖，萬般祥端不如無。',32,'全唐诗/poet.tang.42000.json','["昔日曾看瑞應圖，萬般祥端不如無。", "摩訶池上分明見，仔細看來是那鶘。"]'),
('02458153-7701-4e31-9700-18c116a3df08','與杜光庭','張令問','唐','唐诗','tang','','[]','試問朝中爲宰相，何如林下作神仙。',32,'全唐诗/poet.tang.42000.json','["試問朝中爲宰相，何如林下作神仙。", "一壺美酒一爐藥，飽聽松風白晝眠。"]'),
('ed207df2-47fc-4ea2-8a45-190ce95c9373','題黃居寀秋山圖','徐光溥','唐','唐诗','tang','','[]','天與黃筌藝奇絕，筆精迴感重瞳悅。',384,'全唐诗/poet.tang.42000.json','["天與黃筌藝奇絕，筆精迴感重瞳悅。", "運思潛通造化工，揮毫定得神仙訣。", "秋來奉詔寫秋山，寫在輕綃數幅間。", "高低向背無遺勢，重巒疊嶂何孱顏。", "目想心存妙尤極，研巧覈能狀不得。", "珍禽異獸皆自馴，奇花怪木非因植。", "崎嶇石磴絕遊蹤，薄霧冥冥藏半峰。", "娑蘿掩映迷仙洞，薜荔纍垂繳古松。", "月檻參橋□，僧老坐搘筇。", "屈原江上嬋娟竹，陶潛籬下芳菲菊。", "良宵祗恐鷓鴣啼，晴波但見鴛鴦浴。", "暮煙羃羃鏁村塢，一葉扁舟橫野度。", "颯颯白蘋欲起風，黯黯紅蕉猶帶雨。", "曲沼芙蓉香馥郁，長汀蘆荻花{艹/糓}蓛。", "雁過孤峰帖遠青，鹿傍小溪飲殘綠。", "秋山秀兮秋江靜，江光山色相輝映。", "雪迸飛泉濺釣磯，雲分落葉擁樵徑。", "張璪松石徒稱奇，邊鸞花鳥何足窺。", "白旻鷹逞凌風勢，薛稷鶴誇警露姿。", "方原畫山空巉巖，峭壁枯槎人見嫌。", "孫位畫水多洶湧，驚湍怒濤人見恐。", "若教對此定妍媸，必定伏膺懷愧悚。", "再三展向冕旒側，便是移山回磵力。", "大李小李滅聲華，獻之愷之無顏色。"]'),
('2d40b85a-570b-41c7-bc3e-32dd48dbb5dc','同劉侍郎詠笋','徐光溥','唐','唐诗','tang','','[]','迸出班犀數十株，更添幽景向蓬壺。',32,'全唐诗/poet.tang.42000.json','["迸出班犀數十株，更添幽景向蓬壺。", "出來似有凌雲勢，用作丹梯得也無。"]'),
('61d99ff5-acb2-4d62-bd4c-35e58db8822e','貫休應夢羅漢畫歌','歐陽炯','唐','唐诗','tang','','["\u534e\u5c71"]','西嶽高僧名貫休，孤情峭拔凌清秋。',392,'全唐诗/poet.tang.42000.json','["西嶽高僧名貫休，孤情峭拔凌清秋。", "天教水墨畫羅漢，魁岸古容生筆頭。", "時捎大絹泥高壁，閉目焚香坐禪室。", "忽然夢裏見真儀，脫下袈裟點神筆。", "高握節腕當空擲，窸窣毫端任狂逸。", "逡巡便是兩三軀，不似畫工虛費日。", "怪石安拂嵌復枯，真僧列坐連跏[趺]。", "形如瘦鶴精神健，頂似伏犀頭骨麤。", "倚松根，傍巖縫，曲錄腰身長欲動。", "看經弟子擬聞聲，瞌睡山童疑有夢。", "不知夏臘幾多年，一手搘頤偏袒肩。", "口開或若共人語，身定復疑初坐禪。", "案前臥象低垂鼻，崖畔戲猿斜展臂。", "芭蕉花裏刷輕紅，苔蘚文中暈深翠。", "硬笻杖，矮松牀，雪色眉毛一寸長。", "繩開梵夾兩三片，線補衲衣千萬行。", "林間亂葉紛紛墮，一印殘香斷煙火。", "皮穿木屐不曾拖，笋織蒲團鎮長坐。", "休公休公逸藝無人加，聲譽喧喧遍海涯。", "五七字句一千首，大小篆書三十家。", "唐朝歷歷多名士，蕭子雲兼吳道子。", "若將書畫比休公，只恐當時浪生死。", "休公休公始自江南來入秦，於今到蜀無交親。", "詩名畫手皆奇絕，覰你凡人爭是人。"]'),
('b432f31a-d613-4575-b2dc-072b8343b8fb','題景煥畫應天寺壁天王歌','歐陽炯','唐','唐诗','tang','','["\u5e90\u5c71"]','錦城東北黃金地，故跡何人興此寺。',386,'全唐诗/poet.tang.42000.json','["錦城東北黃金地，故跡何人興此寺。", "白眉長老重名公，曾識會稽山處士。", "寺門左壁圖天王，威儀部從來何方。", "鬼神怪異滿壁走，當簷颯颯生秋光。", "我聞天王分理四天下，水晶宮殿琉璃瓦。", "綵杖時驅狒𤝞裝，金鞭頻策騏驎馬。", "毗沙大像何光輝，手擎巨塔凌雲飛。", "地神對出寶缾子，天女倒披金縷衣。", "唐朝說著名公畫，周昉毫端善圖寫。", "張僧繇是有神人，吳道子稱無敵者。", "奇哉妙手傳孫公，能如此地留神蹤。", "斜窺小鬼怒雙目，直倚越狼高半胸。", "寶冠動總生威容，趨蹌左右來傾恭。", "臂橫鷹爪尖纖利，腰纏虎皮斑剝紅。", "飄飄但恐入雲中，步驟還疑歸海東。", "蟒蛇拖得渾身墮，精魅搦來雙眼空。", "當時此藝實難有，鎮在寶坊稱不朽。", "東邊畫了空西邊，留與後人教敵手。", "後人見者皆心驚，盡爲名公不敢爭。", "誰知未滿三十載，或有異人來間生。", "匡山處士名稱樸，頭骨高奇連五嶽。", "曾持象簡累爲官，又有蛇珠常在握。", "昔年長老遇奇蹤，今日門師識景公。", "興來便請泥高壁，亂搶筆頭如疾風。"]'),
('bcdd13c5-2e1c-4ff8-bfba-9ab6f0260cab','漁父歌二首 一','歐陽炯','唐','唐诗','tang','','[]','擺脫塵機上釣船，免教榮辱有流年。',32,'全唐诗/poet.tang.42000.json','["擺脫塵機上釣船，免教榮辱有流年。", "無繫絆，沒愁煎，須信船中有散仙。"]'),
('c728fe61-d03d-449a-a289-8b9bca87a014','漁父歌二首 二','歐陽炯','唐','唐诗','tang','','[]','風浩寒溪照膽明，小君山上玉蟾生。',32,'全唐诗/poet.tang.42000.json','["風浩寒溪照膽明，小君山上玉蟾生。", "荷露墜，翠煙輕，撥刺遊魚幾處驚。"]'),
('1d68ff6f-2852-4d89-bc66-18345bfabd43','大遊仙詩','歐陽炯','唐','唐诗','tang','','[]','赤城霞起武陵春，桐柏先生解守真。',64,'全唐诗/poet.tang.42000.json','["赤城霞起武陵春，桐柏先生解守真。", "白石橋高曾縱步，朱陽館靜每存神。", "囊中隱訣多仙術，肘後方書濟俗人。", "自領蓬萊都水監，只憂滄海變成塵。"]'),
('508a70ad-8b2d-4db2-b197-0ed342314da2','楊柳枝','歐陽炯','唐','唐诗','tang','','[]','軟碧搖煙似送人，映花時把翠蛾嚬。',32,'全唐诗/poet.tang.42000.json','["軟碧搖煙似送人，映花時把翠蛾嚬。", "青青自是風流主，慢颯金絲待洛神。"]'),
('cc4c9992-415b-450c-8d90-a7a88d8b3006','句','歐陽炯','唐','唐诗','tang','','[]','古人重到今人愛，萬局都無一局同。',16,'全唐诗/poet.tang.42000.json','["古人重到今人愛，萬局都無一局同。"]'),
('ef5354e7-1410-475c-86a9-3fb10ece5269','感懷詩','劉義度','唐','唐诗','tang','','[]','昨日方髽髻，如今滿頷髯。',24,'全唐诗/poet.tang.42000.json','["昨日方髽髻，如今滿頷髯。", "紫閣無心戀，青山有意潛。"]'),
('f7761c55-8be6-4a55-acb2-8f17f8dbd29f','同徐學士詠笋','劉羲叟','唐','唐诗','tang','','[]','徐徐出土非人種，枝葉難投日月壺。',32,'全唐诗/poet.tang.42000.json','["徐徐出土非人種，枝葉難投日月壺。", "爲是因緣生此地，從他長養譬如無。"]'),
('5ef074fb-669e-4ce2-9392-107b219640f3','復留侯從効問南漢劉巖改名龑字音義','詹敦仁','唐','唐诗','tang','','[]','伏羲初畫卦，蒼氏乃製字。',264,'全唐诗/poet.tang.42000.json','["伏羲初畫卦，蒼氏乃製字。", "點畫有偏旁，陰陽貴協比。", "古者不嫌名，周公始稱諱。", "始諱猶未酷，後習轉多忌。", "或援他代易，或變文迴避。", "濫觴久滋蔓，傷心日益熾。", "孫休命子名，吳國尊王意。", "𩅦𦯶𩅔{覀/升}僻，{壴臣}昷𥨆𡚕異。", "梁復踵已非，時亦迹舊事。", "𡽏杰自其一，蜀闖是其二。", "鄙哉化䁈名，陋矣𡏜䵎義。", "大唐有天下，武后擁神器。", "私制迄無取，古音實相類。", "●●●囝星，●●{厓厂=}●埊。", "●圀及曌●，作史難詳備。", "唐祚值傾危，劉龑懷僭僞。", "吁嗟毒蛟輩，睥睨飛龍位。", "龑巖雖同音，形體殊乖致。", "廢學愧未弘，來問辱不棄。", "奇字難雄博，摛文伏韓智。", "因誦鄙所聞，敢布諸下吏。"]'),
('839bf05c-5cfd-4c14-b517-6b902ecb0e74','柳堤詩','詹敦仁','唐','唐诗','tang','','[]','種稻三十頃，種柳百餘[株]。',50,'全唐诗/poet.tang.42000.json','["種稻三十頃，種柳百餘[株]。", "稻可供飦粥，柳可爨庖廚。", "息耒柳陰下，讀書稻田隅。", "以樂堯舜道，同是耕莘夫。"]'),
('e69ef9f8-337a-4d5b-b840-6393fd6fda33','勸王氏入貢寵予以官作辭命篇','詹敦仁','唐','唐诗','tang','','[]','爭霸圖王事總非，中原失統可傷悲。',64,'全唐诗/poet.tang.42000.json','["爭霸圖王事總非，中原失統可傷悲。", "從來賓主如郵傳，勝負干戈似局棊。", "周粟縱榮寧忍食，葛廬頻顧謾勞思。", "江山有待早歸去，好向鷦林擇一枝。"]'),
('2eea1e04-096c-4be4-8fe0-f2b18161964f','余遷泉山城留侯招遊郡圃作此','詹敦仁','唐','唐诗','tang','','[]','當年巧匠製茅亭，臺館翬飛匝郡城。',64,'全唐诗/poet.tang.42000.json','["當年巧匠製茅亭，臺館翬飛匝郡城。", "萬竈貔貅戈甲散，千家羅綺管弦鳴。", "柳腰舞罷香風度，花臉粧勻酒暈生。", "試問亭前花與柳，幾番衰謝幾番榮。"]'),
('9668aded-df40-4a74-9b8d-433aac61c45c','留侯受南唐節度使知郡事辟予爲屬以詩謝之','詹敦仁','唐','唐诗','tang','','[]','晉江江畔趁春風，耕破雲山幾萬重。',32,'全唐诗/poet.tang.42000.json','["晉江江畔趁春風，耕破雲山幾萬重。", "兩足一犂無外事，使君何啻五侯封。"]'),
('02b6f922-6de0-4b4d-94e9-3435904f2bd4','遣子訪劉乙','詹敦仁','唐','唐诗','tang','','[]','掃石耕山舊子真，布衣草履自隨身。',32,'全唐诗/poet.tang.42000.json','["掃石耕山舊子真，布衣草履自隨身。", "石崖壁立題詩處，知是當年鳳閣人。"]'),
('c55d469b-8801-4d5e-99f6-93c4910e4523','永嘉亂衣冠南度流落南泉作憶昔吟','詹琲','唐','唐诗','tang','','[]','憶昔永嘉際，中原板蕩年。',48,'全唐诗/poet.tang.42000.json','["憶昔永嘉際，中原板蕩年。", "衣冠墜塗炭，輿輅染腥膻。", "國勢多危厄，宗人苦播遷。", "南來頻灑淚，渴驥每思泉。"]'),
('0c3ba991-c31e-4e9a-b971-49e9ab7cc437','癸卯閩亂從弟監察御史敬凝迎仕別作','詹琲','唐','唐诗','tang','','[]','一別幾經春，棲遲晉水濱。',48,'全唐诗/poet.tang.42000.json','["一別幾經春，棲遲晉水濱。", "鶺鴒長在念，鴻雁忽來賓。", "五斗嫌腰折，朋山刺眼新。", "善辭如復我，四海五湖身。"]'),
('1b432689-4b77-43af-bdaa-ddbbc3accc2c','追和秦隱君辭薦之韻上陳侯乞歸鳳山','詹琲','唐','唐诗','tang','','[]','誰言悅口是甘肥，獨酌鵝兒噉翠微。',64,'全唐诗/poet.tang.42000.json','["誰言悅口是甘肥，獨酌鵝兒噉翠微。", "蠅利薄於青紙扇，羊裘煖甚紫羅衣。", "心隨倦鳥甘棲宿，目送征鴻遠奮飛。", "擊壤太平朝野客，鳳山深處□生輝。"]'),
('cf2ba782-979f-493f-a9e3-2a8d670acc35','雲','幸夤遜','唐','唐诗','tang','','[]','因登巨石知來處，勃勃元生綠蘚痕。',64,'全唐诗/poet.tang.42000.json','["因登巨石知來處，勃勃元生綠蘚痕。", "靜即等閑藏草木，動時頃刻遍乾坤。", "橫天未必朋元惡，捧日還曾瑞至尊。", "不獨朝朝在巫峽，楚王何事謾勞魂。"]'),
('4760fc44-7062-447a-ad4f-579453cc556e','句','幸夤遜','唐','唐诗','tang','','["\u6cf0\u5c71"]','苦教作鎮居中國，爭得泥金在泰山。',96,'全唐诗/poet.tang.42000.json','["苦教作鎮居中國，爭得泥金在泰山。", "纔聞暖律先偷眼，既待和風始展眉。", "蒙君知重惠瓊實，薄起金刀釘玉深。", "嚼處春冰敲齒冷，嚥時雪液沃心寒。", "深妝玉瓦平無壠，亂拂蘆花細有聲。", "日回禽影穿疎木，風遞猨聲入小樓。"]'),
('fe589d8b-6a1f-4a8f-9a91-89c870603419','詩','丁元和','唐','唐诗','tang','','[]','九重天子人中貴，五等諸侯閫外尊。',32,'全唐诗/poet.tang.42000.json','["九重天子人中貴，五等諸侯閫外尊。", "爭似布衣雲水客，不將名字挂乾坤。"]'),
('ff001976-5c56-4a4f-aea5-90eb260269c6','詠蜀都城上芙蓉花','張立','唐','唐诗','tang','','[]','四十里城花發時，錦囊高下照坤維。',32,'全唐诗/poet.tang.42000.json','["四十里城花發時，錦囊高下照坤維。", "雖粧蜀國三秋色，難入豳風七月詩。"]'),
('da34f34f-7e79-4a36-80a8-b8cbdd7e5bc9','又詠蜀都城上芙蓉花','張立','唐','唐诗','tang','','[]','去年今日到城都，城上芙蓉錦繡舒。',32,'全唐诗/poet.tang.42000.json','["去年今日到城都，城上芙蓉錦繡舒。", "今日重來舊遊處，此花顦顇不如初。"]'),
('85eeacbb-7277-43fb-8fc7-6f1c3fab9e28','句','張立','唐','唐诗','tang','','[]','朝廷不用憂巴蜀，稱霸何曾是蜀人。',16,'全唐诗/poet.tang.42000.json','["朝廷不用憂巴蜀，稱霸何曾是蜀人。"]'),
('ece3d218-8c47-4087-ac2d-bee5df2095ac','括蒼山','劉昭禹','唐','唐诗','tang','','[]','盡日行方半，諸山直下看。',48,'全唐诗/poet.tang.42000.json','["盡日行方半，諸山直下看。", "白雲隨步起，危徑極天盤。", "瀑頂橋形小，溪邊店影寒。", "往來空太息，玄鬢改非難。"]'),
('eca62ef4-3c94-4915-9424-f6d3f7bbbf4e','憶天台山','劉昭禹','唐','唐诗','tang','','[]','常記遊靈境，道人情不低。',48,'全唐诗/poet.tang.42000.json','["常記遊靈境，道人情不低。", "巖房容偃息，天路許相攜。", "霞散曙峰外，虹生涼瀑西。", "何當塵役了，重去聽猨啼。"]'),
('08515c42-46bf-4df1-8eb1-29607de29d42','冬日暮國清寺留題','劉昭禹','唐','唐诗','tang','','[]','天台山下寺，冬暮景如屏。',48,'全唐诗/poet.tang.42000.json','["天台山下寺，冬暮景如屏。", "樹密風長在，年深像有靈。", "高鐘疑到月，遠燒欲連星。", "因共真僧話，心中萬慮寧。"]'),
('00916f6a-26f1-490b-83e7-5dcfebe353a8','靈溪觀','劉昭禹','唐','唐诗','tang','','[]','鼇海西邊地，宵吟景象寬。',48,'全唐诗/poet.tang.42000.json','["鼇海西邊地，宵吟景象寬。", "雲開孤月上，瀑噴一山寒。", "人異髮常綠，草靈秋不乾。", "無由此棲息，魂夢在長安。"]'),
('867e210c-3c08-4ec4-b6d6-2a751689d39c','懷華山隱者','劉昭禹','唐','唐诗','tang','','[]','先生入太華，杳杳絕良音。',48,'全唐诗/poet.tang.42000.json','["先生入太華，杳杳絕良音。", "秋夢有時見，孤雲無處尋。", "神清峰頂立，衣冷瀑邊吟。", "應笑干名者，六街塵土深。"]'),
('d1214742-797e-4613-b64e-3e7015c6d4f1','贈惠律大師','劉昭禹','唐','唐诗','tang','','[]','秋是憶山日，禪窗露灑餘。',48,'全唐诗/poet.tang.42000.json','["秋是憶山日，禪窗露灑餘。", "幾懸華頂夢，應寄沃洲書。", "風月資吟筆，杉篁籠靜居。", "滿城誰不重，見著紫衣初。"]'),
('a7890449-7174-465d-b5fa-f160a3e92b9a','經費冠卿舊隱','劉昭禹','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','節高終不起，死戀九華山。',48,'全唐诗/poet.tang.42000.json','["節高終不起，死戀九華山。", "聖主情何切，孤雲性本閑。", "名傳中國外，墳在亂松間。", "依約曾棲處，斜陽鳥自還。"]'),
('deb464e8-6dea-49d6-8f85-654d009936ef','聞蟬','劉昭禹','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一雨一番晴，山林冷落青。',48,'全唐诗/poet.tang.42000.json','["一雨一番晴，山林冷落青。", "莫侵殘日噪，正在異鄉聽。", "孤館宿漳浦，扁舟離洞庭。", "年年當此際，那免鬢凋零。"]'),
('fa7d2d92-ac17-46b6-9096-7f85751b7d58','送休公歸衡','劉昭禹','唐','唐诗','tang','','["\u8861\u5c71"]','草履初登南嶽船，銅瓶猶貯北山泉。',32,'全唐诗/poet.tang.42000.json','["草履初登南嶽船，銅瓶猶貯北山泉。", "衡陽舊寺春歸晚，門鎖寒潭幾樹蟬。"]'),
('35a4db40-1b5e-4f5e-bb25-075d4956c893','句','劉昭禹','唐','唐诗','tang','','[]','句向夜深得，心從天外歸。',84,'全唐诗/poet.tang.42000.json','["句向夜深得，心從天外歸。", "危樓聊側耳，高柳又鳴蟬。", "蘚色圍波井，花陰上竹樓。", "對面電瞋樹，當街雨趁人。", "春光懷玉闕，萬里起初程。", "江上呼風去，天邊挂席飛。", "漆燈尋黑洞，之字上危峰。"]'),
('4ca855e5-1274-430c-ac60-e30cdc5a9e15','銅柱辭','李宏臯','唐','唐诗','tang','','[]','招靈鑄柱垂英烈，手執干戈征百越。',96,'全唐诗/poet.tang.42000.json','["招靈鑄柱垂英烈，手執干戈征百越。", "誕今鑄柱庇黔黎，指畫風雷開五溪。", "五溪之險不足恃，我旅爭登若平地。", "五溪之衆不足平，我師輕躡如春冰。", "溪人畏威思納質，棄汙歸明求立誓。", "誓山川兮告鬼神，保子孫兮千萬春。"]'),
('3d6778b3-9e6b-4f20-942f-4718bc17d2df','題桃源','李宏臯','唐','唐诗','tang','','[]','山翠參差水渺茫，秦人昔在楚封[疆]。',66,'全唐诗/poet.tang.42000.json','["山翠參差水渺茫，秦人昔在楚封[疆]。", "當時避世乾坤窄，此地安家日月長。", "草色幾經壇杏老，巖花猶帶澗桃香。", "他年倘遂平生志，來著霞衣侍玉皇。"]'),
('f71050f4-0261-41bc-881e-1935a37ebb01','李臯試詩','何仲舉','唐','唐诗','tang','','[]','似玉來投獄，拋家去就枷。',24,'全唐诗/poet.tang.42000.json','["似玉來投獄，拋家去就枷。", "可憐兩片木，夾却一枝花。"]'),
('9632ea8c-ce70-4e5b-a1d3-f9fc3ffddcaf','句','何仲舉','唐','唐诗','tang','','[]','碧雲章句纔離手，紫府神仙盡點頭。',32,'全唐诗/poet.tang.42000.json','["碧雲章句纔離手，紫府神仙盡點頭。", "樹迎高鳥歸深野，雲傍斜陽過遠山。"]'),
('efb8387f-cb9f-40bd-8f0b-2df5fd8d3b78','畊夫謠','徐仲雅','唐','唐诗','tang','','[]','張緒逞風流，王衍事輕薄。',48,'全唐诗/poet.tang.42000.json','["張緒逞風流，王衍事輕薄。", "出門逢畊夫，顏色必不樂。", "肥膚如玉潔，力拗絲不折。", "半日無畊夫，此輩總餓殺。"]'),
('f479eec1-12a5-47b4-bb53-10a5ba462b50','贈齊己','徐仲雅','唐','唐诗','tang','','[]','我唐有僧號齊己，未出家時宰相器。',240,'全唐诗/poet.tang.42000.json','["我唐有僧號齊己，未出家時宰相器。", "爰見夢中逢五丁，毀形自學無生理。", "骨瘦神清風一襟，松老霜天鶴病深。", "一言悟得生死海，芙蓉吐出琉璃心。", "悶見有唐風雅缺，敲破冰天飛白雪。", "清塞清江却有靈，遺魂泣對荒郊月。", "格何古，天工未生誰知主。", "混沌鑿開雞子黃，散作純風如膽苦。", "意何新，織女星機挑白雲。", "真宰夜來調暖律，聲聲吹出嫩青春。", "調何雅，澗底孤松秋雨灑。", "嫦娥月裏學步虛，桂風吹落玉山下。", "語何奇，血潑乾坤龍戰時。", "祖龍跨海日方出，一鞭風雨萬山飛。", "己公己公道如此，浩浩寰中如獨自。", "一簟松風冷如冰，長伴巢由伸脚睡。"]'),
('43890099-7021-48b1-80c6-b59fba090b24','贈江處士','徐仲雅','唐','唐诗','tang','','[]','門在松陰裏，山僧幾度過。',48,'全唐诗/poet.tang.42000.json','["門在松陰裏，山僧幾度過。", "藥靈丸不大，棊妙子無多。", "薄霧籠寒徑，殘風戀綠蘿。", "金烏兼玉兔，年幾奈公何。"]'),
('69809a7d-bdad-42e6-814b-ed3f3a9b7b54','東華觀偃松','徐仲雅','唐','唐诗','tang','','[]','半已化爲石，有靈通碧湘。',48,'全唐诗/poet.tang.42000.json','["半已化爲石，有靈通碧湘。", "生逢堯雨露，老直漢風霜。", "月滴蟾心水，龍遺腦骨香。", "始於毫末後，曾見幾興亡。"]'),
('6ae7cedb-1dc7-404b-bf1e-20773737c8bd','詠椶樹','徐仲雅','唐','唐诗','tang','','[]','葉似新蒲綠，身如亂錦纏。',24,'全唐诗/poet.tang.42000.json','["葉似新蒲綠，身如亂錦纏。", "任君千度剝，意氣自衝天。"]'),
('46d25e19-4b06-4464-b753-46c8c1893c1d','宮詞','徐仲雅','唐','唐诗','tang','','[]','內人曉起怯春寒，輕揭珠簾看牡丹。',32,'全唐诗/poet.tang.42000.json','["內人曉起怯春寒，輕揭珠簾看牡丹。", "一把柳絲收不得，和風搭在玉欄杆。"]'),
('a74073bf-2610-4bb4-98bc-0bc1cb867265','句','徐仲雅','唐','唐诗','tang','','[]','屋面盡生人耳朵，籬頭多是老翁鬚。',208,'全唐诗/poet.tang.42000.json','["屋面盡生人耳朵，籬頭多是老翁鬚。", "平分造化雙苞去，拆破春風兩面開。", "雲路半開千里月，洞門斜掩一天春。", "鑿開青帝春風國，移下姮娥夜月樓。", "珠璣影冷偏黏草，蘭麝香濃却損花。", "山色曉堆羅黛雨，草梢春戛麝香風。", "衰蘭寂寞含愁綠，小杏妖嬈弄色紅。", "旁搜水脉湘心滿，遍揭泉根梵底通。", "水□滴殘青□瘦，石脂傾盡白雲空。", "深浦送回芳草日，急灘牽斷綠楊風。", "藕梢逆入銀塘裏，蘋迹潛來玉井中。", "敗菊籬疎臨野渡，落梅村冷隔江楓。", "剪開淨澗分苗稼，劃破漣漪下釣筒。"]'),
('2360eb86-9864-4e25-83e5-e2ed2b8ae6c1','分水嶺','伍彬','唐','唐诗','tang','','[]','前賢功及物，禹後杳難儔。',48,'全唐诗/poet.tang.42000.json','["前賢功及物，禹後杳難儔。", "不改古今色，平分南北流。", "寒衝山影岸，清繞荻花洲。", "盡是朝宗去，潺潺早晚休。"]'),
('f69b9031-5112-45e3-96b0-1a15d2f5206a','句','伍彬','唐','唐诗','tang','','[]','稚子出看莎徑沒，漁翁來報竹橋流。',32,'全唐诗/poet.tang.42000.json','["稚子出看莎徑沒，漁翁來報竹橋流。", "蹤跡未辭鴛鷺客，夢魂先到鷓鴣村。"]'),
('ea19971f-2e6d-440d-8bd7-3e9aeb8ec62a','留宿廖融山齋','楊徽之','唐','唐诗','tang','','[]','清和春尚在，歡醉日何長。',48,'全唐诗/poet.tang.42000.json','["清和春尚在，歡醉日何長。", "谷鳥隨柯轉，庭花奪酒香。", "初晴巖翠滴，向晚樹陰涼。", "別有堪吟處，相留宿草堂。"]'),
('15609049-0152-4bfc-aca7-d5218dc8662c','句','楊徽之','唐','唐诗','tang','','[]','新霜染楓葉，皎月借蘆花。',24,'全唐诗/poet.tang.42000.json','["新霜染楓葉，皎月借蘆花。", "廢宅寒塘水，荒墳宿草煙。"]'),
('4dfd526d-c8f9-4afd-8abc-fa3fa170b6d4','登祝融峰','王元','唐','唐诗','tang','','[]','草疊到孤頂，身齊高鳥翔。',48,'全唐诗/poet.tang.42000.json','["草疊到孤頂，身齊高鳥翔。", "勢疑撞翼軫，翠欲滴瀟湘。", "雲濕幽崖滑，風梳古木香。", "晴空聊縱目，杳杳極窮荒。"]'),
('f4468744-a0f9-40f5-b244-ae4fc19c1a7e','懷翁宏','王元','唐','唐诗','tang','','[]','獨夜思君切，無人知此情。',48,'全唐诗/poet.tang.42000.json','["獨夜思君切，無人知此情。", "滄州歸未得，華髮別來生。", "孤館木初落，高空月正明。", "遠書多隔歲，獨念沒前程。"]'),
('b32977ae-1a76-412c-b360-4a430274884c','聽琴','王元','唐','唐诗','tang','','[]','拂塵開素匣，有客獨傷時。',48,'全唐诗/poet.tang.42000.json','["拂塵開素匣，有客獨傷時。", "古調俗不樂，正聲君自知。", "寒泉出澗澀，老檜倚風悲。", "縱有來聽者，誰堪繼子期。"]'),
('8f6bf7a7-90ec-4dae-9fdc-7c2e41ec35c2','哭李韶','王元','唐','唐诗','tang','','[]','韶也命何奇，生前與世違。',48,'全唐诗/poet.tang.42000.json','["韶也命何奇，生前與世違。", "貧棲古梵剎，終著舊麻衣。", "雅句僧抄遍，孤墳客弔稀。", "故園今孰在，應見夢中歸。"]'),
('4bc52b54-4019-4988-895c-e29c06f787a5','題鄧真人遺址','王元','唐','唐诗','tang','','[]','三千功滿仙昇去，留得山前舊隱基。',64,'全唐诗/poet.tang.42000.json','["三千功滿仙昇去，留得山前舊隱基。", "但見白雲長掩映，不知浮世幾興衰。", "松稍風觸霓旌動，椶葉霜霑鶴翅垂。", "近代無人尋異事，野泉噴月瀉秋池。"]'),
('5153f37a-4253-4ebd-b17b-db25a2191718','句','王元','唐','唐诗','tang','','[]','伴行惟瘦鶴，尋步入深雲。',12,'全唐诗/poet.tang.42000.json','["伴行惟瘦鶴，尋步入深雲。"]'),
('4b00c212-998f-4b80-a789-09942c84b0a7','謝翁宏以詩百篇見示','廖融','唐','唐诗','tang','','[]','高奇一百篇，造化見工全。',48,'全唐诗/poet.tang.42000.json','["高奇一百篇，造化見工全。", "積思遊滄海，冥搜入洞天。", "神珠迷罔象，端玉匪雕鐫。", "休嘆不得力，離騷千古傳。"]'),
('55549b3f-ae3b-41aa-88f6-e1ee29c9f206','贈天台逸人','廖融','唐','唐诗','tang','','[]','移檜托禪子，攜家上赤城。',48,'全唐诗/poet.tang.42000.json','["移檜托禪子，攜家上赤城。", "拂琴天籟寂，欹枕海濤生。", "雲白寒峰晚，鳥歌春谷晴。", "又聞求桂檝，載月十洲行。"]'),
('b88494f5-b7ac-4cb3-a35d-4a705e665835','古檜','廖融','唐','唐诗','tang','','[]','何人見植初，老樹梵王居。',48,'全唐诗/poet.tang.42000.json','["何人見植初，老樹梵王居。", "山鬼暗棲托，樵夫難破除。", "聲高秋漢迥，影倒月潭虛。", "盡日無僧倚，清風長有餘。"]'),
('211fa2a2-c8b4-4c5b-82c6-f95e92472372','題伍彬屋壁','廖融','唐','唐诗','tang','','[]','圓塘綠水平，魚躍紫蓴生。',48,'全唐诗/poet.tang.42000.json','["圓塘綠水平，魚躍紫蓴生。", "要路貧無力，深村老退耕。", "犢隨原草遠，蛙傍塹籬鳴。", "撥櫂茶川去，初逢穀雨晴。"]'),
('62130af3-2d9c-4905-9b16-c5df2a2899f6','夢仙謠','廖融','唐','唐诗','tang','','[]','琪木扶疎繫辟邪，麻姑夜宴紫皇家。',64,'全唐诗/poet.tang.42000.json','["琪木扶疎繫辟邪，麻姑夜宴紫皇家。", "銀河旌節搖波影，珠閣笙簫吸月華。", "翠鳳引遊三島路，赤龍齊駕五雲車。", "星稀猶倚虹橋立，擬就張騫搭漢槎。"]'),
('7bf07115-ac8d-4c81-b927-e2d5e671b216','退宮妓','廖融','唐','唐诗','tang','','[]','神仙風格本難儔，曾從前皇翠輦遊。',64,'全唐诗/poet.tang.42000.json','["神仙風格本難儔，曾從前皇翠輦遊。", "紅躑躅繁金殿暖，碧芙蓉笑水宮秋。", "寶箏鈿剝陰塵覆，錦帳香消畫燭幽。", "一旦色衰歸故里，月明猶夢按梁州。"]'),
('ba1e399e-4e4f-4346-b3f4-aad23d952f7b','句','廖融','唐','唐诗','tang','','[]','圭竈先知曉，盆池別見天。',36,'全唐诗/poet.tang.42000.json','["圭竈先知曉，盆池別見天。", "古寺尋僧飯，寒巖衣鹿裘。", "雲穿擣藥屋，雪壓釣魚舟。"]'),
('c3519473-d47e-4849-8cb5-546599a0953b','贈廖融','王正己','唐','唐诗','tang','','[]','病起正當秋閣迥，酒醒迎對夜濤寒。',32,'全唐诗/poet.tang.42000.json','["病起正當秋閣迥，酒醒迎對夜濤寒。", "爐中藥熟分僧飯，枕上琴閑借客彈。"]'),
('f83fce7e-a8f3-453c-b217-3e76b04ea1ae','句','王正己','唐','唐诗','tang','','[]','洗盂秋澗日華動，搗藥夜坐秋氣深。',16,'全唐诗/poet.tang.42000.json','["洗盂秋澗日華動，搗藥夜坐秋氣深。"]'),
('6711c65c-3dc9-4a48-bfe6-d5e2dfe66dac','送廖融處士南遊','翁宏','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','病臥瘴雲間，莓苔漬竹關。',48,'全唐诗/poet.tang.42000.json','["病臥瘴雲間，莓苔漬竹關。", "孤吟牛渚月，老憶洞庭山。", "壯志潛消盡，淳風竟未還。", "今朝忽相遇，執手一開顏。"]'),
('44bf70da-4f3b-4124-ba92-095ac3c016e1','春殘','翁宏','唐','唐诗','tang','','[]','又是春殘也，如何出翠幃。',48,'全唐诗/poet.tang.42000.json','["又是春殘也，如何出翠幃。", "落花人獨立，微雨燕雙飛。", "寓目魂將斷，經年夢亦非。", "那堪向愁夕，蕭颯暮蟬輝。"]'),
('cceebdfd-c751-4b3c-8ae9-1f77e182e83f','秋殘','翁宏','唐','唐诗','tang','','[]','又是秋殘也，無聊意若何。',48,'全唐诗/poet.tang.42000.json','["又是秋殘也，無聊意若何。", "客程江外遠，歸思夜深多。", "峴首飛黃葉，湘湄走白波。", "仍聞漢都護，今歲合休戈。"]'),
('1f66ba53-8574-4e34-b4f1-1cc8b7ec524e','句','翁宏','唐','唐诗','tang','','[]','萬木橫秋裏，孤舟半夜猨。',36,'全唐诗/poet.tang.42000.json','["萬木橫秋裏，孤舟半夜猨。", "漏光殘井甃，缺影背山椒。", "風回山火斷，潮落岸冰高。"]'),
('b83b81ec-247f-42dd-b890-97c672aa7a89','過衡山贈廖處士','張觀','唐','唐诗','tang','','["\u8861\u5c71"]','未向漆園爲傲吏，定應明代作徵君。',64,'全唐诗/poet.tang.42000.json','["未向漆園爲傲吏，定應明代作徵君。", "傳家奕世無金玉，樂道經年有典墳。", "帶雨小舟橫別澗，隔花幽犬吠深雲。", "到頭終爲蒼生起，休戀耕煙楚水濆。"]'),
('bdbc2e99-1254-45ec-815d-9bfafc135a55','竹枝詞二首 一','孫光憲','唐','唐诗','tang','','[]','門前春水白蘋花，岸上無人小艇斜。',32,'全唐诗/poet.tang.42000.json','["門前春水白蘋花，岸上無人小艇斜。", "商女經過江欲暮，散拋殘食飼神鴉。"]'),
('b4baa67a-4b44-43e8-8035-c0ffd46e860b','竹枝詞二首 二','孫光憲','唐','唐诗','tang','','[]','亂繩千結絆人深，越羅萬丈表長尋。',32,'全唐诗/poet.tang.42000.json','["亂繩千結絆人深，越羅萬丈表長尋。", "楊柳在身垂意緒，藕花落盡見蓮心。"]'),
('d0877bcd-f8ae-4b1d-8e0f-41854b8ae5c6','楊柳枝詞四首 一','孫光憲','唐','唐诗','tang','','[]','閶門風暖落花乾，飛遍江城雪不寒。',32,'全唐诗/poet.tang.42000.json','["閶門風暖落花乾，飛遍江城雪不寒。", "獨有晚來臨水驛，閑人多憑赤欄干。"]'),
('d36ad41d-a989-4135-b64e-1f77a4026627','楊柳枝詞四首 二','孫光憲','唐','唐诗','tang','','[]','有池有榭即濛濛，浸潤翻成長養功。',32,'全唐诗/poet.tang.42000.json','["有池有榭即濛濛，浸潤翻成長養功。", "恰似有人長點檢，著行排立向春風。"]'),
('8b588be3-c7e7-45d4-ba24-01076e841854','楊柳枝詞四首 三','孫光憲','唐','唐诗','tang','','[]','根柢雖然傍濁河，無妨終日近笙歌。',32,'全唐诗/poet.tang.42000.json','["根柢雖然傍濁河，無妨終日近笙歌。", "毿毿金帶誰堪比，還共黃鶯不較多。"]');
